window.LEETCODE_IO_DATA = {"generatedAt":"2026-06-23T13:18:07+00:00","summary":{"problemCount":93,"contestSolutionCount":40,"contestCount":10,"ratedProblemCount":89},"tiers":[{"slug":"0000-1199-newbie","label":"< 1200","tier":"Newbie","count":11},{"slug":"1200-1399-pupil","label":"1200-1399","tier":"Pupil","count":43},{"slug":"1400-1599-specialist","label":"1400-1599","tier":"Specialist","count":13},{"slug":"1600-1899-expert","label":"1600-1899","tier":"Expert","count":16},{"slug":"1900-2099-candidate-master","label":"1900-2099","tier":"Candidate Master","count":2},{"slug":"2100-2299-master","label":"2100-2299","tier":"Master","count":1},{"slug":"2300-2399-international-master","label":"2300-2399","tier":"International Master","count":1},{"slug":"2400-2599-grandmaster","label":"2400-2599","tier":"Grandmaster","count":2},{"slug":"2600-2999-international-grandmaster","label":"2600-2999","tier":"International Grandmaster","count":0},{"slug":"3000-3999-legendary-grandmaster","label":"3000-3999","tier":"Legendary Grandmaster","count":0},{"slug":"4000-plus-eponym","label":">= 4000","tier":"Eponym","count":0},{"slug":"unrated","label":"Unrated","tier":"Unrated","count":4}],"problems":[{"key":"problem:problems/0000-1199-newbie/3492.maximum-containers-on-a-ship.cpp","id":3492,"qid":"3492","title":"Maximum Containers On A Ship","kebab":"maximum-containers-on-a-ship","rating":1140.4,"ratingLabel":"1140.4","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3492.maximum-containers-on-a-ship.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-containers-on-a-ship/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3492.maximum-containers-on-a-ship.cpp","code":"/*\n * @lc app=leetcode id=3492 lang=cpp\n *\n * [3492] Maximum Containers on a Ship\n *\n * https://leetcode.com/problems/maximum-containers-on-a-ship/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a positive integer n representing an n x n cargo deck on a\n * ship. Each cell on the deck can hold one container with a weight of exactly\n * w.\n * \n * However, the total weight of all containers, if loaded onto the deck, must\n * not exceed the ship's maximum weight capacity, maxWeight.\n * \n * Return the maximum number of containers that can be loaded onto the ship.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 2, w = 3, maxWeight = 15\n * \n * Output: 4\n * \n * Explanation: \n * \n * The deck has 4 cells, and each container weighs 3. The total weight of\n * loading all containers is 12, which does not exceed maxWeight.\n * \n * \n * Example 2:\n * \n * \n * Input: n = 3, w = 5, maxWeight = 20\n * \n * Output: 4\n * \n * Explanation: \n * \n * The deck has 9 cells, and each container weighs 5. The maximum number of\n * containers that can be loaded without exceeding maxWeight is 4.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 1000\n * 1 <= w <= 1000\n * 1 <= maxWeight <= 10^9\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxContainers(int n, int w, int maxWeight) {\n        return min(n*n, maxWeight / w);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3622.check-divisibility-by-digit-sum-and-product.cpp","id":3622,"qid":"3622","title":"Check Divisibility By Digit Sum And Product","kebab":"check-divisibility-by-digit-sum-and-product","rating":1148.9,"ratingLabel":"1148.9","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3622.check-divisibility-by-digit-sum-and-product.cpp","leetcodeUrl":"https://leetcode.com/problems/check-divisibility-by-digit-sum-and-product/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3622.check-divisibility-by-digit-sum-and-product.cpp","code":"class Solution {\npublic:\n    bool checkDivisibility(int n) {\n        int a = 0, b = 1, num = n;\n        while(num > 0) {\n            a += num % 10;\n            b *= num % 10;\n            num /= 10;\n        }\n        return (n % (a + b) == 0) ? true : false;\n    }\n};\n"},{"key":"problem:problems/0000-1199-newbie/2828.check-if-a-string-is-an-acronym-of-words.cpp","id":2828,"qid":"2828","title":"Check If A String Is An Acronym Of Words","kebab":"check-if-a-string-is-an-acronym-of-words","rating":1152.0,"ratingLabel":"1152.0","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/2828.check-if-a-string-is-an-acronym-of-words.cpp","leetcodeUrl":"https://leetcode.com/problems/check-if-a-string-is-an-acronym-of-words/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/2828.check-if-a-string-is-an-acronym-of-words.cpp","code":"/*\n * @lc app=leetcode id=2828 lang=cpp\n *\n * [2828] Check if a String Is an Acronym of Words\n *\n * https://leetcode.com/problems/check-if-a-string-is-an-acronym-of-words/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Given an array of strings words and a string s, determine if s is an acronym\n * of words.\n * \n * The string s is considered an acronym of words if it can be formed by\n * concatenating the first character of each string in words in order. For\n * example, \"ab\" can be formed from [\"apple\", \"banana\"], but it can't be formed\n * from [\"bear\", \"aardvark\"].\n * \n * Return true if s is an acronym of words, and false otherwise. \n * \n * \n * Example 1:\n * \n * \n * Input: words = [\"alice\",\"bob\",\"charlie\"], s = \"abc\"\n * Output: true\n * Explanation: The first character in the words \"alice\", \"bob\", and \"charlie\"\n * are 'a', 'b', and 'c', respectively. Hence, s = \"abc\" is the acronym. \n * \n * \n * Example 2:\n * \n * \n * Input: words = [\"an\",\"apple\"], s = \"a\"\n * Output: false\n * Explanation: The first character in the words \"an\" and \"apple\" are 'a' and\n * 'a', respectively. \n * The acronym formed by concatenating these characters is \"aa\". \n * Hence, s = \"a\" is not the acronym.\n * \n * \n * Example 3:\n * \n * \n * Input: words = [\"never\",\"gonna\",\"give\",\"up\",\"on\",\"you\"], s = \"ngguoy\"\n * Output: true\n * Explanation: By concatenating the first character of the words in the array,\n * we get the string \"ngguoy\". \n * Hence, s = \"ngguoy\" is the acronym.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= words.length <= 100\n * 1 <= words[i].length <= 10\n * 1 <= s.length <= 100\n * words[i] and s consist of lowercase English letters.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool isAcronym(vector<string>& words, string s) {\n        if(words.size() != s.size()) return false;\n\n        for(int i=0; i<words.size(); i++) {\n            if(words[i][0] != s[i]) return false;\n        }\n        return true;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3516.find-closest-person.cpp","id":3516,"qid":"3516","title":"Find Closest Person","kebab":"find-closest-person","rating":1164.2,"ratingLabel":"1164.2","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3516.find-closest-person.cpp","leetcodeUrl":"https://leetcode.com/problems/find-closest-person/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3516.find-closest-person.cpp","code":"/*\n * @lc app=leetcode id=3516 lang=cpp\n *\n * [3516] Find Closest Person\n *\n * https://leetcode.com/problems/find-closest-person/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given three integers x, y, and z, representing the positions of\n * three people on a number line:\n * \n * \n * x is the position of Person 1.\n * y is the position of Person 2.\n * z is the position of Person 3, who does not move.\n * \n * \n * Both Person 1 and Person 2 move toward Person 3 at the same speed.\n * \n * Determine which person reaches Person 3 first:\n * \n * \n * Return 1 if Person 1 arrives first.\n * Return 2 if Person 2 arrives first.\n * Return 0 if both arrive at the same time.\n * \n * \n * Return the result accordingly.\n * \n * \n * Example 1:\n * \n * \n * Input: x = 2, y = 7, z = 4\n * \n * Output: 1\n * \n * Explanation:\n * \n * \n * Person 1 is at position 2 and can reach Person 3 (at position 4) in 2\n * steps.\n * Person 2 is at position 7 and can reach Person 3 in 3 steps.\n * \n * \n * Since Person 1 reaches Person 3 first, the output is 1.\n * \n * \n * Example 2:\n * \n * \n * Input: x = 2, y = 5, z = 6\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * Person 1 is at position 2 and can reach Person 3 (at position 6) in 4\n * steps.\n * Person 2 is at position 5 and can reach Person 3 in 1 step.\n * \n * \n * Since Person 2 reaches Person 3 first, the output is 2.\n * \n * \n * Example 3:\n * \n * \n * Input: x = 1, y = 5, z = 3\n * \n * Output: 0\n * \n * Explanation:\n * \n * \n * Person 1 is at position 1 and can reach Person 3 (at position 3) in 2\n * steps.\n * Person 2 is at position 5 and can reach Person 3 in 2 steps.\n * \n * \n * Since both Person 1 and Person 2 reach Person 3 at the same time, the output\n * is 0.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= x, y, z <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int findClosest(int x, int y, int z) {\n        int a = abs(x - z), b = abs(y - z);\n        if(a < b) return 1;\n        else if(a > b) return 2;\n        return 0;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3467.transform-array-by-parity.cpp","id":3467,"qid":"3467","title":"Transform Array By Parity","kebab":"transform-array-by-parity","rating":1165.8,"ratingLabel":"1165.8","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3467.transform-array-by-parity.cpp","leetcodeUrl":"https://leetcode.com/problems/transform-array-by-parity/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3467.transform-array-by-parity.cpp","code":"/*\n * @lc app=leetcode id=3467 lang=cpp\n *\n * [3467] Transform Array by Parity\n *\n * https://leetcode.com/problems/transform-array-by-parity/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums. Transform nums by performing the\n * following operations in the exact order specified:\n * \n * \n * Replace each even number with 0.\n * Replace each odd numbers with 1.\n * Sort the modified array in non-decreasing order.\n * \n * \n * Return the resulting array after performing these operations.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [4,3,2,1]\n * \n * Output: [0,0,1,1]\n * \n * Explanation:\n * \n * \n * Replace the even numbers (4 and 2) with 0 and the odd numbers (3 and 1) with\n * 1. Now, nums = [0, 1, 0, 1].\n * After sorting nums in non-descending order, nums = [0, 0, 1, 1].\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,5,1,4,2]\n * \n * Output: [0,0,1,1,1]\n * \n * Explanation:\n * \n * \n * Replace the even numbers (4 and 2) with 0 and the odd numbers (1, 5 and 1)\n * with 1. Now, nums = [1, 1, 1, 0, 0].\n * After sorting nums in non-descending order, nums = [0, 0, 1, 1, 1].\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 1 <= nums[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> transformArray(vector<int>& nums) {\n        vector<int> res(nums.size(), 1);\n        int t = 0;\n        for(int i=0; i<nums.size(); i++) {\n            if(nums[i] % 2 == 0) {\n                res[t] = 0;\n                t++;\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/2824.count-pairs-whose-sum-is-less-than-target.cpp","id":2824,"qid":"2824","title":"Count Pairs Whose Sum Is Less Than Target","kebab":"count-pairs-whose-sum-is-less-than-target","rating":1165.9,"ratingLabel":"1165.9","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/2824.count-pairs-whose-sum-is-less-than-target.cpp","leetcodeUrl":"https://leetcode.com/problems/count-pairs-whose-sum-is-less-than-target/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/2824.count-pairs-whose-sum-is-less-than-target.cpp","code":"/*\n * @lc app=leetcode id=2824 lang=cpp\n *\n * [2824] Count Pairs Whose Sum is Less than Target\n *\n * https://leetcode.com/problems/count-pairs-whose-sum-is-less-than-target/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Given a 0-indexed integer array nums of length n and an integer target,\n * return the number of pairs (i, j) where 0 <= i < j < n and nums[i] + nums[j]\n * < target.\n * \n * Example 1:\n * \n * \n * Input: nums = [-1,1,2,3,1], target = 2\n * Output: 3\n * Explanation: There are 3 pairs of indices that satisfy the conditions in the\n * statement:\n * - (0, 1) since 0 < 1 and nums[0] + nums[1] = 0 < target\n * - (0, 2) since 0 < 2 and nums[0] + nums[2] = 1 < target \n * - (0, 4) since 0 < 4 and nums[0] + nums[4] = 0 < target\n * Note that (0, 3) is not counted since nums[0] + nums[3] is not strictly less\n * than the target.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [-6,2,5,-2,-7,-1,3], target = -2\n * Output: 10\n * Explanation: There are 10 pairs of indices that satisfy the conditions in\n * the statement:\n * - (0, 1) since 0 < 1 and nums[0] + nums[1] = -4 < target\n * - (0, 3) since 0 < 3 and nums[0] + nums[3] = -8 < target\n * - (0, 4) since 0 < 4 and nums[0] + nums[4] = -13 < target\n * - (0, 5) since 0 < 5 and nums[0] + nums[5] = -7 < target\n * - (0, 6) since 0 < 6 and nums[0] + nums[6] = -3 < target\n * - (1, 4) since 1 < 4 and nums[1] + nums[4] = -5 < target\n * - (3, 4) since 3 < 4 and nums[3] + nums[4] = -9 < target\n * - (3, 5) since 3 < 5 and nums[3] + nums[5] = -3 < target\n * - (4, 5) since 4 < 5 and nums[4] + nums[5] = -8 < target\n * - (4, 6) since 4 < 6 and nums[4] + nums[6] = -4 < target\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length == n <= 50\n * -50 <= nums[i], target <= 50\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int countPairs(vector<int>& nums, int target) {\n        int res = 0;\n        for(int i=0; i<nums.size(); i++) {\n            for(int j=i+1; j<nums.size(); j++) {\n                if(nums[i] + nums[j] < target) res++;\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3612.process-string-with-special-operations-i.cpp","id":3612,"qid":"3612","title":"Process String With Special Operations I","kebab":"process-string-with-special-operations-i","rating":1186.0,"ratingLabel":"1186.0","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3612.process-string-with-special-operations-i.cpp","leetcodeUrl":"https://leetcode.com/problems/process-string-with-special-operations-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3612.process-string-with-special-operations-i.cpp","code":"/*\n * @lc app=leetcode id=3612 lang=cpp\n *\n * [3612] Process String with Special Operations I\n *\n * https://leetcode.com/problems/process-string-with-special-operations-i/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given a string s consisting of lowercase English letters and the\n * special characters: *, #, and %.\n * \n * Build a new string result by processing s according to the following rules\n * from left to right:\n * \n * \n * If the letter is a lowercase English letter append it to result.\n * A '*' removes the last character from result, if it exists.\n * A '#' duplicates the current result and appends it to itself.\n * A '%' reverses the current result.\n * \n * \n * Return the final string result after processing all characters in s.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"a#b%*\"\n * \n * Output: \"ba\"\n * \n * Explanation:\n * \n * \n * \n * \n * i\n * s[i]\n * Operation\n * Current result\n * \n * \n * \n * \n * 0\n * 'a'\n * Append 'a'\n * \"a\"\n * \n * \n * 1\n * '#'\n * Duplicate result\n * \"aa\"\n * \n * \n * 2\n * 'b'\n * Append 'b'\n * \"aab\"\n * \n * \n * 3\n * '%'\n * Reverse result\n * \"baa\"\n * \n * \n * 4\n * '*'\n * Remove the last character\n * \"ba\"\n * \n * \n * \n * \n * Thus, the final result is \"ba\".\n * \n * \n * Example 2:\n * \n * \n * Input: s = \"z*#\"\n * \n * Output: \"\"\n * \n * Explanation:\n * \n * \n * \n * \n * i\n * s[i]\n * Operation\n * Current result\n * \n * \n * \n * \n * 0\n * 'z'\n * Append 'z'\n * \"z\"\n * \n * \n * 1\n * '*'\n * Remove the last character\n * \"\"\n * \n * \n * 2\n * '#'\n * Duplicate the string\n * \"\"\n * \n * \n * \n * \n * Thus, the final result is \"\".\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= s.length <= 20\n * s consists of only lowercase English letters and special characters *, #,\n * and %.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string processStr(string s) {\n        string res;\n        for(int i=0; i<s.size(); i++) {\n            if(s[i] == '*') {\n                if(res.length() > 0) res.pop_back();\n            }\n            else if(s[i] == '#') res += res;\n            else if(s[i] == '%') reverse(res.begin(), res.end());\n            else res += s[i];\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3461.check-if-digits-are-equal-in-string-after-operations-i.cpp","id":3461,"qid":"3461","title":"Check If Digits Are Equal In String After Operations I","kebab":"check-if-digits-are-equal-in-string-after-operations-i","rating":1189.4,"ratingLabel":"1189.4","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3461.check-if-digits-are-equal-in-string-after-operations-i.cpp","leetcodeUrl":"https://leetcode.com/problems/check-if-digits-are-equal-in-string-after-operations-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3461.check-if-digits-are-equal-in-string-after-operations-i.cpp","code":"/*\n * @lc app=leetcode id=3461 lang=cpp\n *\n * [3461] Check If Digits Are Equal in String After Operations I\n *\n * https://leetcode.com/problems/check-if-digits-are-equal-in-string-after-operations-i/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string s consisting of digits. Perform the following\n * operation repeatedly until the string has exactly two digits:\n * \n * \n * For each pair of consecutive digits in s, starting from the first digit,\n * calculate a new digit as the sum of the two digits modulo 10.\n * Replace s with the sequence of newly calculated digits, maintaining the\n * order in which they are computed.\n * \n * \n * Return true if the final two digits in s are the same; otherwise, return\n * false.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"3902\"\n * \n * Output: true\n * \n * Explanation:\n * \n * \n * Initially, s = \"3902\"\n * First operation:\n * \n * (s[0] + s[1]) % 10 = (3 + 9) % 10 = 2\n * (s[1] + s[2]) % 10 = (9 + 0) % 10 = 9\n * (s[2] + s[3]) % 10 = (0 + 2) % 10 = 2\n * s becomes \"292\"\n * \n * \n * Second operation:\n * \n * (s[0] + s[1]) % 10 = (2 + 9) % 10 = 1\n * (s[1] + s[2]) % 10 = (9 + 2) % 10 = 1\n * s becomes \"11\"\n * \n * \n * Since the digits in \"11\" are the same, the output is true.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: s = \"34789\"\n * \n * Output: false\n * \n * Explanation:\n * \n * \n * Initially, s = \"34789\".\n * After the first operation, s = \"7157\".\n * After the second operation, s = \"862\".\n * After the third operation, s = \"48\".\n * Since '4' != '8', the output is false.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 3 <= s.length <= 100\n * s consists of only digits.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool hasSameDigits(string s) {\n        if(s.length() == 2) {\n            return s[0] == s[1];\n        }\n        string next;\n        for(int i=0; i<s.length()-1; i++) {\n            next += to_string((s[i] - '0' + s[i+1] - '0') % 10);\n        }\n        return hasSameDigits(next);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3340.check-balanced-string.cpp","id":3340,"qid":"3340","title":"Check Balanced String","kebab":"check-balanced-string","rating":1190.7,"ratingLabel":"1190.7","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3340.check-balanced-string.cpp","leetcodeUrl":"https://leetcode.com/problems/check-balanced-string/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3340.check-balanced-string.cpp","code":"class Solution {\npublic:\n    bool isBalanced(string num) {\n        int even = 0, odd = 0;\n        for(int i=0; i<num.size(); i++) {\n            if(i % 2) even += num[i] - '0';\n            else odd += num[i] - '0';\n        }\n        return even == odd;\n    }\n};\n"},{"key":"problem:problems/0000-1199-newbie/3370.smallest-number-with-all-set-bits.cpp","id":3370,"qid":"3370","title":"Smallest Number With All Set Bits","kebab":"smallest-number-with-all-set-bits","rating":1198.6,"ratingLabel":"1198.6","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3370.smallest-number-with-all-set-bits.cpp","leetcodeUrl":"https://leetcode.com/problems/smallest-number-with-all-set-bits/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3370.smallest-number-with-all-set-bits.cpp","code":"/*\n * @lc app=leetcode id=3370 lang=cpp\n *\n * [3370] Smallest Number With All Set Bits\n *\n * https://leetcode.com/problems/smallest-number-with-all-set-bits/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a positive number n.\n * \n * Return the smallest number x greater than or equal to n, such that the\n * binary representation of x contains only set bits\n * \n * \n * Example 1:\n * \n * \n * Input: n = 5\n * \n * Output: 7\n * \n * Explanation:\n * \n * The binary representation of 7 is \"111\".\n * \n * \n * Example 2:\n * \n * \n * Input: n = 10\n * \n * Output: 15\n * \n * Explanation:\n * \n * The binary representation of 15 is \"1111\".\n * \n * \n * Example 3:\n * \n * \n * Input: n = 3\n * \n * Output: 3\n * \n * Explanation:\n * \n * The binary representation of 3 is \"11\".\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int smallestNumber(int n) {\n        int res = 1;\n        while(n > res - 1) res *= 2;\n        return res - 1;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/0000-1199-newbie/3536.maximum-product-of-two-digits.cpp","id":3536,"qid":"3536","title":"Maximum Product Of Two Digits","kebab":"maximum-product-of-two-digits","rating":1199.2,"ratingLabel":"1199.2","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"problems/0000-1199-newbie/3536.maximum-product-of-two-digits.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-product-of-two-digits/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/0000-1199-newbie/3536.maximum-product-of-two-digits.cpp","code":"/*\n * @lc app=leetcode id=3536 lang=cpp\n *\n * [3536] Maximum Product of Two Digits\n *\n * https://leetcode.com/problems/maximum-product-of-two-digits/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a positive integer n.\n * \n * Return the maximum product of any two digits in n.\n * \n * Note: You may use the same digit twice if it appears more than once in n.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 31\n * \n * Output: 3\n * \n * Explanation:\n * \n * \n * The digits of n are [3, 1].\n * The possible products of any two digits are: 3 * 1 = 3.\n * The maximum product is 3.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 22\n * \n * Output: 4\n * \n * Explanation:\n * \n * \n * The digits of n are [2, 2].\n * The possible products of any two digits are: 2 * 2 = 4.\n * The maximum product is 4.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: n = 124\n * \n * Output: 8\n * \n * Explanation:\n * \n * \n * The digits of n are [1, 2, 4].\n * The possible products of any two digits are: 1 * 2 = 2, 1 * 4 = 4, 2 * 4 =\n * 8.\n * The maximum product is 8.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 10 <= n <= 10^9\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxProduct(int n) {\n        vector<int> digits;\n        while(n > 0) {\n            digits.push_back(n % 10);\n            n /= 10;\n        }\n        sort(digits.rbegin(), digits.rend());\n        return (digits[0]) * (digits[1]);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3550.smallest-index-with-digit-sum-equal-to-index.cpp","id":3550,"qid":"3550","title":"Smallest Index With Digit Sum Equal To Index","kebab":"smallest-index-with-digit-sum-equal-to-index","rating":1200.2,"ratingLabel":"1200.2","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3550.smallest-index-with-digit-sum-equal-to-index.cpp","leetcodeUrl":"https://leetcode.com/problems/smallest-index-with-digit-sum-equal-to-index/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3550.smallest-index-with-digit-sum-equal-to-index.cpp","code":"/*\n * @lc app=leetcode id=3550 lang=cpp\n *\n * [3550] Smallest Index With Digit Sum Equal to Index\n *\n * https://leetcode.com/problems/smallest-index-with-digit-sum-equal-to-index/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums.\n * \n * Return the smallest index i such that the sum of the digits of nums[i] is\n * equal to i.\n * \n * If no such index exists, return -1.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,3,2]\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * For nums[2] = 2, the sum of digits is 2, which is equal to index i = 2.\n * Thus, the output is 2.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,10,11]\n * \n * Output: 1\n * \n * Explanation:\n * \n * \n * For nums[1] = 10, the sum of digits is 1 + 0 = 1, which is equal to index i\n * = 1.\n * For nums[2] = 11, the sum of digits is 1 + 1 = 2, which is equal to index i\n * = 2.\n * Since index 1 is the smallest, the output is 1.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: nums = [1,2,3]\n * \n * Output: -1\n * \n * Explanation:\n * \n * \n * Since no index satisfies the condition, the output is -1.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 0 <= nums[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int smallestIndex(vector<int>& nums) {\n        for(int i=0;i<nums.size();i++){\n            int temp = 0;\n            while(nums[i] > 0) {\n                temp += nums[i] % 10;\n                nums[i] /= 10;\n            }\n            if(temp == i) return i;\n        }\n        return -1;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3392.count-subarrays-of-length-three-with-a-condition.cpp","id":3392,"qid":"3392","title":"Count Subarrays Of Length Three With A Condition","kebab":"count-subarrays-of-length-three-with-a-condition","rating":1200.7,"ratingLabel":"1200.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3392.count-subarrays-of-length-three-with-a-condition.cpp","leetcodeUrl":"https://leetcode.com/problems/count-subarrays-of-length-three-with-a-condition/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3392.count-subarrays-of-length-three-with-a-condition.cpp","code":"/*\n * @lc app=leetcode id=3392 lang=cpp\n *\n * [3392] Count Subarrays of Length Three With a Condition\n *\n * https://leetcode.com/problems/count-subarrays-of-length-three-with-a-condition/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Given an integer array nums, return the number of subarrays of length 3 such\n * that the sum of the first and third numbers equals exactly half of the\n * second number.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,1,4,1]\n * \n * Output: 1\n * \n * Explanation:\n * \n * Only the subarray [1,4,1] contains exactly 3 elements where the sum of the\n * first and third numbers equals half the middle number.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,1,1]\n * \n * Output: 0\n * \n * Explanation:\n * \n * [1,1,1] is the only subarray of length 3. However, its first and third\n * numbers do not add to half the middle number.\n * \n * \n * \n * Constraints:\n * \n * \n * 3 <= nums.length <= 100\n * -100 <= nums[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int countSubarrays(vector<int>& nums) {\n        int res = 0;\n        for(int i=0; i+2<nums.size(); i++) {\n            if((nums[i] + nums[i+2]) * 2 == nums[i+1]) res++;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3498.reverse-degree-of-a-string.cpp","id":3498,"qid":"3498","title":"Reverse Degree Of A String","kebab":"reverse-degree-of-a-string","rating":1201.3,"ratingLabel":"1201.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3498.reverse-degree-of-a-string.cpp","leetcodeUrl":"https://leetcode.com/problems/reverse-degree-of-a-string/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3498.reverse-degree-of-a-string.cpp","code":"/*\n * @lc app=leetcode id=3498 lang=cpp\n *\n * [3498] Reverse Degree of a String\n *\n * https://leetcode.com/problems/reverse-degree-of-a-string/description/\n *\n * Category: algorithms\n * Difficult: Easy\n *\n * Given a string s, calculate its reverse degree.\n * \n * The reverse degree is calculated as follows:\n * \n * \n * For each character, multiply its position in the reversed alphabet ('a' =\n * 26, 'b' = 25, ..., 'z' = 1) with its position in the string (1-indexed).\n * Sum these products for all characters in the string.\n * \n * \n * Return the reverse degree of s.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"abc\"\n * \n * Output: 148\n * \n * Explanation:\n * \n * \n * \n * \n * Letter\n * Index in Reversed Alphabet\n * Index in String\n * Product\n * \n * \n * 'a'\n * 26\n * 1\n * 26\n * \n * \n * 'b'\n * 25\n * 2\n * 50\n * \n * \n * 'c'\n * 24\n * 3\n * 72\n * \n * \n * \n * \n * The reversed degree is 26 + 50 + 72 = 148.\n * \n * \n * Example 2:\n * \n * \n * Input: s = \"zaza\"\n * \n * Output: 160\n * \n * Explanation:\n * \n * \n * \n * \n * Letter\n * Index in Reversed Alphabet\n * Index in String\n * Product\n * \n * \n * 'z'\n * 1\n * 1\n * 1\n * \n * \n * 'a'\n * 26\n * 2\n * 52\n * \n * \n * 'z'\n * 1\n * 3\n * 3\n * \n * \n * 'a'\n * 26\n * 4\n * 104\n * \n * \n * \n * \n * The reverse degree is 1 + 52 + 3 + 104 = 160.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= s.length <= 1000\n * s contains only lowercase English letters.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int reverseDegree(string s) {\n        int res = 0;\n        for(int i=0; i < s.size(); i++) {\n            res +=  ('z' - s[i] + 1) * (i + 1);\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3280.convert-date-to-binary.cpp","id":3280,"qid":"3280","title":"Convert Date To Binary","kebab":"convert-date-to-binary","rating":1205.7,"ratingLabel":"1205.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3280.convert-date-to-binary.cpp","leetcodeUrl":"https://leetcode.com/problems/convert-date-to-binary/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3280.convert-date-to-binary.cpp","code":"/*\n * @lc app=leetcode id=3280 lang=cpp\n *\n * [3280] Convert Date to Binary\n *\n * https://leetcode.com/problems/convert-date-to-binary/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string date representing a Gregorian calendar date in the\n * yyyy-mm-dd format.\n * \n * date can be written in its binary representation obtained by converting\n * year, month, and day to their binary representations without any leading\n * zeroes and writing them down in year-month-day format.\n * \n * Return the binary representation of date.\n * \n * \n * Example 1:\n * \n * \n * Input: date = \"2080-02-29\"\n * \n * Output: \"100000100000-10-11101\"\n * \n * Explanation:\n * \n * 100000100000, 10, and 11101 are the binary representations of 2080, 02, and\n * 29 respectively.\n * \n * \n * Example 2:\n * \n * \n * Input: date = \"1900-01-01\"\n * \n * Output: \"11101101100-1-1\"\n * \n * Explanation:\n * \n * 11101101100, 1, and 1 are the binary representations of 1900, 1, and 1\n * respectively.\n * \n * \n * \n * Constraints:\n * \n * \n * date.length == 10\n * date[4] == date[7] == '-', and all other date[i]'s are digits.\n * The input is generated such that date represents a valid Gregorian calendar\n * date between Jan 1^st, 1900 and Dec 31^st, 2100 (both inclusive).\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string convertDateToBinary(string date) {\n        int year = 0, month = 0, day = 0;\n        year += (date[0] - '0') * 1000;\n        year += (date[1] - '0') * 100;\n        year += (date[2] - '0') * 10;\n        year += (date[3] - '0');\n\n        month += (date[5] - '0') * 10;\n        month += (date[6] - '0');\n\n        day += (date[8] - '0') * 10;\n        day += (date[9] - '0');\n\n        string res1, res2, res3;\n        while(year > 0) {\n            res1 += to_string(year % 2);\n            year /= 2;\n        }\n        reverse(res1.begin(), res1.end());\n        while(month > 0) {\n            res2 += to_string(month % 2);\n            month /= 2;\n        }\n        reverse(res2.begin(), res2.end());\n        while(day > 0) {\n            res3 += to_string(day % 2);\n            day /= 2;\n        }\n        reverse(res3.begin(), res3.end());\n\n        string res = res1 + \"-\" + res2 + \"-\" + res3;\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3545.minimum-deletions-for-at-most-k-distinct-characters.cpp","id":3545,"qid":"3545","title":"Minimum Deletions For At Most K Distinct Characters","kebab":"minimum-deletions-for-at-most-k-distinct-characters","rating":1211.0,"ratingLabel":"1211.0","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3545.minimum-deletions-for-at-most-k-distinct-characters.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-deletions-for-at-most-k-distinct-characters/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3545.minimum-deletions-for-at-most-k-distinct-characters.cpp","code":"/*\n * @lc app=leetcode id=3545 lang=cpp\n *\n * [3545] Minimum Deletions for At Most K Distinct Characters\n *\n * https://leetcode.com/problems/minimum-deletions-for-at-most-k-distinct-characters/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string s consisting of lowercase English letters, and an\n * integer k.\n * \n * Your task is to delete some (possibly none) of the characters in the string\n * so that the number of distinct characters in the resulting string is at most\n * k.\n * \n * Return the minimum number of deletions required to achieve this.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"abc\", k = 2\n * \n * Output: 1\n * \n * Explanation:\n * \n * \n * s has three distinct characters: 'a', 'b' and 'c', each with a frequency of\n * 1.\n * Since we can have at most k = 2 distinct characters, remove all occurrences\n * of any one character from the string.\n * For example, removing all occurrences of 'c' results in at most k distinct\n * characters. Thus, the answer is 1.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: s = \"aabb\", k = 2\n * \n * Output: 0\n * \n * Explanation:\n * \n * \n * s has two distinct characters ('a' and 'b') with frequencies of 2 and 2,\n * respectively.\n * Since we can have at most k = 2 distinct characters, no deletions are\n * required. Thus, the answer is 0.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: s = \"yyyzz\", k = 1\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * s has two distinct characters ('y' and 'z') with frequencies of 3 and 2,\n * respectively.\n * Since we can have at most k = 1 distinct character, remove all occurrences\n * of any one character from the string.\n * Removing all 'z' results in at most k distinct characters. Thus, the answer\n * is 2.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= s.length <= 16\n * 1 <= k <= 16\n * s consists only of lowercase English letters.\n * \n * \n * \u2060\n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minDeletion(string s, int k) {\n        sort(s.begin(), s.end());\n        vector<int> freq;\n        for(int i=0; i<s.length(); i++) {\n            int temp = 0;\n            char c = s[i];\n            while(i < s.length() && s[i] == c) {\n                temp++;\n                i++;\n            }\n            freq.push_back(temp);\n            i--;\n        }\n        sort(freq.rbegin(), freq.rend());\n        int res = 0;\n        for(int i=k; i<freq.size(); i++) {\n            res += freq[i];\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3658.gcd-of-odd-and-even-sums.cpp","id":3658,"qid":"3658","title":"Gcd Of Odd And Even Sums","kebab":"gcd-of-odd-and-even-sums","rating":1220.1,"ratingLabel":"1220.1","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3658.gcd-of-odd-and-even-sums.cpp","leetcodeUrl":"https://leetcode.com/problems/gcd-of-odd-and-even-sums/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3658.gcd-of-odd-and-even-sums.cpp","code":"class Solution {\npublic:\n    int gcdOfOddEvenSums(int n) {\n        int a = 0, b = 0;\n        for(int i=1; i<=n; i++) {\n            a += 1 + 2 * i;\n            b += 2 * i;\n        }\n        return __gcd(a, b);\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3512.minimum-operations-to-make-array-sum-divisible-by-k.cpp","id":3512,"qid":"3512","title":"Minimum Operations To Make Array Sum Divisible By K","kebab":"minimum-operations-to-make-array-sum-divisible-by-k","rating":1228.3,"ratingLabel":"1228.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3512.minimum-operations-to-make-array-sum-divisible-by-k.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-operations-to-make-array-sum-divisible-by-k/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3512.minimum-operations-to-make-array-sum-divisible-by-k.cpp","code":"/*\n * @lc app=leetcode id=3512 lang=cpp\n *\n * [3512] Minimum Operations to Make Array Sum Divisible by K\n *\n * https://leetcode.com/problems/minimum-operations-to-make-array-sum-divisible-by-k/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums and an integer k. You can perform the\n * following operation any number of times:\n * \n * \n * Select an index i and replace nums[i] with nums[i] - 1.\n * \n * \n * Return the minimum number of operations required to make the sum of the\n * array divisible by k.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [3,9,7], k = 5\n * \n * Output: 4\n * \n * Explanation:\n * \n * \n * Perform 4 operations on nums[1] = 9. Now, nums = [3, 5, 7].\n * The sum is 15, which is divisible by 5.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [4,1,3], k = 4\n * \n * Output: 0\n * \n * Explanation:\n * \n * \n * The sum is 8, which is already divisible by 4. Hence, no operations are\n * needed.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: nums = [3,2], k = 6\n * \n * Output: 5\n * \n * Explanation:\n * \n * \n * Perform 3 operations on nums[0] = 3 and 2 operations on nums[1] = 2. Now,\n * nums = [0, 0].\n * The sum is 0, which is divisible by 6.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 1000\n * 1 <= nums[i] <= 1000\n * 1 <= k <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minOperations(vector<int>& nums, int k) {\n        int sum = 0;\n        for(auto& i : nums) sum += i;\n        return sum % k;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3591.check-if-any-element-has-prime-frequency.cpp","id":3591,"qid":"3591","title":"Check If Any Element Has Prime Frequency","kebab":"check-if-any-element-has-prime-frequency","rating":1234.5,"ratingLabel":"1234.5","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3591.check-if-any-element-has-prime-frequency.cpp","leetcodeUrl":"https://leetcode.com/problems/check-if-any-element-has-prime-frequency/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3591.check-if-any-element-has-prime-frequency.cpp","code":"/*\n * @lc app=leetcode id=3591 lang=cpp\n *\n * [3591] Check if Any Element Has Prime Frequency\n *\n * https://leetcode.com/problems/check-if-any-element-has-prime-frequency/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums.\n * \n * Return true if the frequency of any element of the array is prime,\n * otherwise, return false.\n * \n * The frequency of an element x is the number of times it occurs in the\n * array.\n * \n * A prime number is a natural number greater than 1 with only two factors, 1\n * and itself.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,3,4,5,4]\n * \n * Output: true\n * \n * Explanation:\n * \n * 4 has a frequency of two, which is a prime number.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,2,3,4,5]\n * \n * Output: false\n * \n * Explanation:\n * \n * All elements have a frequency of one.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [2,2,2,4,4]\n * \n * Output: true\n * \n * Explanation:\n * \n * Both 2 and 4 have a prime frequency.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 0 <= nums[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\n\npublic:\n\n    #define MAXN 1000005\n    bitset<MAXN> is_prime;\n    vector<int> primes;\n\n    void sieve(int N) {\n        is_prime.set();\n        is_prime[0] = is_prime[1] = 0;\n\n        for (int i = 2; i <= N; ++i) {\n            if (is_prime[i]) {\n                primes.push_back(i);\n                for (int j = i * 2; j <= N; j += i) {\n                    is_prime[j] = 0;\n                }\n            }\n        }\n    }\n\n    bool checkPrimeFrequency(vector<int>& nums) {\n        int N = 100;\n        sieve(N);\n\n        unordered_map<int, int> freq;\n        for (int num : nums) {\n            freq[num]++;\n        }\n\n        for (auto it : freq) {\n            int count = it.second;\n            if (count <= N && is_prime[count]) {\n                return true;\n            }\n        }\n\n        return false; \n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3643.flip-square-submatrix-vertically.cpp","id":3643,"qid":"3643","title":"Flip Square Submatrix Vertically","kebab":"flip-square-submatrix-vertically","rating":1235.0,"ratingLabel":"1235.0","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3643.flip-square-submatrix-vertically.cpp","leetcodeUrl":"https://leetcode.com/problems/flip-square-submatrix-vertically/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3643.flip-square-submatrix-vertically.cpp","code":"class Solution {\npublic:\n    vector<vector<int>> reverseSubmatrix(vector<vector<int>>& g, int x, int y, int k) {\n        for(int i=0; i<k/2; i++) {\n            for(int j=0; j<k; j++) {\n                swap(g[x+i][y+j], g[x+k-1-i][y+j]);\n            }\n        }\n        return g;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3345.smallest-divisible-digit-product-i.cpp","id":3345,"qid":"3345","title":"Smallest Divisible Digit Product I","kebab":"smallest-divisible-digit-product-i","rating":1235.1,"ratingLabel":"1235.1","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3345.smallest-divisible-digit-product-i.cpp","leetcodeUrl":"https://leetcode.com/problems/smallest-divisible-digit-product-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3345.smallest-divisible-digit-product-i.cpp","code":"class Solution {\npublic:\n    int prod(int n) {\n        int p = 1;\n        while(n > 0) {\n            p *= n % 10;\n            n /= 10;\n        }\n        return p;\n    }\n    int smallestNumber(int n, int t) {\n        int res = n;\n        while(prod(res) % t != 0) res++;\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3541.find-most-frequent-vowel-and-consonant.cpp","id":3541,"qid":"3541","title":"Find Most Frequent Vowel And Consonant","kebab":"find-most-frequent-vowel-and-consonant","rating":1238.9,"ratingLabel":"1238.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3541.find-most-frequent-vowel-and-consonant.cpp","leetcodeUrl":"https://leetcode.com/problems/find-most-frequent-vowel-and-consonant/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3541.find-most-frequent-vowel-and-consonant.cpp","code":"/*\n * @lc app=leetcode id=3541 lang=cpp\n *\n * [3541] Find Most Frequent Vowel and Consonant\n *\n * https://leetcode.com/problems/find-most-frequent-vowel-and-consonant/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string s consisting of lowercase English letters ('a' to\n * 'z'). \n * \n * Your task is to:\n * \n * \n * Find the vowel (one of 'a', 'e', 'i', 'o', or 'u') with the maximum\n * frequency.\n * Find the consonant (all other letters excluding vowels) with the maximum\n * frequency.\n * \n * \n * Return the sum of the two frequencies.\n * \n * Note: If multiple vowels or consonants have the same maximum frequency, you\n * may choose any one of them. If there are no vowels or no consonants in the\n * string, consider their frequency as 0.\n * The frequency of a letter x is the number of times it occurs in the\n * string.\n * \n * Example 1:\n * \n * \n * Input: s = \"successes\"\n * \n * Output: 6\n * \n * Explanation:\n * \n * \n * The vowels are: 'u' (frequency 1), 'e' (frequency 2). The maximum frequency\n * is 2.\n * The consonants are: 's' (frequency 4), 'c' (frequency 2). The maximum\n * frequency is 4.\n * The output is 2 + 4 = 6.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: s = \"aeiaeia\"\n * \n * Output: 3\n * \n * Explanation:\n * \n * \n * The vowels are: 'a' (frequency 3), 'e' ( frequency 2), 'i' (frequency 2).\n * The maximum frequency is 3.\n * There are no consonants in s. Hence, maximum consonant frequency = 0.\n * The output is 3 + 0 = 3.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= s.length <= 100\n * s consists of lowercase English letters only.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxFreqSum(string s) {\n        unordered_map<char, int> ump;\n        for(auto& i : s) ump[i] ++;\n\n        int res1 = 0, res2 = 0;\n        for(auto& i : ump) {\n            if(i.first == 'a') res1 = max(res1, i.second);\n            else if(i.first == 'e') res1 = max(res1, i.second);\n            else if(i.first == 'i') res1 = max(res1, i.second);\n            else if(i.first == 'o') res1 = max(res1, i.second);\n            else if(i.first == 'u') res1 = max(res1, i.second);\n            else res2 = max(res2, i.second);\n        }\n        return res1 + res2;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3502.minimum-cost-to-reach-every-position.cpp","id":3502,"qid":"3502","title":"Minimum Cost To Reach Every Position","kebab":"minimum-cost-to-reach-every-position","rating":1243.9,"ratingLabel":"1243.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3502.minimum-cost-to-reach-every-position.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-cost-to-reach-every-position/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3502.minimum-cost-to-reach-every-position.cpp","code":"/*\n * @lc app=leetcode id=3502 lang=cpp\n *\n * [3502] Minimum Cost to Reach Every Position\n *\n * https://leetcode.com/problems/minimum-cost-to-reach-every-position/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array cost of size n. You are currently at position\n * n (at the end of the line) in a line of n + 1 people (numbered from 0 to\n * n).\n * \n * You wish to move forward in the line, but each person in front of you\n * charges a specific amount to swap places. The cost to swap with person i is\n * given by cost[i].\n * \n * You are allowed to swap places with people as follows:\n * \n * \n * If they are in front of you, you must pay them cost[i] to swap with\n * them.\n * If they are behind you, they can swap with you for free.\n * \n * \n * Return an array answer of size n, where answer[i] is the minimum total cost\n * to reach each position i in the line.\n * \n * \n * Example 1:\n * \n * \n * Input: cost = [5,3,4,1,3,2]\n * \n * Output: [5,3,3,1,1,1]\n * \n * Explanation:\n * \n * We can get to each position in the following way:\n * \n * \n * i = 0. We can swap with person 0 for a cost of 5.\n * i = 1. We can swap with person 1 for a cost of 3.\n * i = 2. We can swap with person 1 for a cost of 3, then swap with person 2\n * for free.\n * i = 3. We can swap with person 3 for a cost of 1.\n * i = 4. We can swap with person 3 for a cost of 1, then swap with person 4\n * for free.\n * i = 5. We can swap with person 3 for a cost of 1, then swap with person 5\n * for free.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: cost = [1,2,4,6,7]\n * \n * Output: [1,1,1,1,1]\n * \n * Explanation:\n * \n * We can swap with person 0 for a cost of 1, then we will be able to reach any\n * position i for free.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n == cost.length <= 100\n * 1 <= cost[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> minCosts(vector<int>& cost) {\n        vector<int> res(cost.size(), 0);\n        int min = cost[0];\n        for(int i=0; i<cost.size(); i++) {\n            if(cost[i] < min) {\n                min = cost[i];\n            }\n            res[i] = min;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3402.minimum-operations-to-make-columns-strictly-increasing.cpp","id":3402,"qid":"3402","title":"Minimum Operations To Make Columns Strictly Increasing","kebab":"minimum-operations-to-make-columns-strictly-increasing","rating":1245.8,"ratingLabel":"1245.8","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3402.minimum-operations-to-make-columns-strictly-increasing.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-operations-to-make-columns-strictly-increasing/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3402.minimum-operations-to-make-columns-strictly-increasing.cpp","code":"/*\n * @lc app=leetcode id=3402 lang=cpp\n *\n * [3402] Minimum Operations to Make Columns Strictly Increasing\n *\n * https://leetcode.com/problems/minimum-operations-to-make-columns-strictly-increasing/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a m x n matrix grid consisting of non-negative integers.\n * \n * In one operation, you can increment the value of any grid[i][j] by 1.\n * \n * Return the minimum number of operations needed to make all columns of grid\n * strictly increasing.\n * \n * \n * Example 1:\n * \n * \n * Input: grid = [[3,2],[1,3],[3,4],[0,1]]\n * \n * Output: 15\n * \n * Explanation:\n * \n * \n * To make the 0^th column strictly increasing, we can apply 3 operations on\n * grid[1][0], 2 operations on grid[2][0], and 6 operations on grid[3][0].\n * To make the 1^st column strictly increasing, we can apply 4 operations on\n * grid[3][1].\n * \n * \n * \n * Example 2:\n * \n * \n * Input: grid = [[3,2,1],[2,1,0],[1,2,3]]\n * \n * Output: 12\n * \n * Explanation:\n * \n * \n * To make the 0^th column strictly increasing, we can apply 2 operations on\n * grid[1][0], and 4 operations on grid[2][0].\n * To make the 1^st column strictly increasing, we can apply 2 operations on\n * grid[1][1], and 2 operations on grid[2][1].\n * To make the 2^nd column strictly increasing, we can apply 2 operations on\n * grid[1][2].\n * \n * \n * \n * \n * Constraints:\n * \n * \n * m == grid.length\n * n == grid[i].length\n * 1 <= m, n <= 50\n * 0 <= grid[i][j] < 2500\n * \n * \n * \n * \n * \n * \n * \n * \n * \n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minimumOperations(vector<vector<int>>& grid) {\n        int res = 0;\n        for(int j=0; j < grid[0].size(); j++) {\n            int prev = grid[0][j];\n            for(int i=1; i < grid.size(); i++) {\n                if(prev >= grid[i][j]) {\n                    res += prev - grid[i][j] + 1;\n                    prev++;\n                }\n                prev = max(prev, grid[i][j]);\n            }\n        }\n        return res;    \n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3668.restore-finishing-order.cpp","id":3668,"qid":"3668","title":"Restore Finishing Order","kebab":"restore-finishing-order","rating":1255.2,"ratingLabel":"1255.2","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3668.restore-finishing-order.cpp","leetcodeUrl":"https://leetcode.com/problems/restore-finishing-order/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3668.restore-finishing-order.cpp","code":"class Solution {\npublic:\n    vector<int> recoverOrder(vector<int>& order, vector<int>& friends) {\n        vector<int> res;\n        for(auto& i : order) {\n            if(find(friends.begin(), friends.end(), i) != friends.end()) res.push_back(i);\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3386.button-with-longest-push-time.cpp","id":3386,"qid":"3386","title":"Button With Longest Push Time","kebab":"button-with-longest-push-time","rating":1255.5,"ratingLabel":"1255.5","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3386.button-with-longest-push-time.cpp","leetcodeUrl":"https://leetcode.com/problems/button-with-longest-push-time/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3386.button-with-longest-push-time.cpp","code":"/*\n * @lc app=leetcode id=3386 lang=cpp\n *\n * [3386] Button with Longest Push Time\n *\n * https://leetcode.com/problems/button-with-longest-push-time/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a 2D array events which represents a sequence of events where\n * a child pushes a series of buttons on a keyboard.\n * \n * Each events[i] = [indexi, timei] indicates that the button at index indexi\n * was pressed at time timei.\n * \n * \n * The array is sorted in increasing order of time.\n * The time taken to press a button is the difference in time between\n * consecutive button presses. The time for the first button is simply the time\n * at which it was pressed.\n * \n * \n * Return the index of the button that took the longest time to push. If\n * multiple buttons have the same longest time, return the button with the\n * smallest index.\n * \n * \n * Example 1:\n * \n * \n * Input: events = [[1,2],[2,5],[3,9],[1,15]]\n * \n * Output: 1\n * \n * Explanation:\n * \n * \n * Button with index 1 is pressed at time 2.\n * Button with index 2 is pressed at time 5, so it took 5 - 2 = 3 units of\n * time.\n * Button with index 3 is pressed at time 9, so it took 9 - 5 = 4 units of\n * time.\n * Button with index 1 is pressed again at time 15, so it took 15 - 9 = 6 units\n * of time.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: events = [[10,5],[1,7]]\n * \n * Output: 10\n * \n * Explanation:\n * \n * \n * Button with index 10 is pressed at time 5.\n * Button with index 1 is pressed at time 7, so it took 7 - 5 = 2 units of\n * time.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= events.length <= 1000\n * events[i] == [indexi, timei]\n * 1 <= indexi, timei <= 10^5\n * The input is generated such that events is sorted in increasing order of\n * timei.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int buttonWithLongestTime(vector<vector<int>>& events) {\n        map<int, int> mp;\n        for(int i=0; i<events.size(); i++) {\n            if(i == 0) {\n                mp[events[i][0]] = events[i][1];\n            } else {\n                mp[events[i][0]] = max(mp[events[i][0]], events[i][1] - events[i-1][1]);\n            }\n        }\n        int res = 0;\n        int maxTime = 0;\n        for(auto& [key, value] : mp) {\n            if(value > maxTime) {\n                maxTime = value;\n                res = key;\n            } else if(value == maxTime) {\n                res = min(res, key);\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3379.transformed-array.cpp","id":3379,"qid":"3379","title":"Transformed Array","kebab":"transformed-array","rating":1256.6,"ratingLabel":"1256.6","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3379.transformed-array.cpp","leetcodeUrl":"https://leetcode.com/problems/transformed-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3379.transformed-array.cpp","code":"/*\n * @lc app=leetcode id=3379 lang=cpp\n *\n * [3379] Transformed Array\n *\n * https://leetcode.com/problems/transformed-array/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums that represents a circular array. Your\n * task is to create a new array result of the same size, following these\n * rules:\n * For each index i (where 0 <= i < nums.length), perform the following\n * independent actions:\n * \n * \n * If nums[i] > 0: Start at index i and move nums[i] steps to the right in the\n * circular array. Set result[i] to the value of the index where you land.\n * If nums[i] < 0: Start at index i and move abs(nums[i]) steps to the left in\n * the circular array. Set result[i] to the value of the index where you\n * land.\n * If nums[i] == 0: Set result[i] to nums[i].\n * \n * \n * Return the new array result.\n * \n * Note: Since nums is circular, moving past the last element wraps around to\n * the beginning, and moving before the first element wraps back to the end.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [3,-2,1,1]\n * \n * Output: [1,1,1,3]\n * \n * Explanation:\n * \n * \n * For nums[0] that is equal to 3, If we move 3 steps to right, we reach\n * nums[3]. So result[0] should be 1.\n * For nums[1] that is equal to -2, If we move 2 steps to left, we reach\n * nums[3]. So result[1] should be 1.\n * For nums[2] that is equal to 1, If we move 1 step to right, we reach\n * nums[3]. So result[2] should be 1.\n * For nums[3] that is equal to 1, If we move 1 step to right, we reach\n * nums[0]. So result[3] should be 3.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [-1,4,-1]\n * \n * Output: [-1,-1,4]\n * \n * Explanation:\n * \n * \n * For nums[0] that is equal to -1, If we move 1 step to left, we reach\n * nums[2]. So result[0] should be -1.\n * For nums[1] that is equal to 4, If we move 4 steps to right, we reach\n * nums[2]. So result[1] should be -1.\n * For nums[2] that is equal to -1, If we move 1 step to left, we reach\n * nums[1]. So result[2] should be 4.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * -100 <= nums[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> constructTransformedArray(vector<int>& nums) {\n        vector<int> res(nums.size());\n        for(int i=0; i<nums.size(); i++) {\n            if(nums[i] == 0) {\n                res[i] = nums[i];\n            }\n            else if(nums[i] > 0) {\n                int index = (i + nums[i]) % nums.size();\n                res[i] = nums[index];\n            }\n            else if(nums[i] < 0) {\n                int index = (i + nums[i] + 100 * nums.size()) % nums.size();\n                res[i] = nums[index];\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3637.trionic-array-i.cpp","id":3637,"qid":"3637","title":"Trionic Array I","kebab":"trionic-array-i","rating":1263.9,"ratingLabel":"1263.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3637.trionic-array-i.cpp","leetcodeUrl":"https://leetcode.com/problems/trionic-array-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3637.trionic-array-i.cpp","code":"class Solution {\npublic:\n    bool isTrionic(vector<int>& nums) {\n        if(nums[0] > nums[1]) return false;\n        int cnt = 0, pre = 1;\n        for(int i=0; i+1<nums.size(); i++) {\n            if(nums[i] < nums[i+1]) {\n                if(pre == -1) pre = 1, cnt ++;\n            }\n            else if(nums[i] > nums[i+1]) {\n                if(pre == 1) pre = -1, cnt++;\n            }\n            else return false;\n        }\n        return cnt == 2;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3360.stone-removal-game.cpp","id":3360,"qid":"3360","title":"Stone Removal Game","kebab":"stone-removal-game","rating":1267.5,"ratingLabel":"1267.5","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3360.stone-removal-game.cpp","leetcodeUrl":"https://leetcode.com/problems/stone-removal-game/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3360.stone-removal-game.cpp","code":"/*\n * @lc app=leetcode id=3360 lang=cpp\n *\n * [3360] Stone Removal Game\n *\n * https://leetcode.com/problems/stone-removal-game/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Alice and Bob are playing a game where they take turns removing stones from\n * a pile, with Alice going first.\n * \n * \n * Alice starts by removing exactly 10 stones on her first turn.\n * For each subsequent turn, each player removes exactly 1 fewer stone than the\n * previous opponent.\n * \n * \n * The player who cannot make a move loses the game.\n * \n * Given a positive integer n, return true if Alice wins the game and false\n * otherwise.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 12\n * \n * Output: true\n * \n * Explanation:\n * \n * \n * Alice removes 10 stones on her first turn, leaving 2 stones for Bob.\n * Bob cannot remove 9 stones, so Alice wins.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 1\n * \n * Output: false\n * \n * Explanation:\n * \n * \n * Alice cannot remove 10 stones, so Alice loses.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 50\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool canAliceWin(int n) {\n        int turn = 10, sum = 0, who = 1;\n        while(sum <= n) {\n            sum += turn;\n            turn--;\n            who = (who + 1) % 2;\n        }\n        return who == 1;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3663.find-the-least-frequent-digit.cpp","id":3663,"qid":"3663","title":"Find The Least Frequent Digit","kebab":"find-the-least-frequent-digit","rating":1284.4,"ratingLabel":"1284.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3663.find-the-least-frequent-digit.cpp","leetcodeUrl":"https://leetcode.com/problems/find-the-least-frequent-digit/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3663.find-the-least-frequent-digit.cpp","code":"class Solution {\npublic:\n    int getLeastFrequentDigit(int n) {\n        map<int, int> mp;\n        while(n > 0) {\n            mp[n % 10] ++;\n            n /= 10;\n        }\n\n        int res = -1, cnt = INT_MAX;\n        for(auto& i : mp) {\n            if(i.second < cnt) {\n                res = i.first;\n                cnt = i.second;\n            }\n            else if(i.second == cnt) res = min(res, i.first);\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/2833.furthest-point-from-origin.cpp","id":2833,"qid":"2833","title":"Furthest Point From Origin","kebab":"furthest-point-from-origin","rating":1294.3,"ratingLabel":"1294.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/2833.furthest-point-from-origin.cpp","leetcodeUrl":"https://leetcode.com/problems/furthest-point-from-origin/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/2833.furthest-point-from-origin.cpp","code":"/*\n * @lc app=leetcode id=2833 lang=cpp\n *\n * [2833] Furthest Point From Origin\n *\n * https://leetcode.com/problems/furthest-point-from-origin/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string moves of length n consisting only of characters 'L',\n * 'R', and '_'. The string represents your movement on a number line starting\n * from the origin 0.\n * \n * In the i^th move, you can choose one of the following directions:\n * \n * \n * move to the left if moves[i] = 'L' or moves[i] = '_'\n * move to the right if moves[i] = 'R' or moves[i] = '_'\n * \n * \n * Return the distance from the origin of the furthest point you can get to\n * after n moves.\n * \n * \n * Example 1:\n * \n * \n * Input: moves = \"L_RL__R\"\n * Output: 3\n * Explanation: The furthest point we can reach from the origin 0 is point -3\n * through the following sequence of moves \"LLRLLLR\".\n * \n * \n * Example 2:\n * \n * \n * Input: moves = \"_R__LL_\"\n * Output: 5\n * Explanation: The furthest point we can reach from the origin 0 is point -5\n * through the following sequence of moves \"LRLLLLL\".\n * \n * \n * Example 3:\n * \n * \n * Input: moves = \"_______\"\n * Output: 7\n * Explanation: The furthest point we can reach from the origin 0 is point 7\n * through the following sequence of moves \"RRRRRRR\".\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= moves.length == n <= 50\n * moves consists only of characters 'L', 'R' and '_'.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int furthestDistanceFromOrigin(string moves) {\n        int LR = 0, add = 0;\n        for(auto& i : moves) {\n            if(i == 'L') LR++;\n            else if(i == 'R') LR--;\n            else add++;\n        }\n        return abs(LR) + add;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/2815.max-pair-sum-in-an-array.cpp","id":2815,"qid":"2815","title":"Max Pair Sum In An Array","kebab":"max-pair-sum-in-an-array","rating":1295.1,"ratingLabel":"1295.1","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/2815.max-pair-sum-in-an-array.cpp","leetcodeUrl":"https://leetcode.com/problems/max-pair-sum-in-an-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/2815.max-pair-sum-in-an-array.cpp","code":"/*\n * @lc app=leetcode id=2815 lang=cpp\n *\n * [2815] Max Pair Sum in an Array\n *\n * https://leetcode.com/problems/max-pair-sum-in-an-array/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums. You have to find the maximum sum of a\n * pair of numbers from nums such that the largest digit in both numbers is\n * equal.\n * \n * For example, 2373 is made up of three distinct digits: 2, 3, and 7, where 7\n * is the largest among them.\n * \n * Return the maximum sum or -1 if no such pair exists.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [112,131,411]\n * \n * Output: -1\n * \n * Explanation:\n * \n * Each numbers largest digit in order is [2,3,4].\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2536,1613,3366,162]\n * \n * Output: 5902\n * \n * Explanation:\n * \n * All the numbers have 6 as their largest digit, so the answer is 2536 + 3366\n * = 5902.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [51,71,17,24,42]\n * \n * Output: 88\n * \n * Explanation:\n * \n * Each number's largest digit in order is [5,7,7,4,4].\n * \n * So we have only two possible pairs, 71 + 17 = 88 and 24 + 42 = 66.\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= nums.length <= 100\n * 1 <= nums[i] <= 10^4\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxSum(vector<int>& nums) {\n        sort(nums.rbegin(), nums.rend());\n        vector<vector<int>> vt(10);\n\n        for(int i=0; i<nums.size(); i++) {\n            int x = -1;\n            for(int temp = nums[i]; temp>0; temp/=10) {\n                x = max(x, temp%10);\n            }\n            vt[x].push_back(nums[i]);\n        }\n\n        int res = -1;\n        for(int i=0; i<10; i++) {\n            if(vt[i].size() > 1) {\n                res = max(res, vt[i][0] + vt[i][1]);\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3477.fruits-into-baskets-ii.cpp","id":3477,"qid":"3477","title":"Fruits Into Baskets II","kebab":"fruits-into-baskets-ii","rating":1295.6,"ratingLabel":"1295.6","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3477.fruits-into-baskets-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/fruits-into-baskets-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3477.fruits-into-baskets-ii.cpp","code":"/*\n * @lc app=leetcode id=3477 lang=cpp\n *\n * [3477] Fruits Into Baskets II\n *\n * https://leetcode.com/problems/fruits-into-baskets-ii/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given two arrays of integers, fruits and baskets, each of length n,\n * where fruits[i] represents the quantity of the i^th type of fruit, and\n * baskets[j] represents the capacity of the j^th basket.\n * \n * From left to right, place the fruits according to these rules:\n * \n * \n * Each fruit type must be placed in the leftmost available basket with a\n * capacity greater than or equal to the quantity of that fruit type.\n * Each basket can hold only one type of fruit.\n * If a fruit type cannot be placed in any basket, it remains unplaced.\n * \n * \n * Return the number of fruit types that remain unplaced after all possible\n * allocations are made.\n * \n * \n * Example 1:\n * \n * \n * Input: fruits = [4,2,5], baskets = [3,5,4]\n * \n * Output: 1\n * \n * Explanation:\n * \n * \n * fruits[0] = 4 is placed in baskets[1] = 5.\n * fruits[1] = 2 is placed in baskets[0] = 3.\n * fruits[2] = 5 cannot be placed in baskets[2] = 4.\n * \n * \n * Since one fruit type remains unplaced, we return 1.\n * \n * \n * Example 2:\n * \n * \n * Input: fruits = [3,6,1], baskets = [6,4,7]\n * \n * Output: 0\n * \n * Explanation:\n * \n * \n * fruits[0] = 3 is placed in baskets[0] = 6.\n * fruits[1] = 6 cannot be placed in baskets[1] = 4 (insufficient capacity) but\n * can be placed in the next available basket, baskets[2] = 7.\n * fruits[2] = 1 is placed in baskets[1] = 4.\n * \n * \n * Since all fruits are successfully placed, we return 0.\n * \n * \n * \n * Constraints:\n * \n * \n * n == fruits.length == baskets.length\n * 1 <= n <= 100\n * 1 <= fruits[i], baskets[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int numOfUnplacedFruits(vector<int>& fruits, vector<int>& baskets) {\n        int unplaced = 0;\n        vector<int> placed(fruits.size(), 0);\n        for(int i=0; i<fruits.size(); i++) {\n            int check = 0;\n            for(int j=0; j<baskets.size(); j++) {\n                if(placed[j]) continue;\n                if(fruits[i] <= baskets[j]) {\n                    placed[j] = 1;\n                    check = 1;\n                    break;\n                }\n            }\n            if(!check) unplaced++;\n        }\n        return unplaced;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3349.adjacent-increasing-subarrays-detection-i.cpp","id":3349,"qid":"3349","title":"Adjacent Increasing Subarrays Detection I","kebab":"adjacent-increasing-subarrays-detection-i","rating":1298.9,"ratingLabel":"1298.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3349.adjacent-increasing-subarrays-detection-i.cpp","leetcodeUrl":"https://leetcode.com/problems/adjacent-increasing-subarrays-detection-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3349.adjacent-increasing-subarrays-detection-i.cpp","code":"/*\n * @lc app=leetcode id=3349 lang=cpp\n *\n * [3349] Adjacent Increasing Subarrays Detection I\n *\n * https://leetcode.com/problems/adjacent-increasing-subarrays-detection-i/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Given an array nums of n integers and an integer k, determine whether there\n * exist two adjacent subarrays of length k such that both subarrays are\n * strictly increasing. Specifically, check if there are two subarrays starting\n * at indices a and b (a < b), where:\n * \n * \n * Both subarrays nums[a..a + k - 1] and nums[b..b + k - 1] are strictly\n * increasing.\n * The subarrays must be adjacent, meaning b = a + k.\n * \n * \n * Return true if it is possible to find two such subarrays, and false\n * otherwise.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [2,5,7,8,9,2,3,4,3,1], k = 3\n * \n * Output: true\n * \n * Explanation:\n * \n * \n * The subarray starting at index 2 is [7, 8, 9], which is strictly\n * increasing.\n * The subarray starting at index 5 is [2, 3, 4], which is also strictly\n * increasing.\n * These two subarrays are adjacent, so the result is true.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,2,3,4,4,4,4,5,6,7], k = 5\n * \n * Output: false\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= nums.length <= 100\n * 1 < 2 * k <= nums.length\n * -1000 <= nums[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool hasIncreasingSubarrays(vector<int>& nums, int k) {\n        int n = nums.size();\n        for (int i = 0; i <= n - 2 * k; ++i) {\n            bool ok = true;\n            for (int j = i; j < i + k - 1; ++j) {\n                if (nums[j] >= nums[j + 1]) {\n                    ok = false;\n                    break;\n                }\n            }\n            if (!ok) continue;\n            for (int j = i + k; j < i + 2 * k - 1; ++j) {\n                if (nums[j] >= nums[j + 1]) {\n                    ok = false;\n                    break;\n                }\n            }\n            if (ok) return true;\n        }\n        return false;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3396.minimum-number-of-operations-to-make-elements-in-array-distinct.cpp","id":3396,"qid":"3396","title":"Minimum Number Of Operations To Make Elements In Array Distinct","kebab":"minimum-number-of-operations-to-make-elements-in-array-distinct","rating":1299.4,"ratingLabel":"1299.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3396.minimum-number-of-operations-to-make-elements-in-array-distinct.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-number-of-operations-to-make-elements-in-array-distinct/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3396.minimum-number-of-operations-to-make-elements-in-array-distinct.cpp","code":"/*\n * @lc app=leetcode id=3396 lang=cpp\n *\n * [3396] Minimum Number of Operations to Make Elements in Array Distinct\n *\n * https://leetcode.com/problems/minimum-number-of-operations-to-make-elements-in-array-distinct/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums. You need to ensure that the elements in\n * the array are distinct. To achieve this, you can perform the following\n * operation any number of times:\n * \n * \n * Remove 3 elements from the beginning of the array. If the array has fewer\n * than 3 elements, remove all remaining elements.\n * \n * \n * Note that an empty array is considered to have distinct elements. Return the\n * minimum number of operations needed to make the elements in the array\n * distinct.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,3,4,2,3,3,5,7]\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * In the first operation, the first 3 elements are removed, resulting in the\n * array [4, 2, 3, 3, 5, 7].\n * In the second operation, the next 3 elements are removed, resulting in the\n * array [3, 5, 7], which has distinct elements.\n * \n * \n * Therefore, the answer is 2.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [4,5,6,4,4]\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * In the first operation, the first 3 elements are removed, resulting in the\n * array [4, 4].\n * In the second operation, all remaining elements are removed, resulting in an\n * empty array.\n * \n * \n * Therefore, the answer is 2.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [6,7,8,9]\n * \n * Output: 0\n * \n * Explanation:\n * \n * The array already contains distinct elements. Therefore, the answer is\n * 0.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 1 <= nums[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minimumOperations(vector<int>& nums) {\n        int res = nums.size() / 3;\n        if(nums.size() % 3 != 0) res ++;\n        set<int> dis;\n        for(int i=nums.size()-1; i>=0; i--) {\n            if(dis.count(nums[i])) {\n                break;\n            }\n            else {\n                dis.insert(nums[i]);\n                if(i % 3 == 0) res--;\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3364.minimum-positive-sum-subarray.cpp","id":3364,"qid":"3364","title":"Minimum Positive Sum Subarray","kebab":"minimum-positive-sum-subarray","rating":1300.6,"ratingLabel":"1300.6","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3364.minimum-positive-sum-subarray.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-positive-sum-subarray/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3364.minimum-positive-sum-subarray.cpp","code":"/*\n * @lc app=leetcode id=3364 lang=cpp\n *\n * [3364] Minimum Positive Sum Subarray \n *\n * https://leetcode.com/problems/minimum-positive-sum-subarray/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums and two integers l and r. Your task is\n * to find the minimum sum of a subarray whose size is between l and r\n * (inclusive) and whose sum is greater than 0.\n * \n * Return the minimum sum of such a subarray. If no such subarray exists,\n * return -1.\n * \n * A subarray is a contiguous non-empty sequence of elements within an\n * array.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [3, -2, 1, 4], l = 2, r = 3\n * \n * Output: 1\n * \n * Explanation:\n * \n * The subarrays of length between l = 2 and r = 3 where the sum is greater\n * than 0 are:\n * \n * \n * [3, -2] with a sum of 1\n * [1, 4] with a sum of 5\n * [3, -2, 1] with a sum of 2\n * [-2, 1, 4] with a sum of 3\n * \n * \n * Out of these, the subarray [3, -2] has a sum of 1, which is the smallest\n * positive sum. Hence, the answer is 1.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [-2, 2, -3, 1], l = 2, r = 3\n * \n * Output: -1\n * \n * Explanation:\n * \n * There is no subarray of length between l and r that has a sum greater than\n * 0. So, the answer is -1.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [1, 2, 3, 4], l = 2, r = 4\n * \n * Output: 3\n * \n * Explanation:\n * \n * The subarray [1, 2] has a length of 2 and the minimum sum greater than 0.\n * So, the answer is 3.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 1 <= l <= r <= nums.length\n * -1000 <= nums[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minimumSumSubarray(vector<int>& nums, int l, int r) {\n        int res = INT_MAX;\n        for(int i=0; i<nums.size(); i++) {\n            int cur = 0;\n            for(int j=i; j<nums.size(); j++) {\n                cur += nums[j];\n                if(j-i+1 > r) break;\n                if(j-i+1 >= l && cur > 0) {\n                    res = min(res, cur);\n                }\n            }\n        }\n        return res == INT_MAX ? -1 : res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/1877.minimize-maximum-pair-sum-in-array.cpp","id":1877,"qid":"1877","title":"Minimize Maximum Pair Sum In Array","kebab":"minimize-maximum-pair-sum-in-array","rating":1301.4,"ratingLabel":"1301.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/1877.minimize-maximum-pair-sum-in-array.cpp","leetcodeUrl":"https://leetcode.com/problems/minimize-maximum-pair-sum-in-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/1877.minimize-maximum-pair-sum-in-array.cpp","code":"class Solution {\npublic:\n    int minPairSum(vector<int>& nums) {\n        sort(nums.begin(), nums.end());\n        int n = nums.size(), res = nums[0] + nums[n-1];\n        for(int i=0; i<n/2; i++) {\n            res = max(res, nums[i] + nums[n-i-1]);\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3602.hexadecimal-and-hexatrigesimal-conversion.cpp","id":3602,"qid":"3602","title":"Hexadecimal And Hexatrigesimal Conversion","kebab":"hexadecimal-and-hexatrigesimal-conversion","rating":1305.3,"ratingLabel":"1305.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3602.hexadecimal-and-hexatrigesimal-conversion.cpp","leetcodeUrl":"https://leetcode.com/problems/hexadecimal-and-hexatrigesimal-conversion/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3602.hexadecimal-and-hexatrigesimal-conversion.cpp","code":"/*\n * @lc app=leetcode id=3602 lang=cpp\n *\n * [3602] Hexadecimal and Hexatrigesimal Conversion\n *\n * https://leetcode.com/problems/hexadecimal-and-hexatrigesimal-conversion/description/\n *\n * Difficulty: algorithms\n * Category: Easy\n *\n * You are given an integer n.\n * \n * Return the concatenation of the hexadecimal representation of n^2 and the\n * hexatrigesimal representation of n^3.\n * \n * A hexadecimal number is defined as a base-16 numeral system that uses the\n * digits 0 \u2013 9 and the uppercase letters A - F to represent values from 0 to\n * 15.\n * \n * A hexatrigesimal number is defined as a base-36 numeral system that uses the\n * digits 0 \u2013 9 and the uppercase letters A - Z to represent values from 0 to\n * 35.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 13\n * \n * Output: \"A91P1\"\n * \n * Explanation:\n * \n * \n * n^2 = 13 * 13 = 169. In hexadecimal, it converts to (10 * 16) + 9 = 169,\n * which corresponds to \"A9\".\n * n^3 = 13 * 13 * 13 = 2197. In hexatrigesimal, it converts to (1 * 36^2) +\n * (25 * 36) + 1 = 2197, which corresponds to \"1P1\".\n * Concatenating both results gives \"A9\" + \"1P1\" = \"A91P1\".\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 36\n * \n * Output: \"5101000\"\n * \n * Explanation:\n * \n * \n * n^2 = 36 * 36 = 1296. In hexadecimal, it converts to (5 * 16^2) + (1 * 16) +\n * 0 = 1296, which corresponds to \"510\".\n * n^3 = 36 * 36 * 36 = 46656. In hexatrigesimal, it converts to (1 * 36^3) +\n * (0 * 36^2) + (0 * 36) + 0 = 46656, which corresponds to \"1000\".\n * Concatenating both results gives \"510\" + \"1000\" = \"5101000\".\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string toBase36(int number) {\n        const char* digits = \"0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ\";\n            if (number == 0) return \"0\";\n\n            string result;\n            bool isNegative = number < 0;\n            unsigned int n = isNegative ? -number : number;\n\n            while (n > 0) {\n                result += digits[n % 36];\n                n /= 36;\n            }\n\n            if (isNegative)\n                result += '-';\n\n            reverse(result.begin(), result.end());\n            return result;\n    }\n\n    string concatHex36(int n) {\n        string hexadecimal = format(\"{:X}\", n * n);\n        string hexatrigesimal = toBase36(n * n * n);\n        return hexadecimal + hexatrigesimal;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3471.find-the-largest-almost-missing-integer.cpp","id":3471,"qid":"3471","title":"Find The Largest Almost Missing Integer","kebab":"find-the-largest-almost-missing-integer","rating":1308.2,"ratingLabel":"1308.2","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3471.find-the-largest-almost-missing-integer.cpp","leetcodeUrl":"https://leetcode.com/problems/find-the-largest-almost-missing-integer/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3471.find-the-largest-almost-missing-integer.cpp","code":"/*\n * @lc app=leetcode id=3471 lang=cpp\n *\n * [3471] Find the Largest Almost Missing Integer\n *\n * https://leetcode.com/problems/find-the-largest-almost-missing-integer/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums and an integer k.\n * \n * An integer x is almost missing from nums if x appears in exactly one\n * subarray of size k within nums.\n * \n * Return the largest almost missing integer from nums. If no such integer\n * exists, return -1.\n * A subarray is a contiguous sequence of elements within an array.\n * \n * Example 1:\n * \n * \n * Input: nums = [3,9,2,1,7], k = 3\n * \n * Output: 7\n * \n * Explanation:\n * \n * \n * 1 appears in 2 subarrays of size 3: [9, 2, 1] and [2, 1, 7].\n * 2 appears in 3 subarrays of size 3: [3, 9, 2], [9, 2, 1], [2, 1, 7].\n * 3 appears in 1 subarray of size 3: [3, 9, 2].\n * 7 appears in 1 subarray of size 3: [2, 1, 7].\n * 9 appears in 2 subarrays of size 3: [3, 9, 2], and [9, 2, 1].\n * \n * \n * We return 7 since it is the largest integer that appears in exactly one\n * subarray of size k.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [3,9,7,2,1,7], k = 4\n * \n * Output: 3\n * \n * Explanation:\n * \n * \n * 1 appears in 2 subarrays of size 4: [9, 7, 2, 1], [7, 2, 1, 7].\n * 2 appears in 3 subarrays of size 4: [3, 9, 7, 2], [9, 7, 2, 1], [7, 2, 1,\n * 7].\n * 3 appears in 1 subarray of size 4: [3, 9, 7, 2].\n * 7 appears in 3 subarrays of size 4: [3, 9, 7, 2], [9, 7, 2, 1], [7, 2, 1,\n * 7].\n * 9 appears in 2 subarrays of size 4: [3, 9, 7, 2], [9, 7, 2, 1].\n * \n * \n * We return 3 since it is the largest and only integer that appears in exactly\n * one subarray of size k.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [0,0], k = 1\n * \n * Output: -1\n * \n * Explanation:\n * \n * There is no integer that appears in only one subarray of size 1.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 50\n * 0 <= nums[i] <= 50\n * 1 <= k <= nums.length\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int largestInteger(vector<int>& nums, int k) {\n        unordered_map<int, int> count;\n\n        for(int i=0; i<nums.size(); i++) {\n            if(i + k - 1 >= nums.size()) break;\n            set<int> temp;\n            for(int j=i; j<i+k; j++) {\n                // count[nums[j]]++;\n                temp.insert(nums[j]);\n            }\n            for(auto& num : temp) {\n                count[num]++;\n            }\n        }\n        \n        int res = -1;\n        for(auto& [num, cnt] : count) {\n            if(cnt == 1) {\n                res = max(res, num);\n            }\n        }\n\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3582.generate-tag-for-video-caption.cpp","id":3582,"qid":"3582","title":"Generate Tag For Video Caption","kebab":"generate-tag-for-video-caption","rating":1316.6,"ratingLabel":"1316.6","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3582.generate-tag-for-video-caption.cpp","leetcodeUrl":"https://leetcode.com/problems/generate-tag-for-video-caption/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3582.generate-tag-for-video-caption.cpp","code":"/*\n * @lc app=leetcode id=3582 lang=cpp\n *\n * [3582] Generate Tag for Video Caption\n *\n * https://leetcode.com/problems/generate-tag-for-video-caption/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string caption representing the caption for a video.\n * \n * The following actions must be performed in order to generate a valid tag for\n * the video:\n * \n * \n * \n * Combine all words in the string into a single camelCase string prefixed with\n * '#'. A camelCase string is one where the first letter of all words except\n * the first one is capitalized. All characters after the first character in\n * each word must be lowercase.\n * \n * \n * Remove all characters that are not an English letter, except the first\n * '#'.\n * \n * \n * Truncate the result to a maximum of 100 characters.\n * \n * \n * \n * Return the tag after performing the actions on caption.\n * \n * \n * Example 1:\n * \n * \n * Input: caption = \"Leetcode daily streak achieved\"\n * \n * Output: \"#leetcodeDailyStreakAchieved\"\n * \n * Explanation:\n * \n * The first letter for all words except \"leetcode\" should be capitalized.\n * \n * \n * Example 2:\n * \n * \n * Input: caption = \"can I Go There\"\n * \n * Output: \"#canIGoThere\"\n * \n * Explanation:\n * \n * The first letter for all words except \"can\" should be capitalized.\n * \n * \n * Example 3:\n * \n * \n * Input: caption =\n * \"hhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhh\"\n * \n * Output:\n * \"#hhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhh\"\n * \n * Explanation:\n * \n * Since the first word has length 101, we need to truncate the last two\n * letters from the word.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= caption.length <= 150\n * caption consists only of English letters and ' '.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string generateTag(string caption) {\n        string res = \"#\";\n        for(int i=0; i<caption.length(); i++) {\n            if(i == 0 && caption[i] == ' ') {\n                while(i < caption.length() && caption[i] == ' ')\n                    i++;\n            }\n            if(caption[i] == ' ' && i+1 < caption.length() && caption[i+1] != ' ') {\n                res += toupper(caption[i+1]);\n                i++;\n            }\n            else if(caption[i] >= 'a' && caption[i] <= 'z') {\n                res += caption[i];\n            }\n            else if(caption[i] >= 'A' && caption[i] <= 'Z') {\n                res += tolower(caption[i]);\n            }\n\n            if(res.length() >= 100) return res;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3483.unique-3-digit-even-numbers.cpp","id":3483,"qid":"3483","title":"Unique 3 Digit Even Numbers","kebab":"unique-3-digit-even-numbers","rating":1323.6,"ratingLabel":"1323.6","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3483.unique-3-digit-even-numbers.cpp","leetcodeUrl":"https://leetcode.com/problems/unique-3-digit-even-numbers/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3483.unique-3-digit-even-numbers.cpp","code":"/*\n * @lc app=leetcode id=3483 lang=cpp\n *\n * [3483] Unique 3-Digit Even Numbers\n *\n * https://leetcode.com/problems/unique-3-digit-even-numbers/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an array of digits called digits. Your task is to determine\n * the number of distinct three-digit even numbers that can be formed using\n * these digits.\n * \n * Note: Each copy of a digit can only be used once per number, and there may\n * not be leading zeros.\n * \n * \n * Example 1:\n * \n * \n * Input: digits = [1,2,3,4]\n * \n * Output: 12\n * \n * Explanation: The 12 distinct 3-digit even numbers that can be formed are\n * 124, 132, 134, 142, 214, 234, 312, 314, 324, 342, 412, and 432. Note that\n * 222 cannot be formed because there is only 1 copy of the digit 2.\n * \n * \n * Example 2:\n * \n * \n * Input: digits = [0,2,2]\n * \n * Output: 2\n * \n * Explanation: The only 3-digit even numbers that can be formed are 202 and\n * 220. Note that the digit 2 can be used twice because it appears twice in the\n * array.\n * \n * \n * Example 3:\n * \n * \n * Input: digits = [6,6,6]\n * \n * Output: 1\n * \n * Explanation: Only 666 can be formed.\n * \n * \n * Example 4:\n * \n * \n * Input: digits = [1,3,5]\n * \n * Output: 0\n * \n * Explanation: No even 3-digit numbers can be formed.\n * \n * \n * \n * Constraints:\n * \n * \n * 3 <= digits.length <= 10\n * 0 <= digits[i] <= 9\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int totalNumbers(vector<int>& digits) {\n        set<int> s;\n        for(int i=0; i<digits.size(); i++) {\n            for(int j=0; j<digits.size(); j++) {\n                if(i == j) continue;\n                for(int k=0; k<digits.size(); k++) {\n                    if(i == k || j == k) continue;\n                    int num = digits[i] * 100 + digits[j] * 10 + digits[k];\n                    if(num >= 100 && num % 2 == 0) {\n                        s.insert(num);\n                    }\n                }\n            }\n        }\n        return s.size();\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3560.find-minimum-log-transportation-cost.cpp","id":3560,"qid":"3560","title":"Find Minimum Log Transportation Cost","kebab":"find-minimum-log-transportation-cost","rating":1339.2,"ratingLabel":"1339.2","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3560.find-minimum-log-transportation-cost.cpp","leetcodeUrl":"https://leetcode.com/problems/find-minimum-log-transportation-cost/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3560.find-minimum-log-transportation-cost.cpp","code":"/*\n * @lc app=leetcode id=3560 lang=cpp\n *\n * [3560] Find Minimum Log Transportation Cost\n *\n * https://leetcode.com/problems/find-minimum-log-transportation-cost/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given integers n, m, and k.\n * \n * There are two logs of lengths n and m units, which need to be transported in\n * three trucks where each truck can carry one log with length at most k\n * units.\n * \n * You may cut the logs into smaller pieces, where the cost of cutting a log of\n * length x into logs of length len1 and len2 is cost = len1 * len2 such that\n * len1 + len2 = x.\n * \n * Return the minimum total cost to distribute the logs onto the trucks. If the\n * logs don't need to be cut, the total cost is 0.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 6, m = 5, k = 5\n * \n * Output: 5\n * \n * Explanation:\n * \n * Cut the log with length 6 into logs with length 1 and 5, at a cost equal to\n * 1 * 5 == 5. Now the three logs of length 1, 5, and 5 can fit in one truck\n * each.\n * \n * \n * Example 2:\n * \n * \n * Input: n = 4, m = 4, k = 6\n * \n * Output: 0\n * \n * Explanation:\n * \n * The two logs can fit in the trucks already, hence we don't need to cut the\n * logs.\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= k <= 10^5\n * 1 <= n, m <= 2 * k\n * The input is generated such that it is always possible to transport the\n * logs.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    long long minCuttingCost(int n, int m, int k) {\n        long long res = 0;\n        if(n > k) {\n            long long a = n - k;\n            long long b = k;\n            res += a * b;\n        }\n        if(m > k) {\n            long long a = m - k;\n            long long b = k;\n            res += a * b;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/784.letter-case-permutation.cpp","id":784,"qid":"784","title":"Letter Case Permutation","kebab":"letter-case-permutation","rating":1341.5,"ratingLabel":"1341.5","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/784.letter-case-permutation.cpp","leetcodeUrl":"https://leetcode.com/problems/letter-case-permutation/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/784.letter-case-permutation.cpp","code":"// # **Key Idea**\n\n// This is a **backtracking / DFS (Depth-First Search)** problem.\n// For each character in the string:\n\n// * If it's a **letter**, we branch into **two recursive calls**: one for lowercase, one for uppercase.\n// * If it's a **digit**, we only continue with the current character (no branching).\n\n// This way, we explore all combinations of letter case transformations.\n\n// ---\n\n// # **Algorithm**\n\n// 1. Start from index `0` and an empty string `cur`.\n// 2. If we reach the end of the string (`i == s.length()`), we add the current combination `cur` to the result list.\n// 3. Otherwise:\n\n//    * If `s[i]` is a letter:\n\n//      * Add its lowercase form to `cur`, recurse to the next index.\n//      * Change that character to uppercase, recurse again.\n//      * Backtrack by removing the character.\n//    * If `s[i]` is a digit:\n\n//      * Just add the digit to `cur` and recurse once.\n// 4. Return the result list after all recursive calls finish.\n\n// ---\n\n// # **Complexity Analysis**\n\n// * **Time Complexity**:\n//   ( O(2^L) ), where ( L ) is the number of letters. Each letter doubles the number of combinations.\n// * **Space Complexity**:\n//   ( O(L) ) for the recursion stack and current string. The result array holds ( 2^L ) strings.\n\n// ---\n\n// # Code\n// ```cpp []\nclass Solution {\npublic:\n    void dfs(vector<string>& res, string &s, int i, string &cur) {\n        if(i == s.length()) {\n            res.push_back(cur);\n            return;\n        }\n\n        int a = s[i] - 'a', A = s[i] - 'A';\n        if(A >= 0 && A < 26) s[i] = A + 'a', a = A;\n\n        cur.push_back(s[i]);\n        dfs(res, s, i+1, cur);\n        cur.pop_back();\n        \n        if(a >= 0 && a < 26) {\n            cur.push_back(a + 'A');\n            dfs(res, s, i+1, cur);\n            cur.pop_back();\n        }\n    }\n    vector<string> letterCasePermutation(string s) {\n        vector<string> res;\n        string cur = \"\";\n        dfs(res, s, 0, cur);\n        return res;\n    }\n};\n// ```\n"},{"key":"problem:problems/1200-1399-pupil/3633.earliest-finish-time-for-land-and-water-rides-i.cpp","id":3633,"qid":"3633","title":"Earliest Finish Time For Land And Water Rides I","kebab":"earliest-finish-time-for-land-and-water-rides-i","rating":1342.7,"ratingLabel":"1342.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3633.earliest-finish-time-for-land-and-water-rides-i.cpp","leetcodeUrl":"https://leetcode.com/problems/earliest-finish-time-for-land-and-water-rides-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3633.earliest-finish-time-for-land-and-water-rides-i.cpp","code":"class Solution {\npublic:\n    int earliestFinishTime(vector<int>& landStartTime, vector<int>& landDuration, vector<int>& waterStartTime, vector<int>& waterDuration) {\n        int res = INT_MAX;\n\n        int m = landStartTime.size();\n        int n = waterStartTime.size();\n\n        for(int i=0; i<m; i++) {\n            int land = landStartTime[i] + landDuration[i];\n            for(int j=0; j<n; j++) {\n                if(land <= waterStartTime[j]) {\n                    res = min(res, waterStartTime[j] + waterDuration[j]);\n                }\n                else {\n                    res = min(res, land + waterDuration[j]);\n                }\n            }\n        }\n\n        for(int j=0; j<n; j++) {\n            int water = waterStartTime[j] + waterDuration[j];\n            for(int i=0; i<m; i++) {\n                if(water <= landStartTime[i]) {\n                    res = min(res, landStartTime[i] + landDuration[i]);\n                }\n                else {\n                    res = min(res, water + landDuration[i]);\n                }\n            }\n        }\n\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3507.minimum-pair-removal-to-sort-array-i.cpp","id":3507,"qid":"3507","title":"Minimum Pair Removal To Sort Array I","kebab":"minimum-pair-removal-to-sort-array-i","rating":1348.7,"ratingLabel":"1348.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3507.minimum-pair-removal-to-sort-array-i.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-pair-removal-to-sort-array-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3507.minimum-pair-removal-to-sort-array-i.cpp","code":"/*\n * @lc app=leetcode id=3507 lang=cpp\n *\n * [3507] Minimum Pair Removal to Sort Array I\n *\n * https://leetcode.com/problems/minimum-pair-removal-to-sort-array-i/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * Given an array nums, you can perform the following operation any number of\n * times:\n * \n * \n * Select the adjacent pair with the minimum sum in nums. If multiple such\n * pairs exist, choose the leftmost one.\n * Replace the pair with their sum.\n * \n * \n * Return the minimum number of operations needed to make the array\n * non-decreasing.\n * \n * An array is said to be non-decreasing if each element is greater than or\n * equal to its previous element (if it exists).\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [5,2,3,1]\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * The pair (3,1) has the minimum sum of 4. After replacement, nums =\n * [5,2,4].\n * The pair (2,4) has the minimum sum of 6. After replacement, nums = [5,6].\n * \n * \n * The array nums became non-decreasing in two operations.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,2,2]\n * \n * Output: 0\n * \n * Explanation:\n * \n * The array nums is already sorted.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 50\n * -1000 <= nums[i] <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minimumPairRemoval(vector<int>& nums) {\n        int op = 0, inc = 0, mn, add, i;\n\n        while(!inc) {\n            vector<int> temp;\n            inc = 1;\n            mn = INT_MAX;\n\n            for(i=0; i+1<nums.size(); i++) {\n                if(nums[i] > nums[i+1]) inc = 0;\n                mn = min(mn, nums[i] + nums[i+1]);\n            }\n            if(inc == 1) break;\n\n            add = 0;\n            for(i=0; i+1<nums.size() && !add; i++) {\n                if(nums[i] + nums[i+1] == mn) {\n                    temp.push_back(mn);\n                    i++;\n                    add = 1;\n                }\n                else temp.push_back(nums[i]);\n            }\n            while(i < nums.size()) {\n                temp.push_back(nums[i]);\n                i++;\n            }\n            // cout << nums.size() << ' ' << temp.size() << endl;\n            nums = temp;\n            op++;\n        }\n        return op;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/746.min-cost-climbing-stairs.cpp","id":746,"qid":"746","title":"Min Cost Climbing Stairs","kebab":"min-cost-climbing-stairs","rating":1358.4,"ratingLabel":"1358.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/746.min-cost-climbing-stairs.cpp","leetcodeUrl":"https://leetcode.com/problems/min-cost-climbing-stairs/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/746.min-cost-climbing-stairs.cpp","code":"class Solution {\npublic:\n    int minCostClimbingStairs(vector<int>& cost) {\n        int a = cost[0], b = cost[1];\n\n        for(int i=2, t; i<cost.size(); i++) {\n            t = min(a, b) + cost[i];\n            a = b;\n            b = t;\n        }\n\n        return min(a, b);\n\n        // int n = cost.size();\n        // vector<int> arr(n+1, INT_MAX);\n\n        // arr[0] = arr[1] = 0;\n\n        // for(int i=2; i<=n; i++) {\n        //     arr[i] = min(arr[i-1]+cost[i-1], arr[i-2]+cost[i-2]);\n        // }\n\n        // return arr[n];\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3100.water-bottles-ii.cpp","id":3100,"qid":"3100","title":"Water Bottles II","kebab":"water-bottles-ii","rating":1366.3,"ratingLabel":"1366.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3100.water-bottles-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/water-bottles-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3100.water-bottles-ii.cpp","code":"class Solution {\npublic:\n    int maxBottlesDrunk(int A, int B) {\n        int res = A;\n        while(A >= B) {\n            res ++;\n            A -= B-1;\n            B++;\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3674.minimum-operations-to-equalize-array.cpp","id":3674,"qid":"3674","title":"Minimum Operations To Equalize Array","kebab":"minimum-operations-to-equalize-array","rating":1369.1,"ratingLabel":"1369.1","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3674.minimum-operations-to-equalize-array.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-operations-to-equalize-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3674.minimum-operations-to-equalize-array.cpp","code":"class Solution {\npublic:\n    int minOperations(vector<int>& nums) {\n        sort(nums.begin(), nums.end());\n        return nums[0] == nums.back() ? 0 : 1;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3446.sort-matrix-by-diagonals.cpp","id":3446,"qid":"3446","title":"Sort Matrix By Diagonals","kebab":"sort-matrix-by-diagonals","rating":1372.8,"ratingLabel":"1372.8","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3446.sort-matrix-by-diagonals.cpp","leetcodeUrl":"https://leetcode.com/problems/sort-matrix-by-diagonals/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3446.sort-matrix-by-diagonals.cpp","code":"class Solution {\npublic:\n    vector<vector<int>> sortMatrix(vector<vector<int>>& g) {\n        int n = g.size();\n\n        vector<vector<int>> vt(n);\n        for(int i=0; i<n; i++) {\n            for(int j=0; j<=i; j++) {\n                vt[i-j].push_back(g[i][j]);\n            }\n        }\n        for(int i=0; i<n; i++) sort(vt[i].rbegin(), vt[i].rend());\n        for(int i=0; i<n; i++) {\n            for(int j=0; j<=i; j++) {\n                g[i][j] = vt[i-j][j];\n            }\n        }\n\n        vector<vector<int>> vt2(n+1);\n        for(int j=1; j<n; j++) {\n            for(int i=0; i<j; i++) {\n                vt2[j-i].push_back(g[i][j]);\n            }\n        }\n        for(int j=1; j<=n; j++) sort(vt2[j].begin(), vt2[j].end());\n        for(int j=1; j<n; j++) {\n            for(int i=0; i<j; i++) {\n                g[i][j] = vt2[j-i][i];\n            }\n        }\n\n        return g;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3314.construct-the-minimum-bitwise-array-i.cpp","id":3314,"qid":"3314","title":"Construct The Minimum Bitwise Array I","kebab":"construct-the-minimum-bitwise-array-i","rating":1378.7,"ratingLabel":"1378.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3314.construct-the-minimum-bitwise-array-i.cpp","leetcodeUrl":"https://leetcode.com/problems/construct-the-minimum-bitwise-array-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3314.construct-the-minimum-bitwise-array-i.cpp","code":"/*\n * @lc app=leetcode id=3314 lang=cpp\n *\n * [3314] Construct the Minimum Bitwise Array I\n *\n * https://leetcode.com/problems/construct-the-minimum-bitwise-array-i/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an array nums consisting of n prime integers.\n * \n * You need to construct an array ans of length n, such that, for each index i,\n * the bitwise OR of ans[i] and ans[i] + 1 is equal to nums[i], i.e. ans[i] OR\n * (ans[i] + 1) == nums[i].\n * \n * Additionally, you must minimize each value of ans[i] in the resulting\n * array.\n * \n * If it is not possible to find such a value for ans[i] that satisfies the\n * condition, then set ans[i] = -1.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [2,3,5,7]\n * \n * Output: [-1,1,4,3]\n * \n * Explanation:\n * \n * \n * For i = 0, as there is no value for ans[0] that satisfies ans[0] OR (ans[0]\n * + 1) = 2, so ans[0] = -1.\n * For i = 1, the smallest ans[1] that satisfies ans[1] OR (ans[1] + 1) = 3 is\n * 1, because 1 OR (1 + 1) = 3.\n * For i = 2, the smallest ans[2] that satisfies ans[2] OR (ans[2] + 1) = 5 is\n * 4, because 4 OR (4 + 1) = 5.\n * For i = 3, the smallest ans[3] that satisfies ans[3] OR (ans[3] + 1) = 7 is\n * 3, because 3 OR (3 + 1) = 7.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [11,13,31]\n * \n * Output: [9,12,15]\n * \n * Explanation:\n * \n * \n * For i = 0, the smallest ans[0] that satisfies ans[0] OR (ans[0] + 1) = 11 is\n * 9, because 9 OR (9 + 1) = 11.\n * For i = 1, the smallest ans[1] that satisfies ans[1] OR (ans[1] + 1) = 13 is\n * 12, because 12 OR (12 + 1) = 13.\n * For i = 2, the smallest ans[2] that satisfies ans[2] OR (ans[2] + 1) = 31 is\n * 15, because 15 OR (15 + 1) = 31.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 2 <= nums[i] <= 1000\n * nums[i] is a prime number.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> minBitwiseArray(vector<int>& nums) {\n        vector<int> ans(nums.size(), -1);\n        for (int i = 0; i < nums.size(); i++) {\n            for (int j = 0; j < nums[i]; j++) {\n                if( (j | (j + 1)) == nums[i]) {\n                    ans[i] = j;\n                    break;\n                }\n            }\n        }\n        return ans;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/1185.day-of-the-week.cpp","id":1185,"qid":"1185","title":"Day Of The Week","kebab":"day-of-the-week","rating":1382.5,"ratingLabel":"1382.5","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/1185.day-of-the-week.cpp","leetcodeUrl":"https://leetcode.com/problems/day-of-the-week/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/1185.day-of-the-week.cpp","code":"/*\n * @lc app=leetcode id=1185 lang=cpp\n *\n * [1185] Day of the Week\n *\n * https://leetcode.com/problems/day-of-the-week/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n * \n * Given a date, return the corresponding day of the week for that date.\n * \n * The input is given as three integers representing the day, month and year\n * respectively.\n * \n * Return the answer as one of the following values\u00a0{\"Sunday\", \"Monday\",\n * \"Tuesday\", \"Wednesday\", \"Thursday\", \"Friday\", \"Saturday\"}.\n * \n * \n * Example 1:\n * \n * \n * Input: day = 31, month = 8, year = 2019\n * Output: \"Saturday\"\n * \n * \n * Example 2:\n * \n * \n * Input: day = 18, month = 7, year = 1999\n * Output: \"Sunday\"\n * \n * \n * Example 3:\n * \n * \n * Input: day = 15, month = 8, year = 1993\n * Output: \"Sunday\"\n * \n * \n * \n * Constraints:\n * \n * \n * The given dates are valid dates between the years 1971 and 2100.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string dayOfTheWeek(int day, int month, int year) {\n        if (month <= 2) {\n            month += 12;\n            year -= 1;\n        }\n        int K = year % 100; \n        int J = year / 100;\n        int h = (day + (13 * (month + 1)) / 5 + K + K/4 + J/4 + 5*J) % 7;\n        int w = (h + 6) % 7;\n\n        vector<string> names = {\n            \"Sunday\",\"Monday\",\"Tuesday\",\"Wednesday\",\"Thursday\",\"Friday\",\"Saturday\"\n        };\n        return names[w];\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3375.minimum-operations-to-make-array-values-equal-to-k.cpp","id":3375,"qid":"3375","title":"Minimum Operations To Make Array Values Equal To K","kebab":"minimum-operations-to-make-array-values-equal-to-k","rating":1382.8,"ratingLabel":"1382.8","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3375.minimum-operations-to-make-array-values-equal-to-k.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-operations-to-make-array-values-equal-to-k/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3375.minimum-operations-to-make-array-values-equal-to-k.cpp","code":"/*\n * @lc app=leetcode id=3375 lang=cpp\n *\n * [3375] Minimum Operations to Make Array Values Equal to K\n *\n * https://leetcode.com/problems/minimum-operations-to-make-array-values-equal-to-k/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums and an integer k.\n * \n * An integer h is called valid if all values in the array that are strictly\n * greater than h are identical.\n * \n * For example, if nums = [10, 8, 10, 8], a valid integer is h = 9 because all\n * nums[i] > 9\u00a0are equal to 10, but 5 is not a valid integer.\n * \n * You are allowed to perform the following operation on nums:\n * \n * \n * Select an integer h that is valid for the current values in nums.\n * For each index i where nums[i] > h, set nums[i] to h.\n * \n * \n * Return the minimum number of operations required to make every element in\n * nums equal to k. If it is impossible to make all elements equal to k, return\n * -1.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [5,2,5,4,5], k = 2\n * \n * Output: 2\n * \n * Explanation:\n * \n * The operations can be performed in order using valid integers 4 and then\n * 2.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,1,2], k = 2\n * \n * Output: -1\n * \n * Explanation:\n * \n * It is impossible to make all the values equal to 2.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [9,7,5,3], k = 1\n * \n * Output: 4\n * \n * Explanation:\n * \n * The operations can be performed using valid integers in the order 7, 5, 3,\n * and 1.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100 \n * 1 <= nums[i] <= 100\n * 1 <= k <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minOperations(vector<int>& nums, int k) {\n        sort(nums.begin(), nums.end());\n        if(nums[0] < k) return -1;\n        int op = 0;\n        for(int i=0; i<nums.size(); i++) {\n            if(nums[i] > k) {\n                op++;\n            }\n            while(i+1 < nums.size() && nums[i] == nums[i+1]) i++;\n        }\n        return op;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1200-1399-pupil/3354.make-array-elements-equal-to-zero.cpp","id":3354,"qid":"3354","title":"Make Array Elements Equal To Zero","kebab":"make-array-elements-equal-to-zero","rating":1397.3,"ratingLabel":"1397.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3354.make-array-elements-equal-to-zero.cpp","leetcodeUrl":"https://leetcode.com/problems/make-array-elements-equal-to-zero/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3354.make-array-elements-equal-to-zero.cpp","code":"class Solution {\npublic:\n    int countValidSelections(vector<int>& nums) {\n        int sum = 0, temp = 0, res = 0;\n\n        for(auto & i : nums) sum += i;\n        \n        for(auto & i : nums) {\n            if(i == 0 && temp == sum - temp) res += 2;\n            else if(i == 0 && abs(sum - temp - temp) == 1) res ++;\n            temp += i;\n        }\n\n        return res;\n    }\n};\n"},{"key":"problem:problems/1200-1399-pupil/3487.maximum-unique-subarray-sum-after-deletion.cpp","id":3487,"qid":"3487","title":"Maximum Unique Subarray Sum After Deletion","kebab":"maximum-unique-subarray-sum-after-deletion","rating":1399.3,"ratingLabel":"1399.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"problems/1200-1399-pupil/3487.maximum-unique-subarray-sum-after-deletion.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-unique-subarray-sum-after-deletion/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1200-1399-pupil/3487.maximum-unique-subarray-sum-after-deletion.cpp","code":"/*\n * @lc app=leetcode id=3487 lang=cpp\n *\n * [3487] Maximum Unique Subarray Sum After Deletion\n *\n * https://leetcode.com/problems/maximum-unique-subarray-sum-after-deletion/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given an integer array nums.\n * \n * You are allowed to delete any number of elements from nums without making it\n * empty. After performing the deletions, select a subarray of nums such\n * that:\n * \n * \n * All elements in the subarray are unique.\n * The sum of the elements in the subarray is maximized.\n * \n * \n * Return the maximum sum of such a subarray.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,3,4,5]\n * \n * Output: 15\n * \n * Explanation:\n * \n * Select the entire array without deleting any element to obtain the maximum\n * sum.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [1,1,0,1,1]\n * \n * Output: 1\n * \n * Explanation:\n * \n * Delete the element nums[0] == 1, nums[1] == 1, nums[2] == 0, and nums[3] ==\n * 1. Select the entire array [1] to obtain the maximum sum.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [1,2,-1,-2,1,0,-1]\n * \n * Output: 3\n * \n * Explanation:\n * \n * Delete the elements nums[2] == -1 and nums[3] == -2, and select the subarray\n * [2, 1] from [1, 2, 1, 0, -1] to obtain the maximum sum.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * -100 <= nums[i] <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxSum(vector<int>& nums) {\n        sort(nums.begin(), nums.end());\n        int res = nums[0];\n        for(int i=0; i<nums.size(); i++) {\n            if(nums[i] < 0) {\n                res = max(res, nums[i]);\n                continue;\n            }\n\n            int sum = 0;\n            set<int> s;\n            while(i < nums.size()) {\n                if(!s.count(nums[i])) {\n                    s.insert(nums[i]);\n                    sum += nums[i];\n                }\n                i++;\n            }\n            res = max(res, sum);\n            break;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1261.find-elements-in-a-contaminated-binary-tree.cpp","id":1261,"qid":"1261","title":"Find Elements In A Contaminated Binary Tree","kebab":"find-elements-in-a-contaminated-binary-tree","rating":1439.6,"ratingLabel":"1439.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1261.find-elements-in-a-contaminated-binary-tree.cpp","leetcodeUrl":"https://leetcode.com/problems/find-elements-in-a-contaminated-binary-tree/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1261.find-elements-in-a-contaminated-binary-tree.cpp","code":"/*\n * @lc app=leetcode id=1261 lang=cpp\n *\n * [1261] Find Elements in a Contaminated Binary Tree\n *\n * https://leetcode.com/problems/find-elements-in-a-contaminated-binary-tree/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n * \n * Given a binary tree with the following rules:\n * \n * \n * root.val == 0\n * For any treeNode:\n * \n * If treeNode.val has a value x and treeNode.left != null, then\n * treeNode.left.val == 2 * x + 1\n * If treeNode.val has a value x and treeNode.right != null, then\n * treeNode.right.val == 2 * x + 2\n * \n * \n * \n * \n * Now the binary tree is contaminated, which means all treeNode.val have been\n * changed to -1.\n * \n * Implement the FindElements class:\n * \n * \n * FindElements(TreeNode* root) Initializes the object with a contaminated\n * binary tree and recovers it.\n * bool find(int target) Returns true if the target value exists in the\n * recovered binary tree.\n * \n * \n * \n * Example 1:\n * \n * \n * Input\n * [\"FindElements\",\"find\",\"find\"]\n * [[[-1,null,-1]],[1],[2]]\n * Output\n * [null,false,true]\n * Explanation\n * FindElements findElements = new FindElements([-1,null,-1]); \n * findElements.find(1); // return False \n * findElements.find(2); // return True \n * \n * Example 2:\n * \n * \n * Input\n * [\"FindElements\",\"find\",\"find\",\"find\"]\n * [[[-1,-1,-1,-1,-1]],[1],[3],[5]]\n * Output\n * [null,true,true,false]\n * Explanation\n * FindElements findElements = new FindElements([-1,-1,-1,-1,-1]);\n * findElements.find(1); // return True\n * findElements.find(3); // return True\n * findElements.find(5); // return False\n * \n * Example 3:\n * \n * \n * Input\n * [\"FindElements\",\"find\",\"find\",\"find\",\"find\"]\n * [[[-1,null,-1,-1,null,-1]],[2],[3],[4],[5]]\n * Output\n * [null,true,false,false,true]\n * Explanation\n * FindElements findElements = new FindElements([-1,null,-1,-1,null,-1]);\n * findElements.find(2); // return True\n * findElements.find(3); // return False\n * findElements.find(4); // return False\n * findElements.find(5); // return True\n * \n * \n * \n * Constraints:\n * \n * \n * TreeNode.val == -1\n * The height of the binary tree is less than or equal to 20\n * The total number of nodes is between [1, 10^4]\n * Total calls of find() is between [1, 10^4]\n * 0 <= target <= 10^6\n * \n * \n */\n\n// @lc code=start\n/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n * };\n */\nclass FindElements {\npublic:\n    set<int> s;\n\n    void recover(TreeNode* root, int val) {\n        if (!root) return;\n\n        root->val = val;\n        s.insert(val);\n\n        recover(root->left, 2 * val + 1);\n        recover(root->right, 2 * val + 2);\n    }\n\n    FindElements(TreeNode* root) {\n        if(!root) return;\n        root->val = 0;\n        recover(root, 0);\n    }\n    \n    bool find(int target) {\n        return s.count(target);\n    }\n};\n\n/**\n * Your FindElements object will be instantiated and called as such:\n * FindElements* obj = new FindElements(root);\n * bool param_1 = obj->find(target);\n */\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/3411.maximum-subarray-with-equal-products.cpp","id":3411,"qid":"3411","title":"Maximum Subarray With Equal Products","kebab":"maximum-subarray-with-equal-products","rating":1443.2,"ratingLabel":"1443.2","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/3411.maximum-subarray-with-equal-products.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-subarray-with-equal-products/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/3411.maximum-subarray-with-equal-products.cpp","code":"/*\n * @lc app=leetcode id=3411 lang=cpp\n *\n * [3411] Maximum Subarray With Equal Products\n *\n * https://leetcode.com/problems/maximum-subarray-with-equal-products/description/\n *\n * CategoryL algorithms\n * Difficulty: Easy\n *\n * You are given an array of positive integers nums.\n * \n * An array arr is called product equivalent if prod(arr) == lcm(arr) *\n * gcd(arr), where:\n * \n * \n * prod(arr) is the product of all elements of arr.\n * gcd(arr) is the GCD of all elements of arr.\n * lcm(arr) is the LCM of all elements of arr.\n * \n * \n * Return the length of the longest product equivalent subarray of nums.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,1,2,1,1,1]\n * \n * Output: 5\n * \n * Explanation:\u00a0\n * \n * The longest product equivalent subarray is [1, 2, 1, 1, 1], where\u00a0prod([1,\n * 2, 1, 1, 1]) = 2,\u00a0gcd([1, 2, 1, 1, 1]) = 1, and\u00a0lcm([1, 2, 1, 1, 1]) = 2.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,3,4,5,6]\n * \n * Output: 3\n * \n * Explanation:\u00a0\n * \n * The longest product equivalent subarray is [3, 4, 5].\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [1,2,3,1,4,5,1]\n * \n * Output: 5\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= nums.length <= 100\n * 1 <= nums[i] <= 10\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxLength(vector<int>& nums) {\n        int res = 0;\n        for(int i=0; i<nums.size(); i++) {\n            int prod_val = nums[i];\n            int gcd_val = nums[i];\n            int lcm_val = nums[i];\n\n            for(int j=i+1; j<nums.size(); j++) {\n                prod_val *= nums[j];\n                gcd_val = gcd(gcd_val, nums[j]);\n                lcm_val = lcm(lcm_val, nums[j]);\n\n                if(prod_val == lcm_val * gcd_val) {\n                    res = max(res, j-i+1);\n                }\n                else {\n                    break;\n                }\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/3634.minimum-removals-to-balance-array.cpp","id":3634,"qid":"3634","title":"Minimum Removals To Balance Array","kebab":"minimum-removals-to-balance-array","rating":1453.1,"ratingLabel":"1453.1","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/3634.minimum-removals-to-balance-array.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-removals-to-balance-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/3634.minimum-removals-to-balance-array.cpp","code":"class Solution {\npublic:\n    using ll = long long;\n    int minRemoval(vector<int>& nums, int k) {\n        sort(nums.begin(), nums.end());\n        int n = nums.size();\n\n        int res = 1;\n        int l = 0, r = 0;\n\n        for(l=0; l<n; l++) {\n            while(r < n && (ll)nums[r] <= (ll)nums[l] * k) r++;\n            res = max(res, r - l);\n        }\n        return n - res;\n    }\n};\n"},{"key":"problem:problems/1400-1599-specialist/3318.find-x-sum-of-all-k-long-subarrays-i.cpp","id":3318,"qid":"3318","title":"Find X Sum Of All K Long Subarrays I","kebab":"find-x-sum-of-all-k-long-subarrays-i","rating":1457.5,"ratingLabel":"1457.5","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/3318.find-x-sum-of-all-k-long-subarrays-i.cpp","leetcodeUrl":"https://leetcode.com/problems/find-x-sum-of-all-k-long-subarrays-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/3318.find-x-sum-of-all-k-long-subarrays-i.cpp","code":"# include <bits/stdc++.h>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> findXSum(vector<int>& nums, int k, int x) {\n        int n = nums.size();\n        vector<int> res;\n        for(int i=0; i+k<=n; i++) {\n            unordered_map<int, int> f;\n            for(int j=i; j<i+k; j++) f[nums[j]]++;\n            vector<pair<int, int>> v;\n            for(auto& p : f) v.push_back({p.second, p.first});\n            sort(v.begin(), v.end(), [](auto &a, auto &b){\n                if(a.first != b.first) return a.first > b.first;\n                return a.second > b.second;\n            });\n            int sum = 0;\n            int cnt = 0;\n            for(auto& p : v) {\n                if(cnt++ == x) break;\n                sum += 1LL * p.first * p.second;\n            }\n            res.push_back(sum);\n        }\n        return res;\n\n    }\n};\n"},{"key":"problem:problems/1400-1599-specialist/3407.substring-matching-pattern.cpp","id":3407,"qid":"3407","title":"Substring Matching Pattern","kebab":"substring-matching-pattern","rating":1472.7,"ratingLabel":"1472.7","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/3407.substring-matching-pattern.cpp","leetcodeUrl":"https://leetcode.com/problems/substring-matching-pattern/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/3407.substring-matching-pattern.cpp","code":"/*\n * @lc app=leetcode id=3407 lang=cpp\n *\n * [3407] Substring Matching Pattern\n *\n * https://leetcode.com/problems/substring-matching-pattern/description/\n *\n * Category: algorithms\n * Difficulty: Easy\n *\n * You are given a string s and a pattern string p, where p contains exactly\n * one '*' character.\n * \n * The '*' in p can be replaced with any sequence of zero or more characters.\n * \n * Return true if p can be made a substring of s, and false otherwise.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"leetcode\", p = \"ee*e\"\n * \n * Output: true\n * \n * Explanation:\n * \n * By replacing the '*' with \"tcod\", the substring \"eetcode\" matches the\n * pattern.\n * \n * \n * Example 2:\n * \n * \n * Input: s = \"car\", p = \"c*v\"\n * \n * Output: false\n * \n * Explanation:\n * \n * There is no substring matching the pattern.\n * \n * \n * Example 3:\n * \n * \n * Input: s = \"luck\", p = \"u*\"\n * \n * Output: true\n * \n * Explanation:\n * \n * The substrings \"u\", \"uc\", and \"uck\" match the pattern.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= s.length <= 50\n * 1 <= p.length <= 50 \n * s contains only lowercase English letters.\n * p contains only lowercase English letters and exactly one '*'\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool hasMatch(string s, string p) {\n        int star_pos = p.find('*');\n        string prefix = p.substr(0, star_pos);\n        string suffix = p.substr(star_pos + 1);\n        // cout << \"Prefix: \" << prefix << \", Suffix: \" << suffix << endl;\n\n        if (prefix.length() + suffix.length() > s.length()) {\n            return false;\n        }\n        \n        for (int i = 0; i <= s.length() - prefix.length() - suffix.length(); i++) {\n            if (s.substr(i, prefix.length()) != prefix) continue;\n            \n            for (int j = i + prefix.length(); j <= s.length() - suffix.length(); j++) {\n                if (s.substr(j, suffix.length()) == suffix) {\n                    return true;\n                }\n            }\n        }\n        \n        return false;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1829.maximum-xor-for-each-query.cpp","id":1829,"qid":"1829","title":"Maximum Xor For Each Query","kebab":"maximum-xor-for-each-query","rating":1523.4,"ratingLabel":"1523.4","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1829.maximum-xor-for-each-query.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-xor-for-each-query/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1829.maximum-xor-for-each-query.cpp","code":"/*\n * @lc app=leetcode id=1829 lang=cpp\n *\n * [1829] Maximum XOR for Each Query\n *\n * https://leetcode.com/problems/maximum-xor-for-each-query/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given a sorted array nums of n non-negative integers and an integer\n * maximumBit. You want to perform the following query n times:\n * \n * \n * Find a non-negative integer k < 2^maximumBit such that nums[0] XOR nums[1]\n * XOR ... XOR nums[nums.length-1] XOR k is maximized. k is the answer to the\n * i^th query.\n * Remove the last element from the current array nums.\n * \n * \n * Return an array answer, where answer[i] is the answer to the i^th query.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [0,1,1,3], maximumBit = 2\n * Output: [0,3,2,3]\n * Explanation: The queries are answered as follows:\n * 1^st query: nums = [0,1,1,3], k = 0 since 0 XOR 1 XOR 1 XOR 3 XOR 0 = 3.\n * 2^nd query: nums = [0,1,1], k = 3 since 0 XOR 1 XOR 1 XOR 3 = 3.\n * 3^rd query: nums = [0,1], k = 2 since 0 XOR 1 XOR 2 = 3.\n * 4^th query: nums = [0], k = 3 since 0 XOR 3 = 3.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,3,4,7], maximumBit = 3\n * Output: [5,2,6,5]\n * Explanation: The queries are answered as follows:\n * 1^st query: nums = [2,3,4,7], k = 5 since 2 XOR 3 XOR 4 XOR 7 XOR 5 = 7.\n * 2^nd query: nums = [2,3,4], k = 2 since 2 XOR 3 XOR 4 XOR 2 = 7.\n * 3^rd query: nums = [2,3], k = 6 since 2 XOR 3 XOR 6 = 7.\n * 4^th query: nums = [2], k = 5 since 2 XOR 5 = 7.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [0,1,2,2,5,7], maximumBit = 3\n * Output: [4,3,6,4,6,7]\n * \n * \n * \n * Constraints:\n * \n * \n * nums.length == n\n * 1 <= n <= 10^5\n * 1 <= maximumBit <= 20\n * 0 <= nums[i] < 2^maximumBit\n * nums\u200b\u200b\u200b is sorted in ascending order.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    long long power(long long base, long long exp) {\n        long long result = 1;\n        while (exp > 0) {\n            if (exp % 2 == 1) {\n                result *= base;\n            }\n            base *= base;\n            exp /= 2;\n        }\n        return result;\n    }\n\n    vector<int> getMaximumXor(vector<int>& nums, int maximumBit) {\n        long long num = power(2, maximumBit) - 1;\n        vector<int> ans(nums.size());\n\n        for(int i=0; i < nums.size(); i++) {\n            num ^= nums[i];\n            ans[nums.size() - 1 - i] = num;\n        }\n\n        return ans;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1442.count-triplets-that-can-form-two-arrays-of-equal-xor.cpp","id":1442,"qid":"1442","title":"Count Triplets That Can Form Two Arrays Of Equal Xor","kebab":"count-triplets-that-can-form-two-arrays-of-equal-xor","rating":1524.6,"ratingLabel":"1524.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1442.count-triplets-that-can-form-two-arrays-of-equal-xor.cpp","leetcodeUrl":"https://leetcode.com/problems/count-triplets-that-can-form-two-arrays-of-equal-xor/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1442.count-triplets-that-can-form-two-arrays-of-equal-xor.cpp","code":"/*\n * @lc app=leetcode id=1442 lang=cpp\n *\n * [1442] Count Triplets That Can Form Two Arrays of Equal XOR\n *\n * https://leetcode.com/problems/count-triplets-that-can-form-two-arrays-of-equal-xor/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given an array of integers arr.\n * \n * We want to select three indices i, j and k where (0 <= i < j <= k <\n * arr.length).\n * \n * Let's define a and b as follows:\n * \n * \n * a = arr[i] ^ arr[i + 1] ^ ... ^ arr[j - 1]\n * b = arr[j] ^ arr[j + 1] ^ ... ^ arr[k]\n * \n * \n * Note that ^ denotes the bitwise-xor operation.\n * \n * Return the number of triplets (i, j and k) Where a == b.\n * \n * \n * Example 1:\n * \n * \n * Input: arr = [2,3,1,6,7]\n * Output: 4\n * Explanation: The triplets are (0,1,2), (0,2,2), (2,3,4) and (2,4,4)\n * \n * \n * Example 2:\n * \n * \n * Input: arr = [1,1,1,1,1]\n * Output: 10\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= arr.length <= 300\n * 1 <= arr[i] <= 10^8\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int countTriplets(vector<int>& arr) {\n        int res = 0;\n        for(int i=0; i < arr.size(); i++) {\n            for(int j=i+1; j < arr.size(); j++) {\n                for(int k=j; k < arr.size(); k++) {\n                    int a = arr[i], b = arr[j];\n                    for(int l=i+1; l < j; l++) {\n                        a ^= arr[l];\n                    }\n                    for(int l=j+1; l <= k; l++) {\n                        b ^= arr[l];\n                    }\n                    if(a == b) res++;\n                }\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/2997.minimum-number-of-operations-to-make-array-xor-equal-to-k.cpp","id":2997,"qid":"2997","title":"Minimum Number Of Operations To Make Array Xor Equal To K","kebab":"minimum-number-of-operations-to-make-array-xor-equal-to-k","rating":1524.6,"ratingLabel":"1524.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/2997.minimum-number-of-operations-to-make-array-xor-equal-to-k.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-number-of-operations-to-make-array-xor-equal-to-k/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/2997.minimum-number-of-operations-to-make-array-xor-equal-to-k.cpp","code":"/*\n * @lc app=leetcode id=2997 lang=cpp\n *\n * [2997] Minimum Number of Operations to Make Array XOR Equal to K\n *\n * https://leetcode.com/problems/minimum-number-of-operations-to-make-array-xor-equal-to-k/description/\n *\n * Category: algorithms\n * Diffculty: Medium\n *\n * You are given a 0-indexed integer array nums and a positive integer k.\n * \n * You can apply the following operation on the array any number of\n * times:\n * \n * \n * Choose any element of the array and flip a bit in its binary representation.\n * Flipping a bit means changing a 0 to 1 or vice versa.\n * \n * \n * Return the minimum number of operations required to make the bitwise XOR of\n * all elements of the final array equal to k.\n * \n * Note that you can flip leading zero bits in the binary representation of\n * elements. For example, for the number (101)2 you can flip the fourth bit and\n * obtain (1101)2.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [2,1,3,4], k = 1\n * Output: 2\n * Explanation: We can do the following operations:\n * - Choose element 2 which is 3 == (011)2, we flip the first bit and we obtain\n * (010)2 == 2. nums becomes [2,1,2,4].\n * - Choose element 0 which is 2 == (010)2, we flip the third bit and we obtain\n * (110)2 = 6. nums becomes [6,1,2,4].\n * The XOR of elements of the final array is (6 XOR 1 XOR 2 XOR 4) == 1 == k.\n * It can be shown that we cannot make the XOR equal to k in less than 2\n * operations.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,0,2,0], k = 0\n * Output: 0\n * Explanation: The XOR of elements of the array is (2 XOR 0 XOR 2 XOR 0) == 0\n * == k. So no operation is needed.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 10^5\n * 0 <= nums[i] <= 10^6\n * 0 <= k <= 10^6\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minOperations(vector<int>& nums, int k) {\n        int n = k;\n        for(int num : nums) {\n            n ^= num;\n        }\n        int res = 0;\n        while (n > 0) {\n            if(n % 2 == 1) res++;\n            n /= 2;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/2178.maximum-split-of-positive-even-integers.cpp","id":2178,"qid":"2178","title":"Maximum Split Of Positive Even Integers","kebab":"maximum-split-of-positive-even-integers","rating":1538.2,"ratingLabel":"1538.2","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/2178.maximum-split-of-positive-even-integers.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-split-of-positive-even-integers/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/2178.maximum-split-of-positive-even-integers.cpp","code":"/*\n * @lc app=leetcode id=2178 lang=cpp\n *\n * [2178] Maximum Split of Positive Even Integers\n *\n * https://leetcode.com/problems/maximum-split-of-positive-even-integers/description/\n *\n * Category: algorithms\n * Difficulty: Medium \n *\n * You are given an integer finalSum. Split it into a sum of a maximum number\n * of unique positive even integers.\n * \n * \n * For example, given finalSum = 12, the following splits are valid (unique\n * positive even integers summing up to finalSum): (12), (2 + 10), (2 + 4 + 6),\n * and (4 + 8). Among them, (2 + 4 + 6) contains the maximum number of\n * integers. Note that finalSum cannot be split into (2 + 2 + 4 + 4) as all the\n * numbers should be unique.\n * \n * \n * Return a list of integers that represent a valid split containing a maximum\n * number of integers. If no valid split exists for finalSum, return an empty\n * list. You may return the integers in any order.\n * \n * \n * Example 1:\n * \n * \n * Input: finalSum = 12\n * Output: [2,4,6]\n * Explanation: The following are valid splits: (12), (2 + 10), (2 + 4 + 6),\n * and (4 + 8).\n * (2 + 4 + 6) has the maximum number of integers, which is 3. Thus, we return\n * [2,4,6].\n * Note that [2,6,4], [6,2,4], etc. are also accepted.\n * \n * \n * Example 2:\n * \n * \n * Input: finalSum = 7\n * Output: []\n * Explanation: There are no valid splits for the given finalSum.\n * Thus, we return an empty array.\n * \n * \n * Example 3:\n * \n * \n * Input: finalSum = 28\n * Output: [6,8,2,12]\n * Explanation: The following are valid splits: (2 + 26), (6 + 8 + 2 + 12), and\n * (4 + 24). \n * (6 + 8 + 2 + 12) has the maximum number of integers, which is 4. Thus, we\n * return [6,8,2,12].\n * Note that [10,2,4,12], [6,2,4,16], etc. are also accepted.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= finalSum <= 10^10\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    using ll = long long;\n\n    bool back(ll Sum, ll cur, vector<ll>& res) {\n        if(Sum == 0) {\n            return true;\n        }\n\n        for(ll i = cur; i <= Sum; i += 2) {\n            if(!res.empty() && i < res.back()) break;\n            res.push_back(i);\n            if(back(Sum - i, i + 2, res)) {\n                return true;\n            }\n            \n            res.pop_back();\n        }\n        return false;\n    }\n\n    vector<ll> maximumEvenSplit(ll finalSum) {\n        vector<ll> res;\n        if(finalSum % 2 != 0) return res;\n        back(finalSum, 2, res);\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1382.balance-a-binary-search-tree.cpp","id":1382,"qid":"1382","title":"Balance A Binary Search Tree","kebab":"balance-a-binary-search-tree","rating":1540.6,"ratingLabel":"1540.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1382.balance-a-binary-search-tree.cpp","leetcodeUrl":"https://leetcode.com/problems/balance-a-binary-search-tree/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1382.balance-a-binary-search-tree.cpp","code":"/*\n * @lc app=leetcode id=1382 lang=cpp\n *\n * [1382] Balance a Binary Search Tree\n *\n * https://leetcode.com/problems/balance-a-binary-search-tree/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given the root of a binary search tree, return a balanced binary search tree\n * with the same node values. If there is more than one answer, return any of\n * them.\n * \n * A binary search tree is balanced if the depth of the two subtrees of every\n * node never differs by more than 1.\n * \n * \n * Example 1:\n * \n * \n * Input: root = [1,null,2,null,3,null,4,null,null]\n * Output: [2,1,3,null,null,null,4]\n * Explanation: This is not the only correct answer, [3,1,4,null,2] is also\n * correct.\n * \n * \n * Example 2:\n * \n * \n * Input: root = [2,1,3]\n * Output: [2,1,3]\n * \n * \n * \n * Constraints:\n * \n * \n * The number of nodes in the tree is in the range [1, 10^4].\n * 1 <= Node.val <= 10^5\n * \n * \n */\n\n// @lc code=start\n/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:    \n    vector<TreeNode*> nodes;\n\n    void inorder(TreeNode* cur) {\n        if (!cur) return;\n        inorder(cur->left);\n        nodes.push_back(cur);\n        inorder(cur->right);\n    }\n\n    TreeNode* build(int l, int r) {\n        if (l > r) return nullptr;\n        int m = l + (r - l) / 2;\n        TreeNode* root = nodes[m];\n        root->left  = build(l, m - 1);\n        root->right = build(m + 1, r);\n        return root;\n    }\n    \n    TreeNode* balanceBST(TreeNode* root) {\n        if (!root) return nullptr;\n        nodes.clear();\n        inorder(root);\n        return build(0, (int)nodes.size() - 1);\n    }\n    \n\n    \n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1749.maximum-absolute-sum-of-any-subarray.cpp","id":1749,"qid":"1749","title":"Maximum Absolute Sum Of Any Subarray","kebab":"maximum-absolute-sum-of-any-subarray","rating":1541.6,"ratingLabel":"1541.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1749.maximum-absolute-sum-of-any-subarray.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-absolute-sum-of-any-subarray/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1749.maximum-absolute-sum-of-any-subarray.cpp","code":"/*\n * @lc app=leetcode id=1749 lang=cpp\n *\n * [1749] Maximum Absolute Sum of Any Subarray\n *\n * https://leetcode.com/problems/maximum-absolute-sum-of-any-subarray/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an integer array nums. The absolute sum of a subarray [numsl,\n * numsl+1, ..., numsr-1, numsr] is abs(numsl + numsl+1 + ... + numsr-1 +\n * numsr).\n * \n * Return the maximum absolute sum of any (possibly empty) subarray of nums.\n * \n * Note that abs(x) is defined as follows:\n * \n * \n * If x is a negative integer, then abs(x) = -x.\n * If x is a non-negative integer, then abs(x) = x.\n * \n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,-3,2,3,-4]\n * Output: 5\n * Explanation: The subarray [2,3] has absolute sum = abs(2+3) = abs(5) = 5.\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,-5,1,-4,3,-2]\n * Output: 8\n * Explanation: The subarray [-5,1,-4] has absolute sum = abs(-5+1-4) = abs(-8)\n * = 8.\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 10^5\n * -10^4 <= nums[i] <= 10^4\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int maxAbsoluteSum(vector<int>& nums) {\n        int n = nums.size();\n        // int mx = nums[0];\n\n        vector<int> pre(n+1, 0);\n        for(int i=1; i<=n; i++) {\n            pre[i] = pre[i-1] + nums[i-1];\n        }\n\n        // for(int i=1; i<=n; i++) {\n        //     for(int j=0; j<n; j++) {\n        //         mx = max(mx, abs(pre[i] - pre[j]));\n        //     }\n        // }\n\n        int ans = 0;\n        int mx = pre[0], mn = pre[0];\n        for(int i=1; i<=n; i++) {\n            ans = max(ans, abs(pre[i] - mx));\n            ans = max(ans, abs(pre[i] - mn));\n\n            mn = min(mn, pre[i]);\n            mx = max(mx, pre[i]);\n        }\n\n        return ans;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/2044.count-number-of-maximum-bitwise-or-subsets.cpp","id":2044,"qid":"2044","title":"Count Number Of Maximum Bitwise Or Subsets","kebab":"count-number-of-maximum-bitwise-or-subsets","rating":1567.7,"ratingLabel":"1567.7","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/2044.count-number-of-maximum-bitwise-or-subsets.cpp","leetcodeUrl":"https://leetcode.com/problems/count-number-of-maximum-bitwise-or-subsets/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/2044.count-number-of-maximum-bitwise-or-subsets.cpp","code":"/*\n * @lc app=leetcode id=2044 lang=cpp\n *\n * [2044] Count Number of Maximum Bitwise-OR Subsets\n *\n * https://leetcode.com/problems/count-number-of-maximum-bitwise-or-subsets/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given an integer array nums, find the maximum possible bitwise OR of a\n * subset of nums and return the number of different non-empty subsets with the\n * maximum bitwise OR.\n * \n * An array a is a subset of an array b if a can be obtained from b by deleting\n * some (possibly zero) elements of b. Two subsets are considered different if\n * the indices of the elements chosen are different.\n * \n * The bitwise OR of an array a is equal to a[0] OR a[1] OR ... OR a[a.length -\n * 1] (0-indexed).\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [3,1]\n * Output: 2\n * Explanation: The maximum possible bitwise OR of a subset is 3. There are 2\n * subsets with a bitwise OR of 3:\n * - [3]\n * - [3,1]\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [2,2,2]\n * Output: 7\n * Explanation: All non-empty subsets of [2,2,2] have a bitwise OR of 2. There\n * are 2^3 - 1 = 7 total subsets.\n * \n * \n * Example 3:\n * \n * \n * Input: nums = [3,2,1,5]\n * Output: 6\n * Explanation: The maximum possible bitwise OR of a subset is 7. There are 6\n * subsets with a bitwise OR of 7:\n * - [3,5]\n * - [3,1,5]\n * - [3,2,5]\n * - [3,2,1,5]\n * - [2,5]\n * - [2,1,5]\n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 16\n * 1 <= nums[i] <= 10^5\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int countMaxOrSubsets(vector<int>& nums) {\n        int maxOr = 0;\n        for(int num : nums) {\n            maxOr |= num;\n        }\n\n        int res = 0;\n        for(int i=0; i < (1 << nums.size()); i++) {\n            int cur = 0;\n            for (int j = 0; j < nums.size(); j++) {\n                if(i & (1 << j)) {\n                    cur |= nums[j];\n                }\n            }\n            if(cur == maxOr) res++;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1400-1599-specialist/1415.the-k-th-lexicographical-string-of-all-happy-strings-of-length-n.cpp","id":1415,"qid":"1415","title":"The K Th Lexicographical String Of All Happy Strings Of Length N","kebab":"the-k-th-lexicographical-string-of-all-happy-strings-of-length-n","rating":1575.6,"ratingLabel":"1575.6","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"problems/1400-1599-specialist/1415.the-k-th-lexicographical-string-of-all-happy-strings-of-length-n.cpp","leetcodeUrl":"https://leetcode.com/problems/the-k-th-lexicographical-string-of-all-happy-strings-of-length-n/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1400-1599-specialist/1415.the-k-th-lexicographical-string-of-all-happy-strings-of-length-n.cpp","code":"/*\n * @lc app=leetcode id=1415 lang=cpp\n *\n * [1415] The k-th Lexicographical String of All Happy Strings of Length n\n *\n * https://leetcode.com/problems/the-k-th-lexicographical-string-of-all-happy-strings-of-length-n/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * A happy string is a string that:\n * \n * \n * consists only of letters of the set ['a', 'b', 'c'].\n * s[i] != s[i + 1] for all values of i from 1 to s.length - 1 (string is\n * 1-indexed).\n * \n * \n * For example, strings \"abc\", \"ac\", \"b\" and \"abcbabcbcb\" are all happy strings\n * and strings \"aa\", \"baa\" and \"ababbc\" are not happy strings.\n * \n * Given two integers n and k, consider a list of all happy strings of length n\n * sorted in lexicographical order.\n * \n * Return the kth string of this list or return an empty string if there are\n * less than k happy strings of length n.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 1, k = 3\n * Output: \"c\"\n * Explanation: The list [\"a\", \"b\", \"c\"] contains all happy strings of length\n * 1. The third string is \"c\".\n * \n * \n * Example 2:\n * \n * \n * Input: n = 1, k = 4\n * Output: \"\"\n * Explanation: There are only 3 happy strings of length 1.\n * \n * \n * Example 3:\n * \n * \n * Input: n = 3, k = 9\n * Output: \"cab\"\n * Explanation: There are 12 different happy string of length 3 [\"aba\", \"abc\",\n * \"aca\", \"acb\", \"bab\", \"bac\", \"bca\", \"bcb\", \"cab\", \"cac\", \"cba\", \"cbc\"]. You\n * will find the 9^th string = \"cab\"\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 10\n * 1 <= k <= 100\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    void g(vector<string>& all, int n, string cur) {\n        if(cur.size() == n) {\n            all.push_back(cur);\n            return;\n        }\n        for(char c : {'a', 'b', 'c'}) {\n            if(cur.empty() || cur.back() != c) {\n                g(all, n, cur + c);\n            }\n        }\n    }\n    string getHappyString(int n, int k) {\n        vector<string> all;\n        g(all, n, \"\");\n        sort(all.begin(), all.end());\n        if(k > all.size()) return \"\";\n        else return all[k - 1];\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/2320.count-number-of-ways-to-place-houses.cpp","id":2320,"qid":"2320","title":"Count Number Of Ways To Place Houses","kebab":"count-number-of-ways-to-place-houses","rating":1607.7,"ratingLabel":"1607.7","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/2320.count-number-of-ways-to-place-houses.cpp","leetcodeUrl":"https://leetcode.com/problems/count-number-of-ways-to-place-houses/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/2320.count-number-of-ways-to-place-houses.cpp","code":"class Solution {\npublic:\n    int countHousePlacements(int n) {\n        long long mod = 1e9+7, a=0, b=1, res = a+b;\n        for(int i=1; i<=n; i++) {\n            a = b;\n            b = res;\n            res = (a+b) % mod;\n        }\n        return (res * res) % mod;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/3613.minimize-maximum-component-cost.cpp","id":3613,"qid":"3613","title":"Minimize Maximum Component Cost","kebab":"minimize-maximum-component-cost","rating":1641.5,"ratingLabel":"1641.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3613.minimize-maximum-component-cost.cpp","leetcodeUrl":"https://leetcode.com/problems/minimize-maximum-component-cost/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3613.minimize-maximum-component-cost.cpp","code":"/*\n * @lc app=leetcode id=3613 lang=cpp\n *\n * [3613] Minimize Maximum Component Cost\n *\n * https://leetcode.com/problems/minimize-maximum-component-cost/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an undirected connected graph with n nodes labeled from 0 to n\n * - 1 and a 2D integer array edges where edges[i] = [ui, vi, wi] denotes an\n * undirected edge between node ui and node vi with weight wi, and an integer\n * k.\n * \n * You are allowed to remove any number of edges from the graph such that the\n * resulting graph has at most k connected components.\n * \n * The cost of a component is defined as the maximum edge weight in that\n * component. If a component has no edges, its cost is 0.\n * \n * Return the minimum possible value of the maximum cost among all components\n * after such removals.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 5, edges = [[0,1,4],[1,2,3],[1,3,2],[3,4,6]], k = 2\n * \n * Output: 4\n * \n * Explanation:\n * \n * \n * \n * \n * Remove the edge between nodes 3 and 4 (weight 6).\n * The resulting components have costs of 0 and 4, so the overall maximum cost\n * is 4.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 4, edges = [[0,1,5],[1,2,5],[2,3,5]], k = 1\n * \n * Output: 5\n * \n * Explanation:\n * \n * \n * \n * \n * No edge can be removed, since allowing only one component (k = 1) requires\n * the graph to stay fully connected.\n * That single component\u2019s cost equals its largest edge weight, which is\n * 5.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 5 * 10^4\n * 0 <= edges.length <= 10^5\n * edges[i].length == 3\n * 0 <= ui, vi < n\n * 1 <= wi <= 10^6\n * 1 <= k <= n\n * The input graph is connected.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int find(vector<int>& uf, int x) {\n        if(uf[x] != x) {\n            uf[x] = find(uf, uf[x]);\n        }\n        return uf[x];\n    }\n    int minCost(int n, vector<vector<int>>& edges, int k) {\n        sort(edges.begin(), edges.end(), [](const vector<int>& a, const vector<int>& b) {\n            return a[2] < b[2];\n        });\n\n        int res = 0;\n\n        vector<int> uf(n);\n        for(int i=0; i<n; i++) {\n            uf[i] = i;\n        }\n        \n        set<int> root;\n        for(int i=0; i<n; i++) {\n            root.insert(i);\n        }\n        int index = 0;\n        while(root.size() > k) {\n            int u = edges[index][0];\n            int v = edges[index][1];\n            int w = edges[index][2];\n\n            int ru = find(uf, u);\n            int rv = find(uf, v);\n            if(ru != rv) {\n                if(ru < rv) {\n                    uf[rv] = ru;\n                    if(root.count(rv)) root.erase(rv);\n                }\n                else {\n                    uf[ru] = rv;\n                    if(root.count(ru)) root.erase(ru);\n                }\n                res = w;\n            }\n            index++;\n        }\n\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/2698.find-the-punishment-number-of-an-integer.cpp","id":2698,"qid":"2698","title":"Find The Punishment Number Of An Integer","kebab":"find-the-punishment-number-of-an-integer","rating":1678.6,"ratingLabel":"1678.6","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/2698.find-the-punishment-number-of-an-integer.cpp","leetcodeUrl":"https://leetcode.com/problems/find-the-punishment-number-of-an-integer/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/2698.find-the-punishment-number-of-an-integer.cpp","code":"/*\n * @lc app=leetcode id=2698 lang=cpp\n *\n * [2698] Find the Punishment Number of an Integer\n *\n * https://leetcode.com/problems/find-the-punishment-number-of-an-integer/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given a positive integer n, return the punishment number of n.\n * \n * The punishment number of n is defined as the sum of the squares of all\n * integers i such that:\n * \n * \n * 1 <= i <= n\n * The decimal representation of i * i can be partitioned into contiguous\n * substrings such that the sum of the integer values of these substrings\n * equals i.\n * \n * \n * \n * Example 1:\n * \n * \n * Input: n = 10\n * Output: 182\n * Explanation: There are exactly 3 integers i in the range [1, 10] that\n * satisfy the conditions in the statement:\n * - 1 since 1 * 1 = 1\n * - 9 since 9 * 9 = 81 and 81 can be partitioned into 8 and 1 with a sum equal\n * to 8 + 1 == 9.\n * - 10 since 10 * 10 = 100 and 100 can be partitioned into 10 and 0 with a sum\n * equal to 10 + 0 == 10.\n * Hence, the punishment number of 10 is 1 + 81 + 100 = 182\n * \n * \n * Example 2:\n * \n * \n * Input: n = 37\n * Output: 1478\n * Explanation: There are exactly 4 integers i in the range [1, 37] that\n * satisfy the conditions in the statement:\n * - 1 since 1 * 1 = 1. \n * - 9 since 9 * 9 = 81 and 81 can be partitioned into 8 + 1. \n * - 10 since 10 * 10 = 100 and 100 can be partitioned into 10 + 0. \n * - 36 since 36 * 36 = 1296 and 1296 can be partitioned into 1 + 29 + 6.\n * Hence, the punishment number of 37 is 1 + 81 + 100 + 1296 = 1478\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 1000\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    bool valid(int n, int A, int B) {\n        if(A + B == n) {\n            return true;\n        }\n\n        int temp = 0, pow = 1;\n        while(B > 0) {\n            temp = temp + (B % 10) * pow;\n            pow *= 10;\n            // temp = temp * 10 + B % 10;\n            B /= 10;\n            if(valid(n, A + temp, B)) return true;\n        }\n        return false;\n    }\n    int punishmentNumber(int n) {\n        int res = 0;\n        for(int i=1; i<=n; i++) {\n            if(valid(i, 0, i*i)) res += i*i;\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/950.reveal-cards-in-increasing-order.cpp","id":950,"qid":"950","title":"Reveal Cards In Increasing Order","kebab":"reveal-cards-in-increasing-order","rating":1686.4,"ratingLabel":"1686.4","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/950.reveal-cards-in-increasing-order.cpp","leetcodeUrl":"https://leetcode.com/problems/reveal-cards-in-increasing-order/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/950.reveal-cards-in-increasing-order.cpp","code":"/*\n * @lc app=leetcode id=950 lang=cpp\n *\n * [950] Reveal Cards In Increasing Order\n *\n * https://leetcode.com/problems/reveal-cards-in-increasing-order/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an integer array deck. There is a deck of cards where every\n * card has a unique integer. The integer on the i^th card is deck[i].\n * \n * You can order the deck in any order you want. Initially, all the cards start\n * face down (unrevealed) in one deck.\n * \n * You will do the following steps repeatedly until all cards are\n * revealed:\n * \n * \n * Take the top card of the deck, reveal it, and take it out of the deck.\n * If there are still cards in the deck then put the next top card of the deck\n * at the bottom of the deck.\n * If there are still unrevealed cards, go back to step 1. Otherwise, stop.\n * \n * \n * Return an ordering of the deck that would reveal the cards in increasing\n * order.\n * \n * Note that the first entry in the answer is considered to be the top of the\n * deck.\n * \n * \n * Example 1:\n * \n * \n * Input: deck = [17,13,11,2,3,5,7]\n * Output: [2,13,3,11,5,17,7]\n * Explanation: \n * We get the deck in the order [17,13,11,2,3,5,7] (this order does not\n * matter), and reorder it.\n * After reordering, the deck starts as [2,13,3,11,5,17,7], where 2 is the top\n * of the deck.\n * We reveal 2, and move 13 to the bottom.  The deck is now [3,11,5,17,7,13].\n * We reveal 3, and move 11 to the bottom.  The deck is now [5,17,7,13,11].\n * We reveal 5, and move 17 to the bottom.  The deck is now [7,13,11,17].\n * We reveal 7, and move 13 to the bottom.  The deck is now [11,17,13].\n * We reveal 11, and move 17 to the bottom.  The deck is now [13,17].\n * We reveal 13, and move 17 to the bottom.  The deck is now [17].\n * We reveal 17.\n * Since all the cards revealed are in increasing order, the answer is\n * correct.\n * \n * \n * Example 2:\n * \n * \n * Input: deck = [1,1000]\n * Output: [1,1000]\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= deck.length <= 1000\n * 1 <= deck[i] <= 10^6\n * All the values of deck are unique.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> deckRevealedIncreasing(vector<int>& deck) {\n        vector<int> res(deck.size());\n        queue<int> q;\n        for(int i=0; i<deck.size(); i++) q.push(i);\n\n        sort(deck.begin(), deck.end());\n        int i=0, j;\n        while(!q.empty()) {\n            j = q.front();\n            q.pop();\n            res[j] = deck[i++];\n            \n            if(!q.empty()) {\n                q.push(q.front());\n                q.pop();\n            }\n        }\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/1963.minimum-number-of-swaps-to-make-the-string-balanced.cpp","id":1963,"qid":"1963","title":"Minimum Number Of Swaps To Make The String Balanced","kebab":"minimum-number-of-swaps-to-make-the-string-balanced","rating":1688.9,"ratingLabel":"1688.9","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/1963.minimum-number-of-swaps-to-make-the-string-balanced.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-number-of-swaps-to-make-the-string-balanced/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/1963.minimum-number-of-swaps-to-make-the-string-balanced.cpp","code":"class Solution {\npublic:\n    int minSwaps(string s) {\n        int res = 0, cur = 0;\n        for(int i=0; i<s.size(); i++) {\n            if(s[i] == '[') cur++;\n            else {\n                if(cur > 0) cur--;\n                else {\n                    res++;\n                    cur = 1;\n                }\n            }\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/2466.count-ways-to-build-good-strings.cpp","id":2466,"qid":"2466","title":"Count Ways To Build Good Strings","kebab":"count-ways-to-build-good-strings","rating":1694.4,"ratingLabel":"1694.4","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/2466.count-ways-to-build-good-strings.cpp","leetcodeUrl":"https://leetcode.com/problems/count-ways-to-build-good-strings/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/2466.count-ways-to-build-good-strings.cpp","code":"class Solution {\npublic:\n    int countGoodStrings(int low, int high, int zero, int one) {\n        long long res = 0, mod = 1e9 + 7;\n        vector<long long> dp(high+1, 0);\n        dp[0] = 1;\n\n        for(int i=1; i<=high; i++) {\n            if(i >= zero) dp[i] += dp[i - zero];\n            if(i >= one) dp[i] += dp[i - one];\n            dp[i] %= mod;\n\n            if(i >= low) {\n                res += dp[i];\n                res %= mod;\n            }\n        }\n        return res;\n        \n        // vector<long long> arr(high+1, 0);\n\n        // for(int i=min(zero, one); i<=high; i++) {\n        //     if(i == zero) arr[i] += 1;\n        //     if(i == one) arr[i] += 1;\n\n        //     if(i-zero > 0) arr[i] = (arr[i] + arr[i-zero]);\n        //     if(i-one > 0) arr[i] = (arr[i] + arr[i-one]);\n        //     arr[i] %= mod;\n\n        //     if(i >= low) res = (res + arr[i]);\n        //     res %= mod;\n        // }\n\n        // return res;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/3315.construct-the-minimum-bitwise-array-ii.cpp","id":3315,"qid":"3315","title":"Construct The Minimum Bitwise Array II","kebab":"construct-the-minimum-bitwise-array-ii","rating":1714.7,"ratingLabel":"1714.7","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3315.construct-the-minimum-bitwise-array-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/construct-the-minimum-bitwise-array-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3315.construct-the-minimum-bitwise-array-ii.cpp","code":"/*\n * @lc app=leetcode id=3315 lang=cpp\n *\n * [3315] Construct the Minimum Bitwise Array II\n *\n * https://leetcode.com/problems/construct-the-minimum-bitwise-array-ii/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an array nums consisting of n prime integers.\n * \n * You need to construct an array ans of length n, such that, for each index i,\n * the bitwise OR of ans[i] and ans[i] + 1 is equal to nums[i], i.e. ans[i] OR\n * (ans[i] + 1) == nums[i].\n * \n * Additionally, you must minimize each value of ans[i] in the resulting\n * array.\n * \n * If it is not possible to find such a value for ans[i] that satisfies the\n * condition, then set ans[i] = -1.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [2,3,5,7]\n * \n * Output: [-1,1,4,3]\n * \n * Explanation:\n * \n * \n * For i = 0, as there is no value for ans[0] that satisfies ans[0] OR (ans[0]\n * + 1) = 2, so ans[0] = -1.\n * For i = 1, the smallest ans[1] that satisfies ans[1] OR (ans[1] + 1) = 3 is\n * 1, because 1 OR (1 + 1) = 3.\n * For i = 2, the smallest ans[2] that satisfies ans[2] OR (ans[2] + 1) = 5 is\n * 4, because 4 OR (4 + 1) = 5.\n * For i = 3, the smallest ans[3] that satisfies ans[3] OR (ans[3] + 1) = 7 is\n * 3, because 3 OR (3 + 1) = 7.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: nums = [11,13,31]\n * \n * Output: [9,12,15]\n * \n * Explanation:\n * \n * \n * For i = 0, the smallest ans[0] that satisfies ans[0] OR (ans[0] + 1) = 11 is\n * 9, because 9 OR (9 + 1) = 11.\n * For i = 1, the smallest ans[1] that satisfies ans[1] OR (ans[1] + 1) = 13 is\n * 12, because 12 OR (12 + 1) = 13.\n * For i = 2, the smallest ans[2] that satisfies ans[2] OR (ans[2] + 1) = 31 is\n * 15, because 15 OR (15 + 1) = 31.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 100\n * 2 <= nums[i] <= 10^9\n * nums[i] is a prime number.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> minBitwiseArray(vector<int>& nums) {\n        vector<int> ans(nums.size(), -1);\n        for (int i = 0; i < nums.size(); i++) {\n            if(nums[i] == 2) {\n                ans[i] = -1;\n            }\n            else if(nums[i] % 2 == 1) {\n                ans[i] = nums[i] - 1; \n                if(nums[i] % 4 == 3) {\n                    int q = 0, temp = nums[i];\n                    while(temp & 1) {\n                        temp >>= 1;\n                        q++;\n                    }\n                    ans[i] = min(ans[i], nums[i] - (1 << q - 1));\n                }\n            }\n        }\n        return ans;\n    }\n};\n// @lc code=end\n\n/*\n**Solution Summary:**\n\nFor each number `n`, we want to find the smallest non-negative integer `m` such that `m | (m + 1) == n`.\n\n* **If `n` is even**: No solution exists because `m | (m + 1)` is always odd. So, return -1.\n* **If `n` is odd**:\n\n  * **Candidate 1**: `m = n - 1` (from an even `m`). Always valid.\n  * **Candidate 2**: Valid only if `n % 4 == 3` (i.e., binary ends with at least two 1s). Let `q` be the number of trailing 1s in `n`; then `m = n - (1 << (q - 1))`.\n\n**Final Answer**:\n\n* If `n % 4 == 1`: Only Candidate 1 \u2192 return `n - 1`.\n* If `n % 4 == 3`: Return `min(n - 1, n - (1 << (q - 1)))`.\n*/\n"},{"key":"problem:problems/1600-1899-expert/1079.letter-tile-possibilities.cpp","id":1079,"qid":"1079","title":"Letter Tile Possibilities","kebab":"letter-tile-possibilities","rating":1740.5,"ratingLabel":"1740.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/1079.letter-tile-possibilities.cpp","leetcodeUrl":"https://leetcode.com/problems/letter-tile-possibilities/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/1079.letter-tile-possibilities.cpp","code":"/*\n * @lc app=leetcode id=1079 lang=cpp\n *\n * [1079] Letter Tile Possibilities\n *\n * https://leetcode.com/problems/letter-tile-possibilities/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You have n\u00a0\u00a0tiles, where each tile has one letter tiles[i] printed on it.\n * \n * Return the number of possible non-empty sequences of letters you can make\n * using the letters printed on those tiles.\n * \n * \n * Example 1:\n * \n * \n * Input: tiles = \"AAB\"\n * Output: 8\n * Explanation: The possible sequences are \"A\", \"B\", \"AA\", \"AB\", \"BA\", \"AAB\",\n * \"ABA\", \"BAA\".\n * \n * \n * Example 2:\n * \n * \n * Input: tiles = \"AAABBC\"\n * Output: 188\n * \n * \n * Example 3:\n * \n * \n * Input: tiles = \"V\"\n * Output: 1\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= tiles.length <= 7\n * tiles consists of uppercase English letters.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int back(vector<int>& cnt) {\n        int res = 0;\n        for(int i=0; i < 26; i++) {\n            if(cnt[i] > 0) {\n                cnt[i]--;\n                res += 1 + back(cnt);\n                cnt[i]++;\n            }\n        }\n        return res;\n    }\n    int numTilePossibilities(string tiles) {\n        vector<int> cnt(26, 0);\n        for(char c : tiles) {\n            cnt[c - 'A']++;\n        }\n\n        return back(cnt);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/1028.recover-a-tree-from-preorder-traversal.cpp","id":1028,"qid":"1028","title":"Recover A Tree From Preorder Traversal","kebab":"recover-a-tree-from-preorder-traversal","rating":1797.5,"ratingLabel":"1797.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/1028.recover-a-tree-from-preorder-traversal.cpp","leetcodeUrl":"https://leetcode.com/problems/recover-a-tree-from-preorder-traversal/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/1028.recover-a-tree-from-preorder-traversal.cpp","code":"/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    TreeNode* recoverFromPreorder(string traversal) {\n        vector<TreeNode*> st;\n        int i = 0, n = traversal.size();\n\n        while (i < n) {\n            int depth = 0;\n            while (i < n && traversal[i] == '-') {\n                ++depth;\n                ++i;\n            }\n\n            int val = 0;\n            while (i < n && isdigit(traversal[i])) {\n                val = val * 10 + (traversal[i] - '0');\n                ++i;\n            }\n\n            TreeNode* node = new TreeNode(val);\n\n            while ((int)st.size() > depth) st.pop_back();\n\n            if (!st.empty()) {\n                TreeNode* parent = st.back();\n                if (!parent->left) parent->left = node;\n                else parent->right = node;\n            }\n\n            st.push_back(node);\n        }\n\n        return st.empty() ? nullptr : st.front();\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/3604.minimum-time-to-reach-destination-in-directed-graph.cpp","id":3604,"qid":"3604","title":"Minimum Time To Reach Destination In Directed Graph","kebab":"minimum-time-to-reach-destination-in-directed-graph","rating":1844.6,"ratingLabel":"1844.6","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3604.minimum-time-to-reach-destination-in-directed-graph.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-time-to-reach-destination-in-directed-graph/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3604.minimum-time-to-reach-destination-in-directed-graph.cpp","code":"/*\n * @lc app=leetcode id=3604 lang=cpp\n *\n * [3604] Minimum Time to Reach Destination in Directed Graph\n *\n * https://leetcode.com/problems/minimum-time-to-reach-destination-in-directed-graph/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an integer n and a directed graph with n nodes labeled from 0\n * to n - 1. This is represented by a 2D array edges, where edges[i] = [ui, vi,\n * starti, endi] indicates an edge from node ui to vi that can only be used at\n * any integer time t such that starti <= t <= endi.\n * \n * You start at node 0 at time 0.\n * \n * In one unit of time, you can either:\n * \n * \n * Wait at your current node without moving, or\n * Travel along an outgoing edge from your current node if the current time t\n * satisfies starti <= t <= endi.\n * \n * \n * Return the minimum time required to reach node n - 1. If it is impossible,\n * return -1.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 3, edges = [[0,1,0,1],[1,2,2,5]]\n * \n * Output: 3\n * \n * Explanation:\n * \n * \n * \n * The optimal path is:\n * \n * \n * At time t = 0, take the edge (0 \u2192 1) which is available from 0 to 1. You\n * arrive at node 1 at time t = 1, then wait until t = 2.\n * At time t = 2, take the edge (1 \u2192 2) which is available from 2 to 5. You\n * arrive at node 2 at time 3.\n * \n * \n * Hence, the minimum time to reach node 2 is 3.\n * \n * \n * Example 2:\n * \n * \n * Input: n = 4, edges = [[0,1,0,3],[1,3,7,8],[0,2,1,5],[2,3,4,7]]\n * \n * Output: 5\n * \n * Explanation:\n * \n * \n * \n * The optimal path is:\n * \n * \n * Wait at node 0 until time t = 1, then take the edge (0 \u2192 2) which is\n * available from 1 to 5. You arrive at node 2 at t = 2.\n * Wait at node 2 until time t = 4, then take the edge (2 \u2192 3) which is\n * available from 4 to 7. You arrive at node 3 at t = 5.\n * \n * \n * Hence, the minimum time to reach node 3 is 5.\n * \n * \n * Example 3:\n * \n * \n * Input: n = 3, edges = [[1,0,1,3],[1,2,3,5]]\n * \n * Output: -1\n * \n * Explanation:\n * \n * \n * \n * \n * Since there is no outgoing edge from node 0, it is impossible to reach node\n * 2. Hence, the output is -1.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 10^5\n * 0 <= edges.length <= 10^5\n * edges[i] == [ui, vi, starti, endi]\n * 0 <= ui, vi <= n - 1\n * ui != vi\n * 0 <= starti <= endi <= 10^9\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int minTime(int n, vector<vector<int>>& edges) {\n        vector<vector<pair<int, pair<int, int>>>> adj(n);\n        for (const auto& edge : edges) {\n            adj[edge[0]].push_back({edge[1], {edge[2], edge[3]}});\n        }\n\n        vector<long long> dist(n, -1);\n        dist[0] = 0;\n\n        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;\n        pq.push({0, 0}); // {time, node}\n\n        while (!pq.empty()) {\n            auto [time, u] = pq.top();\n            pq.pop();\n\n            if (time > dist[u] && dist[u] != -1) {\n                continue;\n            }\n\n            for (const auto& edge : adj[u]) {\n                int v = edge.first;\n                long long start = edge.second.first;\n                long long end = edge.second.second;\n\n                long long departure_time = max(time, start);\n                if (departure_time <= end) {\n                    long long arrival_time = departure_time + 1;\n                    if (dist[v] == -1 || arrival_time < dist[v]) {\n                        dist[v] = arrival_time;\n                        pq.push({arrival_time, v});\n                    }\n                }\n            }\n        }\n        return static_cast<int>(dist[n - 1]);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/3676.count-bowl-subarrays.cpp","id":3676,"qid":"3676","title":"Count Bowl Subarrays","kebab":"count-bowl-subarrays","rating":1847.5,"ratingLabel":"1847.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3676.count-bowl-subarrays.cpp","leetcodeUrl":"https://leetcode.com/problems/count-bowl-subarrays/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3676.count-bowl-subarrays.cpp","code":"class Solution {\npublic:\n    long long bowlSubarrays(vector<int>& nums) {\n        int n = nums.size();\n        vector<pair<int,int>> a; a.reserve(n);\n        for (int i = 0; i < n; ++i) a.push_back({nums[i], i});\n        sort(a.rbegin(), a.rend());\n\n        set<int> active;\n        long long ans = 0;\n\n        for (auto &[val, idx] : a) {\n            auto it = active.lower_bound(idx);\n            if (it != active.end()) {\n                int r = *it;\n                if (r - idx >= 2) ans++;\n            }\n            if (it != active.begin()) {\n                int l = *prev(it);\n                if (idx - l >= 2) ans++;\n            }\n            active.insert(idx);\n        }\n        return ans;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/2266.count-number-of-texts.cpp","id":2266,"qid":"2266","title":"Count Number Of Texts","kebab":"count-number-of-texts","rating":1856.9,"ratingLabel":"1856.9","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/2266.count-number-of-texts.cpp","leetcodeUrl":"https://leetcode.com/problems/count-number-of-texts/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/2266.count-number-of-texts.cpp","code":"class Solution {\npublic:\n    int countTexts(string k) {\n        int n = k.length();\n        long long res = 1, mod = 1e9+7;\n\n        vector<long long> g1(n+1, 0), g2(n+1, 0);\n        g1[0] = g2[0] = 1;\n        for(int i=1; i<=n; i++) {\n            if(i >= 1) g1[i] += g1[i-1], g2[i] += g2[i-1];\n            if(i >= 2) g1[i] += g1[i-2], g2[i] += g2[i-2];\n            if(i >= 3) g1[i] += g1[i-3], g2[i] += g2[i-3];\n            if(i >= 4) g2[i] += g2[i-4];\n\n            g1[i] %= mod, g2[i] %= mod;\n        }\n        \n        for(int i=0; i<n; ) {\n            char c = k[i];\n            int cur = 0;\n            while(i < n && k[i] == c) {\n                cur++;\n                i++;\n            }\n\n            // if(c == '7' || c == '9') res = res * g2[cur];\n            // else res = res * g1[cur];\n            res = (c == '7' || c == '9') ? res * g2[cur] : res * g1[cur];\n            res %= mod;\n        }\n\n        return res;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/3346.maximum-frequency-of-an-element-after-performing-operations-i.cpp","id":3346,"qid":"3346","title":"Maximum Frequency Of An Element After Performing Operations I","kebab":"maximum-frequency-of-an-element-after-performing-operations-i","rating":1864.9,"ratingLabel":"1864.9","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3346.maximum-frequency-of-an-element-after-performing-operations-i.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-frequency-of-an-element-after-performing-operations-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3346.maximum-frequency-of-an-element-after-performing-operations-i.cpp","code":"class Solution {\npublic:\n    int maxFrequency(vector<int>& nums, int k, int numOperations) {\n        unordered_map<int, int> mp;\n        for(auto& i : nums) mp[i]++;\n\n        vector<int> vt;\n        for(auto& i : mp) vt.push_back(i.first);\n        sort(vt.begin(), vt.end());\n\n        if(numOperations == 0 || k == 0) {\n            int res = 0;\n            for(auto& i : mp) res = max(res, i.second);\n            return res;\n        }\n        \n        int cur = 0;\n        for(int i=vt[0]-1; i<=vt[0]-1+k; i++) {\n            cur += mp[i];\n        }\n        int res = min(cur, numOperations);\n        for(int i=vt[0]-1, j; i<=vt.back()+1; ) {\n            cur -= mp[i-k];\n            i++, j=i+k;\n            cur -= mp[i];\n            cur += mp[i+k];\n\n            res = max(res, min(cur, numOperations) + mp[i]);\n            cur += mp[i];\n        }\n        return res;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/1605.find-valid-matrix-given-row-and-column-sums.cpp","id":1605,"qid":"1605","title":"Find Valid Matrix Given Row And Column Sums","kebab":"find-valid-matrix-given-row-and-column-sums","rating":1867.9,"ratingLabel":"1867.9","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/1605.find-valid-matrix-given-row-and-column-sums.cpp","leetcodeUrl":"https://leetcode.com/problems/find-valid-matrix-given-row-and-column-sums/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/1605.find-valid-matrix-given-row-and-column-sums.cpp","code":"class Solution {\npublic:\n    vector<vector<int>> restoreMatrix(vector<int>& rowSum, vector<int>& colSum) {\n        int n = rowSum.size(), m = colSum.size();\n        vector<vector<int>> g(n, vector<int>(m, 0));\n\n        for(int i=0; i<n; i++) {\n            for(int j=0; j<m; j++) {\n                int x = min(rowSum[i], colSum[j]);\n                g[i][j] = x;\n                rowSum[i] -= x;\n                colSum[j] -= x;\n            }\n        }\n\n        return g;\n    }\n};\n"},{"key":"problem:problems/1600-1899-expert/2305.fair-distribution-of-cookies.cpp","id":2305,"qid":"2305","title":"Fair Distribution Of Cookies","kebab":"fair-distribution-of-cookies","rating":1886.7,"ratingLabel":"1886.7","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/2305.fair-distribution-of-cookies.cpp","leetcodeUrl":"https://leetcode.com/problems/fair-distribution-of-cookies/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/2305.fair-distribution-of-cookies.cpp","code":"/*\n * @lc app=leetcode id=2305 lang=cpp\n *\n * [2305] Fair Distribution of Cookies\n *\n * https://leetcode.com/problems/fair-distribution-of-cookies/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an integer array cookies, where cookies[i] denotes the number\n * of cookies in the i^th bag. You are also given an integer k that denotes the\n * number of children to distribute all the bags of cookies to. All the cookies\n * in the same bag must go to the same child and cannot be split up.\n * \n * The unfairness of a distribution is defined as the maximum total cookies\n * obtained by a single child in the distribution.\n * \n * Return the minimum unfairness of all distributions.\n * \n * \n * Example 1:\n * \n * \n * Input: cookies = [8,15,10,20,8], k = 2\n * Output: 31\n * Explanation: One optimal distribution is [8,15,8] and [10,20]\n * - The 1^st child receives [8,15,8] which has a total of 8 + 15 + 8 = 31\n * cookies.\n * - The 2^nd child receives [10,20] which has a total of 10 + 20 = 30 cookies.\n * The unfairness of the distribution is max(31,30) = 31.\n * It can be shown that there is no distribution with an unfairness less than\n * 31.\n * \n * \n * Example 2:\n * \n * \n * Input: cookies = [6,1,3,2,2,4,1,2], k = 3\n * Output: 7\n * Explanation: One optimal distribution is [6,1], [3,2,2], and [4,1,2]\n * - The 1^st child receives [6,1] which has a total of 6 + 1 = 7 cookies.\n * - The 2^nd child receives [3,2,2] which has a total of 3 + 2 + 2 = 7\n * cookies.\n * - The 3^rd child receives [4,1,2] which has a total of 4 + 1 + 2 = 7\n * cookies.\n * The unfairness of the distribution is max(7,7,7) = 7.\n * It can be shown that there is no distribution with an unfairness less than\n * 7.\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= cookies.length <= 8\n * 1 <= cookies[i] <= 10^5\n * 2 <= k <= cookies.length\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int min_unfairness = INT_MAX;\n\n    void dis(vector<int>& cookies, int k, int i_cook, vector<int>& child) {\n        if(i_cook == cookies.size()) {\n            int max_cookies = 0;\n            for(int i = 0; i < k; i++) {\n                max_cookies = max(max_cookies, child[i]);\n            }\n            min_unfairness = min(min_unfairness, max_cookies);\n            return;\n        }\n\n        for(int i = 0; i < k; i++) {\n            child[i] += cookies[i_cook];\n            dis(cookies, k, i_cook + 1, child);\n            child[i] -= cookies[i_cook];\n        }\n    }\n\n    int distributeCookies(vector<int>& cookies, int k) {\n        vector<int> child(k, 0);\n        min_unfairness = INT_MAX;\n        dis(cookies, k, 0, child);\n        return min_unfairness;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1600-1899-expert/3608.minimum-time-for-k-connected-components.cpp","id":3608,"qid":"3608","title":"Minimum Time For K Connected Components","kebab":"minimum-time-for-k-connected-components","rating":1892.5,"ratingLabel":"1892.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"problems/1600-1899-expert/3608.minimum-time-for-k-connected-components.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-time-for-k-connected-components/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1600-1899-expert/3608.minimum-time-for-k-connected-components.cpp","code":"/*\n * @lc app=leetcode id=3608 lang=cpp\n *\n * [3608] Minimum Time for K Connected Components\n *\n * https://leetcode.com/problems/minimum-time-for-k-connected-components/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * You are given an integer n and an undirected graph with n nodes labeled from\n * 0 to n - 1. This is represented by a 2D array edges, where edges[i] = [ui,\n * vi, timei] indicates an undirected edge between nodes ui and vi that can be\n * removed at timei.\n * \n * You are also given an integer k.\n * \n * Initially, the graph may be connected or disconnected. Your task is to find\n * the minimum time t such that after removing all edges with time <= t, the\n * graph contains at least k connected components.\n * \n * Return the minimum time t.\n * \n * A connected component is a subgraph of a graph in which there exists a path\n * between any two vertices, and no vertex of the subgraph shares an edge with\n * a vertex outside of the subgraph.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 2, edges = [[0,1,3]], k = 2\n * \n * Output: 3\n * \n * Explanation:\n * \n * \n * \n * \n * Initially, there is one connected component {0, 1}.\n * At time = 1 or 2, the graph remains unchanged.\n * At time = 3, edge [0, 1] is removed, resulting in k = 2 connected components\n * {0}, {1}. Thus, the answer is 3.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 3, edges = [[0,1,2],[1,2,4]], k = 3\n * \n * Output: 4\n * \n * Explanation:\n * \n * \n * \n * \n * Initially, there is one connected component {0, 1, 2}.\n * At time = 2, edge [0, 1] is removed, resulting in two connected components\n * {0}, {1, 2}.\n * At time = 4, edge [1, 2] is removed, resulting in k = 3 connected components\n * {0}, {1}, {2}. Thus, the answer is 4.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: n = 3, edges = [[0,2,5]], k = 2\n * \n * Output: 0\n * \n * Explanation:\n * \n * \n * \n * \n * Since there are already k = 2 disconnected components {1}, {0, 2}, no edge\n * removal is needed. Thus, the answer is 0.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= n <= 10^5\n * 0 <= edges.length <= 10^5\n * edges[i] = [ui, vi, timei]\n * 0 <= ui, vi < n\n * ui != vi\n * 1 <= timei <= 10^9\n * 1 <= k <= n\n * There are no duplicate edges.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n\nvoid init_union_find(vector<int>& uf, int n) {\n    uf.assign(n, -1);\n}\nint find(vector<int>& uf, int x) {\n    if (uf[x] < 0) return x;\n    return uf[x] = find(uf, uf[x]);\n}\nbool unite(vector<int>& uf, int x, int y) {\n    x = find(uf, x);\n    y = find(uf, y);\n    if (x == y) return false;\n\n    if (uf[x] > uf[y]) swap(x, y);\n    uf[x] += uf[y];\n    uf[y] = x;\n    return true;\n}\nbool connected(vector<int>& uf, int x, int y) {\n    return find(uf, x) == find(uf, y);\n}\nint size(vector<int>& uf, int x) {\n    return -uf[find(uf, x)];\n}\nint count_components(const vector<int>& uf) {\n    int count = 0;\n    for (int i = 0; i < uf.size(); ++i) {\n        if (uf[i] < 0) ++count;\n    }\n    return count;\n}\n/* --- */\n    int minTime(int n, vector<vector<int>>& edges, int k) {\n        vector<int> uf;\n        init_union_find(uf, n);\n        \n        sort(edges.begin(), edges.end(), [](const vector<int>& a, const vector<int>& b) {\n            return a[2] > b[2];\n        });\n\n        int merge = 0;\n        for(int i=0; i<edges.size(); i++) {\n            int u = edges[i][0];\n            int v = edges[i][1];\n            if(!connected(uf, u, v)) {\n                unite(uf, u, v);\n                merge++;\n                if(n - merge < k) {\n                    return edges[i][2];\n                }\n            }\n            // unite(uf, u, v);\n            // if(count_components(uf) < k) {\n            //     return edges[i][2];\n            // }\n        }\n        return 0;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1900-2099-candidate-master/1140.stone-game-ii.cpp","id":1140,"qid":"1140","title":"Stone Game II","kebab":"stone-game-ii","rating":2035.0,"ratingLabel":"2035.0","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"problems/1900-2099-candidate-master/1140.stone-game-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/stone-game-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1900-2099-candidate-master/1140.stone-game-ii.cpp","code":"/*\n * @lc app=leetcode id=1140 lang=cpp\n *\n * [1140] Stone Game II\n *\n * https://leetcode.com/problems/stone-game-ii/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Alice and Bob continue their games with piles of stones. There are a number\n * of piles arranged in a row, and each pile has a positive integer number of\n * stones piles[i]. The objective of the game is to end with the most stones.\n * \n * Alice and Bob take turns, with Alice starting first.\n * \n * On each player's turn, that player can take all the stones in the first X\n * remaining piles, where 1 <= X <= 2M. Then, we set M = max(M, X). Initially,\n * M = 1.\n * \n * The game continues until all the stones have been taken.\n * \n * Assuming Alice and Bob play optimally, return the maximum number of stones\n * Alice can get.\n * \n * \n * Example 1:\n * \n * \n * Input: piles = [2,7,9,4,4]\n * \n * Output: 10\n * \n * Explanation:\n * \n * \n * If Alice takes one pile at the beginning, Bob takes two piles, then Alice\n * takes 2 piles again. Alice can get 2 + 4 + 4 = 10 stones in total.\n * If Alice takes two piles at the beginning, then Bob can take all three piles\n * left. In this case, Alice get 2 + 7 = 9 stones in total.\n * \n * \n * So we return 10 since it's larger.\n * \n * \n * Example 2:\n * \n * \n * Input: piles = [1,2,3,4,5,100]\n * \n * Output: 104\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= piles.length <= 100\n * 1 <= piles[i]\u00a0<= 10^4\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    int dfs(vector<vector<int>>& dp, vector<int>& suffix, int index, int M) {\n        if(index >= suffix.size()) return 0;\n        if(2 * M >= suffix.size() - index) return suffix[index];\n        if(dp[index][M] != -1) return dp[index][M];\n\n        int best = 0;\n        for(int X = 1; X <= 2*M; X++) {\n            best = max(best, suffix[index] - dfs(dp, suffix, index+X, max(M, X)));\n        }\n        return dp[index][M] = best;\n    }\n    int stoneGameII(vector<int>& piles) {\n        int n = piles.size();\n\n        vector<int> suffix(n+1, 0);\n        for(int i=n-1; i>=0; i--) {\n            suffix[i] = suffix[i+1] + piles[i];\n        }\n\n        vector<vector<int>> dp(n, vector<int>(n+1, -1));\n\n        return dfs(dp, suffix, 0, 1);\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/1900-2099-candidate-master/3685.subsequence-sum-after-capping-elements.cpp","id":3685,"qid":"3685","title":"Subsequence Sum After Capping Elements","kebab":"subsequence-sum-after-capping-elements","rating":2073.4,"ratingLabel":"2073.4","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"problems/1900-2099-candidate-master/3685.subsequence-sum-after-capping-elements.cpp","leetcodeUrl":"https://leetcode.com/problems/subsequence-sum-after-capping-elements/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/1900-2099-candidate-master/3685.subsequence-sum-after-capping-elements.cpp","code":"/* Upsolving */\n\nclass Solution {\npublic:\n    vector<bool> subsequenceSumAfterCapping(vector<int>& nums, int k) {\n        int n = nums.size();\n        sort(nums.begin(), nums.end());\n        vector<bool> sum(k+1, 0), res(n, 0);\n        sum[0] = 1;\n        \n        for(int i=0, x=1; x<=n; x++) {\n            while(i < n && nums[i] < x) {\n                for(int j=k; j>=nums[i]; j--) {\n                    if(sum[j - nums[i]]) sum[j] = 1;\n                }\n                i++;\n            }\n\n            int cap = n-i;\n            for(int j=0; j<=cap && j * x <= k; j++) {\n                if(sum[k - j * x]) {\n                    res[x-1] = 1;\n                    break;\n                }\n            }\n        }\n        return res;\n    }\n};\n\n/* ===================================*/\n\n/*\n\n====== Fail to solve in contest ======\n\nclass Solution {\npublic:\n    vector<bool> subsequenceSumAfterCapping(vector<int>& nums, int k) {\n        int n = nums.size();\n        vector<bool> ans(n, false);\n\n        sort(nums.begin(), nums.end());\n        // int mx = *max_element(nums.begin(), nums.end());\n        // for(int i=n-1; i>=0; i--) if(nums[i] > k) nums[i] = k;\n        int mx = nums.back();\n        \n        for (int cap = 1; cap <= n; cap++) {\n            // if(cap > nums[n-1]) {\n            if(cap > mx) {\n                ans[cap-1] = ans[cap-2];\n                continue;\n            }\n            if(cap * n < k) {\n                // ans[cap-1] = false;\n                continue;\n            }\n            \n            bitset<4001> dp;\n            dp[0] = 1;\n\n            for (int& x : nums) {\n                int val = min(x, cap);\n                if (val > k) break;\n                else if(val == k) {\n                    dp[k] = 1;\n                    break;\n                }\n                else {\n                    dp |= (dp << val);\n                    if(dp[k]) break;\n                }\n            }\n            \n            ans[cap-1] = dp[k];\n        }\n        \n        return ans;\n    }\n};\n*/\n"},{"key":"problem:problems/2100-2299-master/3714.longest-balanced-substring-ii.cpp","id":3714,"qid":"3714","title":"Longest Balanced Substring II","kebab":"longest-balanced-substring-ii","rating":2201.8,"ratingLabel":"2201.8","tier":"Master","tierSlug":"2100-2299-master","tierLabel":"2100-2299","path":"problems/2100-2299-master/3714.longest-balanced-substring-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-balanced-substring-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/2100-2299-master/3714.longest-balanced-substring-ii.cpp","code":"// UPSOLVING\n\nclass Solution {\npublic:\n    int double_chars(string s, char x, char y) {\n        int n = s.size();\n        int res = 0;\n        unordered_map<int, int> first;\n        int bal = 0;\n\n        first[0] = -1;\n\n        for(int i=0; i<n; i++) {\n            if(s[i] == x) bal++;\n            else if(s[i] == y) bal--;\n            else {\n                bal = 0;\n                first.clear();\n                first[0] = i;\n                continue;\n            }\n            if(first.count(bal)) {\n                res = max(res, i - first[bal]);\n            }\n            else {\n                first[bal] = i;\n            }\n        }\n        return res;\n    }\n    int longestBalanced(string s) {\n        int res = 0;\n        int n = s.size();\n\n        // single char\n        char ch = s[0];\n        for(int i=0, cur=0; i<n; i++) {\n            if(s[i] == ch) {\n                cur++;\n            }\n            else {\n                ch = s[i];\n                cur = 1;\n            }\n            res = max(res, cur);\n        }\n\n        // double chars\n        res = max(res, double_chars(s, 'a', 'b'));\n        res = max(res, double_chars(s, 'b', 'c'));\n        res = max(res, double_chars(s, 'a', 'c'));\n\n        // triple chars\n        int a=0, b=0, c=0;\n        map<pair<int, int>, int> mp;\n        mp[{0,0}] = -1;\n\n        for(int i=0; i<n; i++) {\n            if(s[i] == 'a') a++;\n            else if(s[i] == 'b') b++;\n            else if(s[i] == 'c') c++;\n\n            pair<int, int> k = {a - b, a - c};\n            if(mp.count(k)) res = max(res, i - mp[k]);\n            else mp[k] = i;\n        }\n\n        return res;\n    }\n};\n"},{"key":"problem:problems/2300-2399-international-master/3600.maximize-spanning-tree-stability-with-upgrades.cpp","id":3600,"qid":"3600","title":"Maximize Spanning Tree Stability With Upgrades","kebab":"maximize-spanning-tree-stability-with-upgrades","rating":2301.0,"ratingLabel":"2301.0","tier":"International Master","tierSlug":"2300-2399-international-master","tierLabel":"2300-2399","path":"problems/2300-2399-international-master/3600.maximize-spanning-tree-stability-with-upgrades.cpp","leetcodeUrl":"https://leetcode.com/problems/maximize-spanning-tree-stability-with-upgrades/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/2300-2399-international-master/3600.maximize-spanning-tree-stability-with-upgrades.cpp","code":"/*\n * @lc app=leetcode id=3600 lang=cpp\n *\n * [3600] Maximize Spanning Tree Stability with Upgrades\n *\n * https://leetcode.com/problems/maximize-spanning-tree-stability-with-upgrades/description/\n *\n * Category: algorithms\n * Difficulty: Hard\n *\n * You are given an integer n, representing n nodes numbered from 0 to n - 1\n * and a list of edges, where edges[i] = [ui, vi, si, musti]:\n * \n * \n * ui and vi indicates an undirected edge between nodes ui and vi.\n * si is the strength of the edge.\n * musti is an integer (0 or 1). If musti == 1, the edge must be included in\n * the spanning tree. These edges cannot be upgraded.\n * \n * \n * You are also given an integer k, the maximum number of upgrades you can\n * perform. Each upgrade doubles the strength of an edge, and each eligible\n * edge (with musti == 0) can be upgraded at most once.\n * \n * The stability of a spanning tree is defined as the minimum strength score\n * among all edges included in it.\n * \n * Return the maximum possible stability of any valid spanning tree. If it is\n * impossible to connect all nodes, return -1.\n * \n * Note: A spanning tree of a graph with n nodes is a subset of the edges that\n * connects all nodes together (i.e. the graph is connected) without forming\n * any cycles, and uses exactly n - 1 edges.\n * \n * \n * Example 1:\n * \n * \n * Input: n = 3, edges = [[0,1,2,1],[1,2,3,0]], k = 1\n * \n * Output: 2\n * \n * Explanation:\n * \n * \n * Edge [0,1] with strength = 2 must be included in the spanning tree.\n * Edge [1,2] is optional and can be upgraded from 3 to 6 using one\n * upgrade.\n * The resulting spanning tree includes these two edges with strengths 2 and\n * 6.\n * The minimum strength in the spanning tree is 2, which is the maximum\n * possible stability.\n * \n * \n * \n * Example 2:\n * \n * \n * Input: n = 3, edges = [[0,1,4,0],[1,2,3,0],[0,2,1,0]], k = 2\n * \n * Output: 6\n * \n * Explanation:\n * \n * \n * Since all edges are optional and up to k = 2 upgrades are allowed.\n * Upgrade edges [0,1] from 4 to 8 and [1,2] from 3 to 6.\n * The resulting spanning tree includes these two edges with strengths 8 and\n * 6.\n * The minimum strength in the tree is 6, which is the maximum possible\n * stability.\n * \n * \n * \n * Example 3:\n * \n * \n * Input: n = 3, edges = [[0,1,1,1],[1,2,1,1],[2,0,1,1]], k = 0\n * \n * Output: -1\n * \n * Explanation:\n * \n * \n * All edges are mandatory and form a cycle, which violates the spanning tree\n * property of acyclicity. Thus, the answer is -1.\n * \n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= n <= 10^5\n * 1 <= edges.length <= 10^5\n * edges[i] = [ui, vi, si, musti]\n * 0 <= ui, vi < n\n * ui != vi\n * 1 <= si <= 10^5\n * musti is either 0 or 1.\n * 0 <= k <= n\n * There are no duplicate edges.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n\n    // Union-Find\n    void init_union_find(vector<int>& uf, int n) {\n        uf.assign(n, -1);\n    }\n\n    int find(vector<int>& uf, int x) {\n        if (uf[x] < 0) return x;\n        return uf[x] = find(uf, uf[x]);\n    }\n\n    bool unite(vector<int>& uf, int x, int y) {\n        x = find(uf, x);\n        y = find(uf, y);\n        if (x == y) return false;\n\n        if (uf[x] > uf[y]) swap(x, y);\n        uf[x] += uf[y];\n        uf[y] = x;\n        return true;\n    }\n\n    bool connected(vector<int>& uf, int x, int y) {\n        return find(uf, x) == find(uf, y);\n    }\n\n    int size(vector<int>& uf, int x) {\n        return -uf[find(uf, x)];\n    }\n    // Union-Find\n\n\n    int maxStability(int n, vector<vector<int>>& edges, int k) {\n        sort(edges.begin(), edges.end(), [](const vector<int>& a, const vector<int>& b) {\n            if (a[3] != b[3]) return a[3] > b[3];\n            return a[2] > b[2];\n        });\n\n        vector<int> uf(n);\n        init_union_find(uf, n);\n\n        int edge_count = 0;\n\n        int must_edge = INT_MAX;\n        vector<int> upgraded_edges;\n\n        for(int i=0; i<edges.size(); i++) {\n            if (edges[i][3] == 1) {\n                if (!unite(uf, edges[i][0], edges[i][1])) {\n                    return -1;\n                }\n                must_edge = min(must_edge, edges[i][2]);\n                edge_count++;\n            }\n            else if (edges[i][3] == 0) {\n                if(!unite(uf, edges[i][0], edges[i][1])) {\n                    continue;\n                }\n\n                upgraded_edges.push_back(edges[i][2]);\n                edge_count++;\n            }\n        }\n\n        if(edge_count < n - 1) {\n            return -1;\n        }\n        \n        int upgraded_edge = INT_MAX;\n        if(upgraded_edges.size() > 0) {\n            sort(upgraded_edges.begin(), upgraded_edges.end());\n            for(int i=0; k > 0 && i < upgraded_edges.size(); i++) {\n                upgraded_edges[i] *= 2;\n                k--;\n            }\n            upgraded_edge = *min_element(upgraded_edges.begin(), upgraded_edges.end());\n        }\n\n        int res = min(must_edge, upgraded_edge);\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/2400-2599-grandmaster/3691.maximum-total-subarray-value-ii.cpp","id":3691,"qid":"3691","title":"Maximum Total Subarray Value II","kebab":"maximum-total-subarray-value-ii","rating":2469.0,"ratingLabel":"2469.0","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"problems/2400-2599-grandmaster/3691.maximum-total-subarray-value-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-total-subarray-value-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/2400-2599-grandmaster/3691.maximum-total-subarray-value-ii.cpp","code":"struct RMQ {\n    int n, LOG;\n    vector<int> lg;                 // floor(log2(i))\n    vector<vector<int>> stMax;      // stMax[k][i] = max on [i, i+2^k-1]\n    vector<vector<int>> stMin;      // stMin[k][i] = min on [i, i+2^k-1]\n\n    RMQ() {}\n    RMQ(const vector<int>& a) { build(a); }\n\n    void build(const vector<int>& a) {\n        n = (int)a.size();\n        LOG = 1;\n        while ((1 << LOG) <= n) ++LOG;\n\n        lg.assign(n + 1, 0);\n        for (int i = 2; i <= n; ++i) lg[i] = lg[i >> 1] + 1;\n\n        stMax.assign(LOG, vector<int>(n));\n        stMin.assign(LOG, vector<int>(n));\n        // k = 0\n        for (int i = 0; i < n; ++i) {\n            stMax[0][i] = a[i];\n            stMin[0][i] = a[i];\n        }\n        // k > 0\n        for (int k = 1; k < LOG; ++k) {\n            int len = 1 << k;\n            int half = len >> 1;\n            for (int i = 0; i + len - 1 < n; ++i) {\n                stMax[k][i] = std::max(stMax[k - 1][i], stMax[k - 1][i + half]);\n                stMin[k][i] = std::min(stMin[k - 1][i], stMin[k - 1][i + half]);\n            }\n        }\n    }\n\n    inline int rangeMax(int l, int r) const {\n        if (l > r) swap(l, r);\n        int k = lg[r - l + 1];\n        return std::max(stMax[k][l], stMax[k][r - (1 << k) + 1]);\n    }\n    inline int rangeMin(int l, int r) const {\n        if (l > r) swap(l, r);\n        int k = lg[r - l + 1];\n        return std::min(stMin[k][l], stMin[k][r - (1 << k) + 1]);\n    }\n    inline int value(int l, int r) const { // v(l,r) = max - min\n        return rangeMax(l, r) - rangeMin(l, r);\n    }\n};\n\nclass Solution {\npublic:\n    long long maxTotalValue(vector<int>& nums, int k) {\n        int n = (int)nums.size();\n        RMQ rmq(nums);\n\n        // \u5c0d\u6bcf\u500b\u56fa\u5b9a l\uff0c\u5e8f\u5217 v(l, r)\uff08r \u5f80\u5de6\u79fb\uff09\u70ba\u975e\u589e\n        // \u521d\u59cb\u5316\u5c07 (l, r = n-1) \u653e\u5165\u6700\u5927\u5806\n        using Node = pair<int, pair<int,int>>; // (value, (l, r))\n        priority_queue<Node> pq;\n        pq = priority_queue<Node>();\n\n        for (int l = 0; l < n; ++l) {\n            int r = n - 1;\n            int v = rmq.value(l, r);\n            pq.push({v, {l, r}});\n        }\n\n        long long ans = 0;\n        while (k-- > 0 && !pq.empty()) {\n            auto [val, lr] = pq.top(); pq.pop();\n            int l = lr.first, r = lr.second;\n            ans += (long long)val;\n\n            // \u5f80\u540c\u4e00 row \u7684\u4e0b\u4e00\u500b\uff08r-1\uff09\u63a8\u9032\n            if (r > l) {\n                int nr = r - 1;\n                int nv = rmq.value(l, nr);\n                pq.push({nv, {l, nr}});\n            }\n        }\n        return ans;\n    }\n};\n"},{"key":"problem:problems/2400-2599-grandmaster/2014.longest-subsequence-repeated-k-times.cpp","id":2014,"qid":"2014","title":"Longest Subsequence Repeated K Times","kebab":"longest-subsequence-repeated-k-times","rating":2558.3,"ratingLabel":"2558.3","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"problems/2400-2599-grandmaster/2014.longest-subsequence-repeated-k-times.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-subsequence-repeated-k-times/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/2400-2599-grandmaster/2014.longest-subsequence-repeated-k-times.cpp","code":"/*\n * @lc app=leetcode id=2014 lang=cpp\n *\n * [2014] Longest Subsequence Repeated k Times\n *\n * https://leetcode.com/problems/longest-subsequence-repeated-k-times/description/\n *\n * Category: algorithms\n * Difficulty: Hard\n *\n * You are given a string s of length n, and an integer k. You are tasked to\n * find the longest subsequence repeated k times in string s.\n * \n * A subsequence is a string that can be derived from another string by\n * deleting some or no characters without changing the order of the remaining\n * characters.\n * \n * A subsequence seq is repeated k times in the string s if seq * k is a\n * subsequence of s, where seq * k represents a string constructed by\n * concatenating seq k times.\n * \n * \n * For example, \"bba\" is repeated 2 times in the string \"bababcba\", because the\n * string \"bbabba\", constructed by concatenating \"bba\" 2 times, is a\n * subsequence of the string \"bababcba\".\n * \n * \n * Return the longest subsequence repeated k times in string s. If multiple\n * such subsequences are found, return the lexicographically largest one. If\n * there is no such subsequence, return an empty string.\n * \n * \n * Example 1:\n * \n * \n * Input: s = \"letsleetcode\", k = 2\n * Output: \"let\"\n * Explanation: There are two longest subsequences repeated 2 times: \"let\" and\n * \"ete\".\n * \"let\" is the lexicographically largest one.\n * \n * \n * Example 2:\n * \n * \n * Input: s = \"bb\", k = 2\n * Output: \"b\"\n * Explanation: The longest subsequence repeated 2 times is \"b\".\n * \n * \n * Example 3:\n * \n * \n * Input: s = \"ab\", k = 2\n * Output: \"\"\n * Explanation: There is no subsequence repeated 2 times. Empty string is\n * returned.\n * \n * \n * \n * Constraints:\n * \n * \n * n == s.length\n * 2 <= k <= 2000\n * 2 <= n < min(2001, k * 8)\n * s consists of lowercase English letters.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    string res;\n\n    bool repeat(string& s, string &pat, int k) {\n        if(pat.empty()) return true;\n\n        int cnt = 0, pos = 0;\n\n        for(char c : s) {\n            if(c == pat[pos]) {\n                pos = (pos + 1) % pat.length();\n                if(pos == 0) {\n                    cnt++;\n                    if(cnt == k) return true;\n                }\n            }\n        }\n        return false;\n    }\n\n    void back(string& s, int k, string cur) {\n        if(cur.length() >= res.length()) {\n            res = max(res, cur);\n            // return;\n        }\n\n        for (char c = 'a'; c <= 'z'; c++) {\n            cur.push_back(c);\n            if(repeat(s, cur, k)) back(s, k, cur);\n            cur.pop_back();\n        }\n    }\n\n    string longestSubsequenceRepeatedK(string s, int k) {\n        vector<int> cnt(26, 0);\n        for(char c : s) {\n            cnt[c - 'a']++;\n        }\n        string temp;\n        for(char c : s) {\n            if(cnt[c - 'a'] >= k) {\n                temp += c;\n            }\n        }\n        s = temp;\n        res = \"\";\n        back(s, k, res);\n        return res;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/unrated/75.sort-colors.cpp","id":75,"qid":"75","title":"Sort Colors","kebab":"sort-colors","rating":null,"ratingLabel":"-","tier":"Unrated","tierSlug":"unrated","tierLabel":"Unrated","path":"problems/unrated/75.sort-colors.cpp","leetcodeUrl":"https://leetcode.com/problems/sort-colors/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/unrated/75.sort-colors.cpp","code":"class Solution {\npublic:\n    void sortColors(vector<int>& nums) {\n        int a = 0, b = 0, c = 0;\n        for(auto& x : nums) {\n            if(x == 0) a++;\n            else if(x == 1) b++;\n            else c++;\n        }\n        int i=0;\n        for(int j=0; j<a; j++, i++) nums[i] = 0;\n        for(int j=0; j<b; j++, i++) nums[i] = 1;\n        for(int j=0; j<c; j++, i++) nums[i] = 2;\n    }\n};\n"},{"key":"problem:problems/unrated/78.subsets.cpp","id":78,"qid":"78","title":"Subsets","kebab":"subsets","rating":null,"ratingLabel":"-","tier":"Unrated","tierSlug":"unrated","tierLabel":"Unrated","path":"problems/unrated/78.subsets.cpp","leetcodeUrl":"https://leetcode.com/problems/subsets/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/unrated/78.subsets.cpp","code":"/*\n * @lc app=leetcode id=78 lang=cpp\n *\n * [78] Subsets\n *\n * https://leetcode.com/problems/subsets/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given an integer array nums of unique elements, return all possible subsets\n * (the power set).\n * \n * The solution set must not contain duplicate subsets. Return the solution in\n * any order.\n * \n * \n * Example 1:\n * \n * \n * Input: nums = [1,2,3]\n * Output: [[],[1],[2],[1,2],[3],[1,3],[2,3],[1,2,3]]\n * \n * \n * Example 2:\n * \n * \n * Input: nums = [0]\n * Output: [[],[0]]\n * \n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 10\n * -10 <= nums[i] <= 10\n * All the numbers of\u00a0nums are unique.\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<vector<int>> ans;\n    \n    void back(vector<int>& nums, vector<int>& cur, int i) {\n        if(i == nums.size()) {\n            ans.push_back(cur);\n            return;\n        }\n        \n        back(nums, cur, i + 1);\n        cur.push_back(nums[i]);\n        back(nums, cur, i + 1);\n        cur.pop_back();\n    }\n\n    vector<vector<int>> subsets(vector<int>& nums) {\n        vector<int> cur;\n        back(nums, cur, 0);\n        return ans;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/unrated/90.subsets-ii.cpp","id":90,"qid":"90","title":"Subsets II","kebab":"subsets-ii","rating":null,"ratingLabel":"-","tier":"Unrated","tierSlug":"unrated","tierLabel":"Unrated","path":"problems/unrated/90.subsets-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/subsets-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/unrated/90.subsets-ii.cpp","code":"/*\n * @lc app=leetcode id=90 lang=cpp\n *\n * [90] Subsets II\n *\n * https://leetcode.com/problems/subsets-ii/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * Given an integer array nums that may contain duplicates, return all possible\n * subsets (the power set).\n * \n * The solution set must not contain duplicate subsets. Return the solution in\n * any order.\n * \n * \n * Example 1:\n * Input: nums = [1,2,2]\n * Output: [[],[1],[1,2],[1,2,2],[2],[2,2]]\n * Example 2:\n * Input: nums = [0]\n * Output: [[],[0]]\n * \n * \n * Constraints:\n * \n * \n * 1 <= nums.length <= 10\n * -10 <= nums[i] <= 10\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<vector<int>> ans;\n    \n    void back(vector<int>& cur, vector<int>& cnt, int index) {\n        ans.push_back(cur);\n\n        for(int i=index; i<21; i++) {\n            if(cnt[i] == 0) continue;\n\n            cur.push_back(i - 10);\n            cnt[i]--;\n            back(cur, cnt, i);\n\n            cnt[i]++;\n            cur.pop_back();\n            // back(cur, cnt);\n        }\n    }\n\n    vector<vector<int>> subsetsWithDup(vector<int>& nums) {\n        vector<int> cnt(21, 0);\n        for(int i=0; i<nums.size(); i++) {\n            cnt[nums[i] + 10]++;\n        }\n\n        vector<int> cur;\n        back(cur, cnt, 0);\n        return ans;\n    }\n};\n// @lc code=end\n"},{"key":"problem:problems/unrated/735.asteroid-collision.cpp","id":735,"qid":"735","title":"Asteroid Collision","kebab":"asteroid-collision","rating":null,"ratingLabel":"-","tier":"Unrated","tierSlug":"unrated","tierLabel":"Unrated","path":"problems/unrated/735.asteroid-collision.cpp","leetcodeUrl":"https://leetcode.com/problems/asteroid-collision/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/problems/unrated/735.asteroid-collision.cpp","code":"/*\n * @lc app=leetcode id=735 lang=cpp\n *\n * [735] Asteroid Collision\n *\n * https://leetcode.com/problems/asteroid-collision/description/\n *\n * Category: algorithms\n * Difficulty: Medium\n *\n * We are given an array asteroids of integers representing asteroids in a row.\n * The indices of the asteriod in the array represent their relative position\n * in space.\n * \n * For each asteroid, the absolute value represents its size, and the sign\n * represents its direction (positive meaning right, negative meaning left).\n * Each asteroid moves at the same speed.\n * \n * Find out the state of the asteroids after all collisions. If two asteroids\n * meet, the smaller one will explode. If both are the same size, both will\n * explode. Two asteroids moving in the same direction will never meet.\n * \n * \n * Example 1:\n * \n * \n * Input: asteroids = [5,10,-5]\n * Output: [5,10]\n * Explanation: The 10 and -5 collide resulting in 10. The 5 and 10 never\n * collide.\n * \n * \n * Example 2:\n * \n * \n * Input: asteroids = [8,-8]\n * Output: []\n * Explanation: The 8 and -8 collide exploding each other.\n * \n * \n * Example 3:\n * \n * \n * Input: asteroids = [10,2,-5]\n * Output: [10]\n * Explanation: The 2 and -5 collide resulting in -5. The 10 and -5 collide\n * resulting in 10.\n * \n * \n * \n * Constraints:\n * \n * \n * 2 <= asteroids.length <= 10^4\n * -1000 <= asteroids[i] <= 1000\n * asteroids[i] != 0\n * \n * \n */\n\n// @lc code=start\nclass Solution {\npublic:\n    vector<int> asteroidCollision(vector<int>& asteroids) {\n        vector<int> res;\n        for (int a : asteroids) {\n            bool destroyed = false;\n            // \u6aa2\u67e5\u7576\u524d\u5c0f\u884c\u661f a \u662f\u5426\u6703\u8207 res \u4e2d\u6700\u5f8c\u4e00\u9846\u53f3\u79fb\u5c0f\u884c\u661f\u78b0\u649e\n            while (!res.empty() && a < 0 && res.back() > 0) {\n                if (res.back() < -a) {\n                    // res \u6700\u5f8c\u4e00\u9846\u5c0f\u884c\u661f\u6bd4 a \u5c0f\uff0c\u88ab\u649e\u788e\uff0c\u7e7c\u7e8c\u6aa2\u67e5\u524d\u4e00\u9846\n                    res.pop_back();\n                    continue;\n                } \n                else if (res.back() == -a) {\n                    // \u76f8\u7b49\uff0c\u5169\u9846\u90fd\u7206\u70b8\n                    res.pop_back();\n                }\n                // a \u88ab\u649e\u788e\n                destroyed = true;\n                break;\n            }\n            if (!destroyed) res.push_back(a);\n        }\n        return res;\n    }\n};\n// @lc code=end\n"}],"contests":[{"key":"contest:contests/biweekly163/3648.minimum-sensors-to-cover-grid.cpp","id":3648,"qid":"3648","title":"Minimum Sensors To Cover Grid","kebab":"minimum-sensors-to-cover-grid","rating":1396.0,"ratingLabel":"1396.0","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/biweekly163/3648.minimum-sensors-to-cover-grid.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-sensors-to-cover-grid/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly163/3648.minimum-sensors-to-cover-grid.cpp","code":"class Solution {\npublic:\n    int minSensors(int n, int m, int k) {\n        k = k * 2 + 1;\n        int N = (n % k == 0) ? n / k : n / k + 1;\n        int M = (m % k == 0) ? m / k : m / k + 1;\n\n        return N * M;\n    }\n};\n","contest":"biweekly163","contestType":"biweekly","contestNumber":163,"contestUrl":"https://leetcode.com/contest/biweekly-contest-163/"},{"key":"contest:contests/biweekly163/3649.number-of-perfect-pairs.cpp","id":3649,"qid":"3649","title":"Number Of Perfect Pairs","kebab":"number-of-perfect-pairs","rating":1715.6,"ratingLabel":"1715.6","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/biweekly163/3649.number-of-perfect-pairs.cpp","leetcodeUrl":"https://leetcode.com/problems/number-of-perfect-pairs/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly163/3649.number-of-perfect-pairs.cpp","code":"class Solution {\npublic:\n    long long perfectPairs(vector<int>& nums) {\n        long long res = 0;\n        vector<long long> pos;\n        for(auto& i : nums) {\n            if(i == 0) res++;\n            else pos.push_back(abs(i));\n        }\n        \n        res = res * (res - 1) / 2;\n        sort(pos.begin(), pos.end());\n\n        int l=0, r=0;\n        for(r-0; r<pos.size(); r++) {\n            while(l < r && pos[l] * 2 < pos[r]) l++;\n            res += (r - l);\n        }\n        return res;\n    }\n};\n","contest":"biweekly163","contestType":"biweekly","contestNumber":163,"contestUrl":"https://leetcode.com/contest/biweekly-contest-163/"},{"key":"contest:contests/biweekly163/3650.minimum-cost-path-with-edge-reversals.cpp","id":3650,"qid":"3650","title":"Minimum Cost Path With Edge Reversals","kebab":"minimum-cost-path-with-edge-reversals","rating":1853.7,"ratingLabel":"1853.7","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/biweekly163/3650.minimum-cost-path-with-edge-reversals.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-cost-path-with-edge-reversals/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly163/3650.minimum-cost-path-with-edge-reversals.cpp","code":"class Solution {\npublic:\n    int minCost(int n, vector<vector<int>>& edges) {\n        vector<vector<pair<int,int>>> g(n);\n        for (auto &e : edges) {\n            int u = e[0], v = e[1], w = e[2];\n            g[u].push_back({v, w});\n            g[v].push_back({u, 2 * w});\n        }\n        \n        const long long INF = (1LL<<62);\n        vector<long long> dist(n, INF);\n        priority_queue<pair<long long,int>, vector<pair<long long,int>>, greater<pair<long long,int>>> pq;\n\n        dist[0] = 0;\n        pq.push({0, 0});\n\n        while (!pq.empty()) {\n            auto [d, u] = pq.top();\n            pq.pop();\n            \n            if (d != dist[u]) continue;\n            if (u == n - 1) break;\n\n            for (auto [v, w] : g[u]) {\n                long long nd = d + w;\n                if (nd < dist[v]) {\n                    dist[v] = nd;\n                    pq.push({nd, v});\n                }\n            }\n        }\n\n        return dist[n-1] == INF ? -1 : dist[n-1];\n    }\n};\n","contest":"biweekly163","contestType":"biweekly","contestNumber":163,"contestUrl":"https://leetcode.com/contest/biweekly-contest-163/"},{"key":"contest:contests/biweekly163/3651.minimum-cost-path-with-teleportations.cpp","id":3651,"qid":"3651","title":"Minimum Cost Path With Teleportations","kebab":"minimum-cost-path-with-teleportations","rating":2411.2,"ratingLabel":"2411.2","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"contests/biweekly163/3651.minimum-cost-path-with-teleportations.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-cost-path-with-teleportations/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly163/3651.minimum-cost-path-with-teleportations.cpp","code":"class Solution {\npublic:\n    int minCost(vector<vector<int>>& g, int k) {\n        const long long INF = (1LL << 62);\n\n        int m = g.size(), n = g[0].size();\n\n        \n    }\n};\n\n// NOT FINISHED\n","contest":"biweekly163","contestType":"biweekly","contestNumber":163,"contestUrl":"https://leetcode.com/contest/biweekly-contest-163/"},{"key":"contest:contests/biweekly165/3678.smallest-absent-positive-greater-than-average.cpp","id":3678,"qid":"3678","title":"Smallest Absent Positive Greater Than Average","kebab":"smallest-absent-positive-greater-than-average","rating":1306.1,"ratingLabel":"1306.1","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/biweekly165/3678.smallest-absent-positive-greater-than-average.cpp","leetcodeUrl":"https://leetcode.com/problems/smallest-absent-positive-greater-than-average/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly165/3678.smallest-absent-positive-greater-than-average.cpp","code":"class Solution {\npublic:\n    int smallestAbsent(vector<int>& nums) {\n        sort(nums.begin(), nums.end());\n        int sum = 0;\n        set<int> s;\n        for(auto& i : nums) {\n            sum += i;\n            s.insert(i);\n        }\n        int avg = sum / nums.size();\n        int i = (nums[0] < 1) ? 1 : nums[0];\n        // cout << sum << endl;\n        while(sum > 0 && i <= avg) i++;\n        // cout << i << endl;\n        while(s.count(i)) i++;\n        return i;\n    }\n};\n","contest":"biweekly165","contestType":"biweekly","contestNumber":165,"contestUrl":"https://leetcode.com/contest/biweekly-contest-165/"},{"key":"contest:contests/biweekly165/3679.minimum-discards-to-balance-inventory.cpp","id":3679,"qid":"3679","title":"Minimum Discards To Balance Inventory","kebab":"minimum-discards-to-balance-inventory","rating":1638.9,"ratingLabel":"1638.9","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/biweekly165/3679.minimum-discards-to-balance-inventory.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-discards-to-balance-inventory/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly165/3679.minimum-discards-to-balance-inventory.cpp","code":"class Solution {\npublic:\n    int minArrivalsToDiscard(vector<int>& arrivals, int w, int m) {\n        int res = 0;\n        unordered_map<int, int> mp;\n        vector<int> kpt(arrivals.size(), 1);\n        for(int i=0; i<arrivals.size(); i++) {\n            if(i-w >= 0 && kpt[i-w]) {\n                mp[arrivals[i-w]]--;\n            }\n            mp[arrivals[i]]++;\n            // cout << mp[3] << endl;\n            // if(i >= w) {\n            if(mp[arrivals[i]] > m) {\n                mp[arrivals[i]]--;\n                res++;\n                kpt[i] = 0;\n            }\n            // }\n        }\n        return res;\n    }\n};\n","contest":"biweekly165","contestType":"biweekly","contestNumber":165,"contestUrl":"https://leetcode.com/contest/biweekly-contest-165/"},{"key":"contest:contests/biweekly165/3680.generate-schedule.cpp","id":3680,"qid":"3680","title":"Generate Schedule","kebab":"generate-schedule","rating":2377.9,"ratingLabel":"2377.9","tier":"International Master","tierSlug":"2300-2399-international-master","tierLabel":"2300-2399","path":"contests/biweekly165/3680.generate-schedule.cpp","leetcodeUrl":"https://leetcode.com/problems/generate-schedule/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly165/3680.generate-schedule.cpp","code":"class Solution {\npublic:\n    vector<vector<int>> res;\n    bool dfs(vector<vector<int>>& all, vector<vector<int>>& gm, int cur) {\n        if(cur == all.size()) {\n            res = gm;\n            return true;\n        }\n\n        for(int i=0; i<all.size(); i++) {\n            if(all[i][2]) continue;\n\n            if(cur>0 && (all[i][0] == gm[cur-1][0] || all[i][0] == gm[cur-1][1])) continue;\n            if(cur>0 && (all[i][1] == gm[cur-1][0] || all[i][1] == gm[cur-1][1])) continue;\n\n            all[i][2] = 1;\n            gm[cur][0] = all[i][0];\n            gm[cur][1] = all[i][1];\n            if(dfs(all, gm, cur+1)) return true;\n\n            all[i][2] = 0;\n        }\n        return false;\n    }\n    vector<vector<int>> generateSchedule(int n) {\n        vector<vector<int>> all;\n        for(int i=0; i<n; i++) {\n            for(int j=0; j<n; j++) {\n                if(i == j) continue;\n                all.push_back({i, j, 0});\n            }\n        }\n        // cout << all.size() << endl;\n\n        vector<vector<int>> gm(all.size(), vector<int>(2, -1));\n        gm[0] = {all[0][0], all[0][1]};\n        all[0][2] = 1;\n        res = {{}};\n        if(dfs(all, gm, 1)) return gm;\n        else return {};\n\n        return res;\n    }\n};\n","contest":"biweekly165","contestType":"biweekly","contestNumber":165,"contestUrl":"https://leetcode.com/contest/biweekly-contest-165/"},{"key":"contest:contests/biweekly165/3681.maximum-xor-of-subsequences.cpp","id":3681,"qid":"3681","title":"Maximum Xor Of Subsequences","kebab":"maximum-xor-of-subsequences","rating":2026.8,"ratingLabel":"2026.8","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/biweekly165/3681.maximum-xor-of-subsequences.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-xor-of-subsequences/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly165/3681.maximum-xor-of-subsequences.cpp","code":"class Solution {\npublic:\n    int maxXorSubsequences(vector<int>& nums) {\n        vector<int> bs(32);\n        for(int x : nums) {\n            int v = x;\n            for(int b=31; b>=0; b--) {\n                if(((v >> b) & 1) == 0) continue;\n                if(bs[b] == 0) {\n                    bs[b] = v;\n                    break;\n                }\n                v ^= bs[b];\n            }\n        }\n\n        int res = 0;\n        for(int b = 31; b>=0; b--) {\n            if((res ^ bs[b]) > res) res ^= bs[b];\n        }\n        return res;\n    }\n};\n","contest":"biweekly165","contestType":"biweekly","contestNumber":165,"contestUrl":"https://leetcode.com/contest/biweekly-contest-165/"},{"key":"contest:contests/biweekly166/3692.majority-frequency-characters.cpp","id":3692,"qid":"3692","title":"Majority Frequency Characters","kebab":"majority-frequency-characters","rating":1384.4,"ratingLabel":"1384.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/biweekly166/3692.majority-frequency-characters.cpp","leetcodeUrl":"https://leetcode.com/problems/majority-frequency-characters/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly166/3692.majority-frequency-characters.cpp","code":"# include <bits/stdc++.h>\nusing namespace std;\n\nclass Solution {\npublic:\n    string majorityFrequencyGroup(string s) {\n        vector<int> arr(26, 0);\n        for(int i=0; i<s.size(); i++) {\n            arr[s[i] - 'a']++;\n        }\n        \n        unordered_map<char, int> mp;\n        for(int i=0; i<26; i++) {\n            if (arr[i] > 0) mp[arr[i]]++;\n        }\n\n        int bestK = 0;\n        int bestSize = -1;\n        for (const auto &p : mp) {\n            int k = p.first, sz = p.second;\n            if (sz > bestSize || (sz == bestSize && k > bestK)) {\n                bestSize = sz;\n                bestK = k;\n            }\n        }\n\n        string ans;\n        for (int i = 0; i < 26; ++i) {\n            if (arr[i] == bestK) ans.push_back('a' + i);\n        }\n        return ans;\n    }\n};\n","contest":"biweekly166","contestType":"biweekly","contestNumber":166,"contestUrl":"https://leetcode.com/contest/biweekly-contest-166/"},{"key":"contest:contests/biweekly166/3693.climbing-stairs-ii.cpp","id":3693,"qid":"3693","title":"Climbing Stairs II","kebab":"climbing-stairs-ii","rating":1560.3,"ratingLabel":"1560.3","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"contests/biweekly166/3693.climbing-stairs-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/climbing-stairs-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly166/3693.climbing-stairs-ii.cpp","code":"# include <bits/stdc++.h>\nusing namespace std;\n\nclass Solution {\npublic:\n    int climbStairs(int n, vector<int>& costs) {\n        vector<int> res(n+1, INT_MAX);\n        res[0] = 0;\n        for(int i=0; i<n; i++) {\n            if(i >= 0) {\n                res[i+1] = min(res[i+1], res[i] + costs[i] + 1);\n            }\n            if(i-1 >= 0) {\n                res[i+1] = min(res[i+1], res[i-1] + costs[i] + 4);\n            }\n            if(i-2 >= 0) {\n                res[i+1] = min(res[i+1], res[i-2] + costs[i] + 9);\n            }\n        }\n        return res[n];\n    }\n};\n","contest":"biweekly166","contestType":"biweekly","contestNumber":166,"contestUrl":"https://leetcode.com/contest/biweekly-contest-166/"},{"key":"contest:contests/biweekly166/3694.distinct-points-reachable-after-substring-removal.cpp","id":3694,"qid":"3694","title":"Distinct Points Reachable After Substring Removal","kebab":"distinct-points-reachable-after-substring-removal","rating":1739.3,"ratingLabel":"1739.3","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/biweekly166/3694.distinct-points-reachable-after-substring-removal.cpp","leetcodeUrl":"https://leetcode.com/problems/distinct-points-reachable-after-substring-removal/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly166/3694.distinct-points-reachable-after-substring-removal.cpp","code":"# include <bits/stdc++.h>\nusing namespace std;\n\nclass Solution {\npublic:\n    int distinctPoints(string s, int k) {\n        set<vector<int>> g;\n\n        int x = 0, y = 0;\n        for(int i=k; i<s.size(); i++) {\n            if(s[i] == 'U') y++;\n            else if(s[i] == 'D') y--;\n            else if(s[i] == 'L') x--;\n            else if(s[i] == 'R') x++;\n        }\n\n        g.insert({x, y});\n\n        for(int i=0, j=k; j<s.size(); i++, j++) {\n            if(s[i] == 'U') y++;\n            else if(s[i] == 'D') y--;\n            else if(s[i] == 'L') x--;\n            else if(s[i] == 'R') x++;\n\n            if(s[j] == 'U') y--;\n            else if(s[j] == 'D') y++;\n            else if(s[j] == 'L') x++;\n            else if(s[j] == 'R') x--;\n\n            g.insert({x, y});\n        }\n\n        return g.size();\n    }\n};\n","contest":"biweekly166","contestType":"biweekly","contestNumber":166,"contestUrl":"https://leetcode.com/contest/biweekly-contest-166/"},{"key":"contest:contests/biweekly166/3695.maximize-alternating-sum-using-swaps.cpp","id":3695,"qid":"3695","title":"Maximize Alternating Sum Using Swaps","kebab":"maximize-alternating-sum-using-swaps","rating":1984.2,"ratingLabel":"1984.2","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/biweekly166/3695.maximize-alternating-sum-using-swaps.cpp","leetcodeUrl":"https://leetcode.com/problems/maximize-alternating-sum-using-swaps/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly166/3695.maximize-alternating-sum-using-swaps.cpp","code":"# include <bits/stdc++.h>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> p, r;\n\n    int find(int x) {\n        if(p[x] == x) return x;\n        return p[x] = find(p[x]);\n    }\n\n    void unite(int a, int b) {\n        a = find(a), b = find(b);\n        if(a == b) return;\n        if(r[a] < r[b]) swap(a, b);\n        p[b] = a;\n        if(r[a] == r[b]) r[a]++;\n    }\n    \n    long long maxAlternatingSum(vector<int>& nums, vector<vector<int>>& swaps) {\n        int n = nums.size();\n        p.resize(n);\n        r.assign(n, 0);\n        iota(p.begin(), p.end(), 0);\n\n        for(auto& e : swaps) unite(e[0], e[1]);\n\n        unordered_map<int, vector<int>> comp;\n        comp.reserve(n*2);\n        for(int i=0; i<n; i++) comp[find(i)].push_back(i);\n\n        long long res = 0;\n        vector<long long> vals;\n        vals.reserve(n);\n\n        for(auto& kv : comp) {\n            const auto &idxs = kv.second;\n            vals.clear();\n            int k_even = 0;\n            for(int i : idxs) {\n                vals.push_back(nums[i]);\n                if((i&1) == 0) k_even++;\n            }\n            sort(vals.begin(), vals.end(), greater<long long>());\n\n            long long sumTopK = 0, sumRest = 0;\n            for(int i=0; i<vals.size(); i++) {\n                (i < k_even ? sumTopK : sumRest) += vals[i];\n            }\n\n            res += (sumTopK - sumRest);\n        }\n\n        return res;\n    }\n};\n","contest":"biweekly166","contestType":"biweekly","contestNumber":166,"contestUrl":"https://leetcode.com/contest/biweekly-contest-166/"},{"key":"contest:contests/biweekly167/3707.equal-score-substrings.cpp","id":3707,"qid":"3707","title":"Equal Score Substrings","kebab":"equal-score-substrings","rating":1262.4,"ratingLabel":"1262.4","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/biweekly167/3707.equal-score-substrings.cpp","leetcodeUrl":"https://leetcode.com/problems/equal-score-substrings/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly167/3707.equal-score-substrings.cpp","code":"class Solution {\npublic:\n    bool scoreBalance(string s) {\n        int all = 0;\n        for(auto& i : s) {\n            all += (i - 'a') + 1;\n        }\n        int half = 0;\n        for(auto& i : s) {\n            half += (i - 'a') + 1;\n            if(half == all - half) return true;\n        }\n        return false;\n    }\n};\n","contest":"biweekly167","contestType":"biweekly","contestNumber":167,"contestUrl":"https://leetcode.com/contest/biweekly-contest-167/"},{"key":"contest:contests/biweekly167/3708.longest-fibonacci-subarray.cpp","id":3708,"qid":"3708","title":"Longest Fibonacci Subarray","kebab":"longest-fibonacci-subarray","rating":1380.9,"ratingLabel":"1380.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/biweekly167/3708.longest-fibonacci-subarray.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-fibonacci-subarray/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly167/3708.longest-fibonacci-subarray.cpp","code":"class Solution {\npublic:\n    int longestSubarray(vector<int>& nums) {\n        if(nums.size() == 1) return true;\n        if(nums.size() == 2) return true;\n\n        int res = 0, cur = 0;\n        for(int i=0; i+2<nums.size(); i++) {\n            if(nums[i+2] == nums[i] + nums[i+1]) cur ++;\n            else cur = 0;\n            res = max(res, cur+2);\n        }\n        return res;\n    }\n};\n","contest":"biweekly167","contestType":"biweekly","contestNumber":167,"contestUrl":"https://leetcode.com/contest/biweekly-contest-167/"},{"key":"contest:contests/biweekly167/3709.design-exam-scores-tracker.cpp","id":3709,"qid":"3709","title":"Design Exam Scores Tracker","kebab":"design-exam-scores-tracker","rating":1647.5,"ratingLabel":"1647.5","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/biweekly167/3709.design-exam-scores-tracker.cpp","leetcodeUrl":"https://leetcode.com/problems/design-exam-scores-tracker/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly167/3709.design-exam-scores-tracker.cpp","code":"class ExamTracker {\npublic:\n    vector<int> t;\n    vector<long long> prefix;\n    \n    ExamTracker() {\n            \n    }\n    \n    void record(int time, int score) {\n        t.push_back(time);\n\n        if(prefix.empty()) prefix.push_back(score);\n        else prefix.push_back(prefix.back() + score);\n    }\n    \n    long long totalScore(int startTime, int endTime) {\n        int L = lower_bound(t.begin(), t.end(), startTime) - t.begin();\n        int R = upper_bound(t.begin(), t.end(), endTime) - t.begin();\n\n        if(L >= R) return 0;\n\n        long long total = prefix[R - 1];\n        if(L > 0) total -= prefix[L - 1];\n\n        return total;\n    }\n};\n\n/**\n * Your ExamTracker object will be instantiated and called as such:\n * ExamTracker* obj = new ExamTracker();\n * obj->record(time,score);\n * long long param_2 = obj->totalScore(startTime,endTime);\n */\n","contest":"biweekly167","contestType":"biweekly","contestNumber":167,"contestUrl":"https://leetcode.com/contest/biweekly-contest-167/"},{"key":"contest:contests/biweekly167/3710.maximum-partition-factor.cpp","id":3710,"qid":"3710","title":"Maximum Partition Factor","kebab":"maximum-partition-factor","rating":2135.1,"ratingLabel":"2135.1","tier":"Master","tierSlug":"2100-2299-master","tierLabel":"2100-2299","path":"contests/biweekly167/3710.maximum-partition-factor.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-partition-factor/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/biweekly167/3710.maximum-partition-factor.cpp","code":"class Solution {\npublic:\n    bool ok(vector<vector<long long>> &d, long long D) {\n        int n = d.size();\n        vector<vector<int>> adj(n);\n        for(int i=0; i<n; i++) {\n            for(int j=i+1; j<n; j++) {\n                if(d[i][j] < D) {\n                    adj[i].push_back(j);\n                    adj[j].push_back(i);\n                }\n            }\n        }\n\n        vector<int> c(n, -1);\n        for(int i=0; i<n; i++) {\n            if(c[i] == -1) {\n                queue<int> q;\n                q.push(i);\n                c[i] = 0;\n                while(!q.empty()) {\n                    int u = q.front(); q.pop();\n                    for(int v : adj[u]) {\n                        if(c[v] == -1) {\n                            c[v] = c[u] ^ 1;\n                            q.push(v);\n                        }\n                        else if(c[v] == c[u]) return false;\n                    }\n                }\n            }\n        }\n        return true;\n    }\n    \n    int maxPartitionFactor(vector<vector<int>>& p) {\n        int n = p.size();\n        if(n == 2) return 0;\n        \n        vector<vector<long long>> d(n, vector<long long>(n, 0));\n        set<long long> L;\n        \n        for(int i=0; i<n; i++) {\n            for(int j=i+1; j<n; j++) {\n                d[i][j] = llabs((long long)p[i][0] - p[j][0]) +  llabs((long long)p[i][1] - p[j][1]);\n                L.insert(d[i][j]);\n            }\n        }\n        vector<long long> list(L.begin(), L.end());\n\n        long long lo=0, hi=list.size()-1, mid;\n        long long res = 0;\n        vector<int> uf;\n        while(lo <= hi) {\n            mid = (lo + hi) / 2;\n\n            if(ok(d, list[mid])) {\n                res = list[mid];\n                lo = mid + 1;\n            }\n            else {\n                hi = mid - 1;\n            }\n        }\n        return res;\n    }\n};\n","contest":"biweekly167","contestType":"biweekly","contestNumber":167,"contestUrl":"https://leetcode.com/contest/biweekly-contest-167/"},{"key":"contest:contests/weekly463/3652.best-time-to-buy-and-sell-stock-using-strategy.cpp","id":3652,"qid":"3652","title":"Best Time To Buy And Sell Stock Using Strategy","kebab":"best-time-to-buy-and-sell-stock-using-strategy","rating":1556.8,"ratingLabel":"1556.8","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"contests/weekly463/3652.best-time-to-buy-and-sell-stock-using-strategy.cpp","leetcodeUrl":"https://leetcode.com/problems/best-time-to-buy-and-sell-stock-using-strategy/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly463/3652.best-time-to-buy-and-sell-stock-using-strategy.cpp","code":"class Solution {\npublic:\nlong long maxProfit(vector<int>& p, vector<int>& s, int k) {\n    int n = p.size();\n    vector<long long> prefA(n + 1, 0), prefP(n + 1, 0);\n\n    long long base = 0;\n    for (int i = 0; i < n; ++i) {\n        long long A = 1LL * p[i] * s[i];\n        base += A;\n        prefA[i + 1] = prefA[i] + A;\n        prefP[i + 1] = prefP[i] + p[i];\n    }\n\n    int len = k / 2;\n    long long res = base;\n\n    for (int i = 0; i + k <= n; ++i) {\n        long long sumA_window  = prefA[i + k] - prefA[i];\n        long long sumP_second  = prefP[i + k] - prefP[i + len];\n        long long cand = base - sumA_window + sumP_second;\n        if (cand > res) res = cand;\n    }\n    return res;\n}\n\n};\n","contest":"weekly463","contestType":"weekly","contestNumber":463,"contestUrl":"https://leetcode.com/contest/weekly-contest-463/"},{"key":"contest:contests/weekly463/3653.xor-after-range-multiplication-queries-i.cpp","id":3653,"qid":"3653","title":"Xor After Range Multiplication Queries I","kebab":"xor-after-range-multiplication-queries-i","rating":1556.3,"ratingLabel":"1556.3","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"contests/weekly463/3653.xor-after-range-multiplication-queries-i.cpp","leetcodeUrl":"https://leetcode.com/problems/xor-after-range-multiplication-queries-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly463/3653.xor-after-range-multiplication-queries-i.cpp","code":"class Solution {\npublic:\n    int xorAfterQueries(vector<int>& nums, vector<vector<int>>& q) {\n        long long res = 0;\n        // for(auto& i : nums) res ^= i;\n        for(int i=0; i<q.size(); i++) {\n            long long l = q[i][0];\n            long long r = q[i][1];\n            long long k = q[i][2];\n            long long v = q[i][3];\n            // if((r - l) % k == 0) {\n            //     res ^= v;\n            // }\n            // long long V = 1;\n            while(l <= r) {\n                // V = (V * v) % 1000000007;\n                long long temp = nums[l];\n                temp *= v;\n                temp %= 1000000007;\n                nums[l] = temp;\n                l += k;\n            }\n            // res ^= V;\n        }\n        // for(auto& i : nums) cout << i << ' ';\n        // cout << endl;\n        for(auto& i : nums) res ^= i;\n        return res;\n    }\n};\n","contest":"weekly463","contestType":"weekly","contestNumber":463,"contestUrl":"https://leetcode.com/contest/weekly-contest-463/"},{"key":"contest:contests/weekly463/3654.minimum-sum-after-divisible-sum-deletions.cpp","id":3654,"qid":"3654","title":"Minimum Sum After Divisible Sum Deletions","kebab":"minimum-sum-after-divisible-sum-deletions","rating":2038.8,"ratingLabel":"2038.8","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/weekly463/3654.minimum-sum-after-divisible-sum-deletions.cpp","leetcodeUrl":"https://leetcode.com/problems/minimum-sum-after-divisible-sum-deletions/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly463/3654.minimum-sum-after-divisible-sum-deletions.cpp","code":"class Solution {\npublic:\n    long long minArraySum(vector<int>& nums, int k) {\n        int n = nums.size();\n        vector<long long> prefix(n + 1, 0);\n        for (int i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];\n\n        long long total = prefix[n];\n        long long removed = 0;\n\n        vector<int> pos(k, -1);\n        vector<int> seen(k, 0);\n        int ver = 1;\n\n        pos[0] = -1;\n        seen[0] = ver;\n\n        int cur_mod = 0;\n\n        for (int i = 0; i < n; ++i) {\n            cur_mod = (cur_mod + nums[i]) % k;\n\n            if (seen[cur_mod] == ver) {\n                int L = pos[cur_mod] + 1;\n                int R = i;\n                removed += prefix[R + 1] - prefix[L];\n\n                ++ver;\n                if (ver == INT_MAX) {\n                    fill(seen.begin(), seen.end(), 0);\n                    ver = 1;\n                }\n                pos[0] = i;\n                seen[0] = ver;\n                cur_mod = 0;\n            } else {\n                pos[cur_mod] = i;\n                seen[cur_mod] = ver;\n            }\n        }\n\n        return total - removed;\n    }\n};\n\n// NOT FINISHED\n","contest":"weekly463","contestType":"weekly","contestNumber":463,"contestUrl":"https://leetcode.com/contest/weekly-contest-463/"},{"key":"contest:contests/weekly463/3655.xor-after-range-multiplication-queries-ii.cpp","id":3655,"qid":"3655","title":"Xor After Range Multiplication Queries II","kebab":"xor-after-range-multiplication-queries-ii","rating":2453.9,"ratingLabel":"2453.9","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"contests/weekly463/3655.xor-after-range-multiplication-queries-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/xor-after-range-multiplication-queries-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly463/3655.xor-after-range-multiplication-queries-ii.cpp","code":"class Solution {\npublic:\n    int xorAfterQueries(vector<int>& nums, vector<vector<int>>& q) {\n        long long res = 0;\n        map<int, multiset<int>> mp;\n        for(int i=0; i<q.size(); i++) {\n            long long l = q[i][0];\n            long long r = q[i][1];\n            long long k = q[i][2];\n            long long v = q[i][3];\n            while(l <= r) {\n                // long long temp = nums[l];\n                // temp *= v;\n                // temp %= 1000000007;\n                // nums[l] = temp;\n                mp[l].insert(v);\n                l += k;\n            }\n        }\n        for(auto& i : mp) {\n            int l = i.first;\n            multiset<int> s = i.second;\n            long long temp = 1;\n            for(auto& j : s) {\n                if(s.count(j) % 2 == 1) {\n                    temp *= j;\n                    temp %= 1000000007;\n                }\n            }\n            // cout << temp << endl;\n            temp = temp * nums[l];\n            temp %= 1000000007;\n            nums[l] = temp;\n        }\n        for(auto& i : nums) res ^= i;\n        return res;\n    }\n};\n\n// NOT FINISHED\n","contest":"weekly463","contestType":"weekly","contestNumber":463,"contestUrl":"https://leetcode.com/contest/weekly-contest-463/"},{"key":"contest:contests/weekly467/3683.earliest-time-to-finish-one-task.cpp","id":3683,"qid":"3683","title":"Earliest Time To Finish One Task","kebab":"earliest-time-to-finish-one-task","rating":1198.8,"ratingLabel":"1198.8","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"contests/weekly467/3683.earliest-time-to-finish-one-task.cpp","leetcodeUrl":"https://leetcode.com/problems/earliest-time-to-finish-one-task/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly467/3683.earliest-time-to-finish-one-task.cpp","code":"class Solution {\npublic:\n    int earliestTime(vector<vector<int>>& tasks) {\n        int res = tasks[0][0] + tasks[0][1];\n        for(int i=1; i<tasks.size(); i++) {\n            res = min(res,tasks[i][0] + tasks[i][1]);\n        }\n        return res;\n    }\n};\n","contest":"weekly467","contestType":"weekly","contestNumber":467,"contestUrl":"https://leetcode.com/contest/weekly-contest-467/"},{"key":"contest:contests/weekly467/3684.maximize-sum-of-at-most-k-distinct-elements.cpp","id":3684,"qid":"3684","title":"Maximize Sum Of At Most K Distinct Elements","kebab":"maximize-sum-of-at-most-k-distinct-elements","rating":1298.8,"ratingLabel":"1298.8","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/weekly467/3684.maximize-sum-of-at-most-k-distinct-elements.cpp","leetcodeUrl":"https://leetcode.com/problems/maximize-sum-of-at-most-k-distinct-elements/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly467/3684.maximize-sum-of-at-most-k-distinct-elements.cpp","code":"class Solution {\npublic:\n    vector<int> maxKDistinct(vector<int>& nums, int k) {\n        sort(nums.rbegin(), nums.rend());\n        vector<int> res;\n        res.push_back(nums[0]);\n        for(int i=1; i<nums.size(); i++) {\n            if(res.size() == k) break;\n            if(res.back() == nums[i]) continue;\n            res.push_back(nums[i]);\n        }\n        return res;\n    }\n};\n","contest":"weekly467","contestType":"weekly","contestNumber":467,"contestUrl":"https://leetcode.com/contest/weekly-contest-467/"},{"key":"contest:contests/weekly467/3685.subsequence-sum-after-capping-elements.cpp","id":3685,"qid":"3685","title":"Subsequence Sum After Capping Elements","kebab":"subsequence-sum-after-capping-elements","rating":2073.4,"ratingLabel":"2073.4","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/weekly467/3685.subsequence-sum-after-capping-elements.cpp","leetcodeUrl":"https://leetcode.com/problems/subsequence-sum-after-capping-elements/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly467/3685.subsequence-sum-after-capping-elements.cpp","code":"/* Upsolving */\n\nclass Solution {\npublic:\n    vector<bool> subsequenceSumAfterCapping(vector<int>& nums, int k) {\n        int n = nums.size();\n        sort(nums.begin(), nums.end());\n        vector<bool> sum(k+1, 0), res(n, 0);\n        sum[0] = 1;\n        \n        for(int i=0, x=1; x<=n; x++) {\n            while(i < n && nums[i] < x) {\n                for(int j=k; j>=nums[i]; j--) {\n                    if(sum[j - nums[i]]) sum[j] = 1;\n                }\n                i++;\n            }\n\n            int cap = n-i;\n            for(int j=0; j<=cap && j * x <= k; j++) {\n                if(sum[k - j * x]) {\n                    res[x-1] = 1;\n                    break;\n                }\n            }\n        }\n        return res;\n    }\n};\n\n/* ===================================*/\n\n/*\n\n====== Fail to solve in contest ======\n\nclass Solution {\npublic:\n    vector<bool> subsequenceSumAfterCapping(vector<int>& nums, int k) {\n        int n = nums.size();\n        vector<bool> ans(n, false);\n\n        sort(nums.begin(), nums.end());\n        // int mx = *max_element(nums.begin(), nums.end());\n        // for(int i=n-1; i>=0; i--) if(nums[i] > k) nums[i] = k;\n        int mx = nums.back();\n        \n        for (int cap = 1; cap <= n; cap++) {\n            // if(cap > nums[n-1]) {\n            if(cap > mx) {\n                ans[cap-1] = ans[cap-2];\n                continue;\n            }\n            if(cap * n < k) {\n                // ans[cap-1] = false;\n                continue;\n            }\n            \n            bitset<4001> dp;\n            dp[0] = 1;\n\n            for (int& x : nums) {\n                int val = min(x, cap);\n                if (val > k) break;\n                else if(val == k) {\n                    dp[k] = 1;\n                    break;\n                }\n                else {\n                    dp |= (dp << val);\n                    if(dp[k]) break;\n                }\n            }\n            \n            ans[cap-1] = dp[k];\n        }\n        \n        return ans;\n    }\n};\n*/\n","contest":"weekly467","contestType":"weekly","contestNumber":467,"contestUrl":"https://leetcode.com/contest/weekly-contest-467/"},{"key":"contest:contests/weekly467/3686.number-of-stable-subsequences.cpp","id":3686,"qid":"3686","title":"Number Of Stable Subsequences","kebab":"number-of-stable-subsequences","rating":1969.3,"ratingLabel":"1969.3","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/weekly467/3686.number-of-stable-subsequences.cpp","leetcodeUrl":"https://leetcode.com/problems/number-of-stable-subsequences/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly467/3686.number-of-stable-subsequences.cpp","code":"\n","contest":"weekly467","contestType":"weekly","contestNumber":467,"contestUrl":"https://leetcode.com/contest/weekly-contest-467/"},{"key":"contest:contests/weekly468/3688.bitwise-or-of-even-numbers-in-an-array.cpp","id":3688,"qid":"3688","title":"Bitwise Or Of Even Numbers In An Array","kebab":"bitwise-or-of-even-numbers-in-an-array","rating":1204.9,"ratingLabel":"1204.9","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/weekly468/3688.bitwise-or-of-even-numbers-in-an-array.cpp","leetcodeUrl":"https://leetcode.com/problems/bitwise-or-of-even-numbers-in-an-array/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly468/3688.bitwise-or-of-even-numbers-in-an-array.cpp","code":"class Solution {\npublic:\n    int evenNumberBitwiseORs(vector<int>& nums) {\n        int res = 0;\n        for(auto& a : nums) {\n            if(a % 2 == 0) res |= a;\n        }\n        return res;\n    }\n};\n","contest":"weekly468","contestType":"weekly","contestNumber":468,"contestUrl":"https://leetcode.com/contest/weekly-contest-468/"},{"key":"contest:contests/weekly468/3689.maximum-total-subarray-value-i.cpp","id":3689,"qid":"3689","title":"Maximum Total Subarray Value I","kebab":"maximum-total-subarray-value-i","rating":1370.7,"ratingLabel":"1370.7","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/weekly468/3689.maximum-total-subarray-value-i.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-total-subarray-value-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly468/3689.maximum-total-subarray-value-i.cpp","code":"class Solution {\npublic:\n    long long maxTotalValue(vector<int>& nums, int k) {\n        int n = nums.size();\n        long long mx = nums[0], mn = mx;\n        for(auto& i : nums) {\n            if(i > mx) mx = i;\n            if(i < mn) mn = i;\n        }\n\n        long long res = mx - mn;\n        res = res * (long long)k;\n        return res;\n    }\n};\n","contest":"weekly468","contestType":"weekly","contestNumber":468,"contestUrl":"https://leetcode.com/contest/weekly-contest-468/"},{"key":"contest:contests/weekly468/3690.split-and-merge-array-transformation.cpp","id":3690,"qid":"3690","title":"Split And Merge Array Transformation","kebab":"split-and-merge-array-transformation","rating":1982.5,"ratingLabel":"1982.5","tier":"Candidate Master","tierSlug":"1900-2099-candidate-master","tierLabel":"1900-2099","path":"contests/weekly468/3690.split-and-merge-array-transformation.cpp","leetcodeUrl":"https://leetcode.com/problems/split-and-merge-array-transformation/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly468/3690.split-and-merge-array-transformation.cpp","code":"class Solution {\npublic:\n    int minSplitMerge(vector<int>& nums1, vector<int>& nums2) {\n        int n = nums1.size();\n        if (nums1 == nums2) return 0;\n    \n        queue<vector<int>> q;\n        map<vector<int>, int> dist;\n        q.push(nums1);\n        dist[nums1] = 0;\n    \n        while (!q.empty()) {\n            auto cur = q.front(); q.pop();\n            int d = dist[cur];\n    \n            for (int L = 0; L < n; ++L) {\n                for (int R = L; R < n; ++R) {\n                    vector<int> block(cur.begin() + L, cur.begin() + R + 1);\n                    vector<int> remain; remain.reserve(n - (R - L + 1));\n                    remain.insert(remain.end(), cur.begin(), cur.begin() + L);\n                    remain.insert(remain.end(), cur.begin() + R + 1, cur.end());\n    \n                    for (int ins = 0; ins <= (int)remain.size(); ++ins) {\n                        vector<int> nxt; nxt.reserve(n);\n                        nxt.insert(nxt.end(), remain.begin(), remain.begin() + ins);\n                        nxt.insert(nxt.end(), block.begin(), block.end());\n                        nxt.insert(nxt.end(), remain.begin() + ins, remain.end());\n    \n                        if (nxt == cur) continue;\n                        if (dist.find(nxt) != dist.end()) continue;\n    \n                        dist[nxt] = d + 1;\n                        if (nxt == nums2) return d + 1;\n                        q.push(std::move(nxt));\n                    }\n                }\n            }\n        }\n        return -1;\n    }\n};\n","contest":"weekly468","contestType":"weekly","contestNumber":468,"contestUrl":"https://leetcode.com/contest/weekly-contest-468/"},{"key":"contest:contests/weekly468/3691.maximum-total-subarray-value-ii.cpp","id":3691,"qid":"3691","title":"Maximum Total Subarray Value II","kebab":"maximum-total-subarray-value-ii","rating":2469.0,"ratingLabel":"2469.0","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"contests/weekly468/3691.maximum-total-subarray-value-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/maximum-total-subarray-value-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly468/3691.maximum-total-subarray-value-ii.cpp","code":"struct RMQ {\n    int n, LOG;\n    vector<int> lg;                 // floor(log2(i))\n    vector<vector<int>> stMax;      // stMax[k][i] = max on [i, i+2^k-1]\n    vector<vector<int>> stMin;      // stMin[k][i] = min on [i, i+2^k-1]\n\n    RMQ() {}\n    RMQ(const vector<int>& a) { build(a); }\n\n    void build(const vector<int>& a) {\n        n = (int)a.size();\n        LOG = 1;\n        while ((1 << LOG) <= n) ++LOG;\n\n        lg.assign(n + 1, 0);\n        for (int i = 2; i <= n; ++i) lg[i] = lg[i >> 1] + 1;\n\n        stMax.assign(LOG, vector<int>(n));\n        stMin.assign(LOG, vector<int>(n));\n        // k = 0\n        for (int i = 0; i < n; ++i) {\n            stMax[0][i] = a[i];\n            stMin[0][i] = a[i];\n        }\n        // k > 0\n        for (int k = 1; k < LOG; ++k) {\n            int len = 1 << k;\n            int half = len >> 1;\n            for (int i = 0; i + len - 1 < n; ++i) {\n                stMax[k][i] = std::max(stMax[k - 1][i], stMax[k - 1][i + half]);\n                stMin[k][i] = std::min(stMin[k - 1][i], stMin[k - 1][i + half]);\n            }\n        }\n    }\n\n    inline int rangeMax(int l, int r) const {\n        if (l > r) swap(l, r);\n        int k = lg[r - l + 1];\n        return std::max(stMax[k][l], stMax[k][r - (1 << k) + 1]);\n    }\n    inline int rangeMin(int l, int r) const {\n        if (l > r) swap(l, r);\n        int k = lg[r - l + 1];\n        return std::min(stMin[k][l], stMin[k][r - (1 << k) + 1]);\n    }\n    inline int value(int l, int r) const { // v(l,r) = max - min\n        return rangeMax(l, r) - rangeMin(l, r);\n    }\n};\n\nclass Solution {\npublic:\n    long long maxTotalValue(vector<int>& nums, int k) {\n        int n = (int)nums.size();\n        RMQ rmq(nums);\n\n        // \u5c0d\u6bcf\u500b\u56fa\u5b9a l\uff0c\u5e8f\u5217 v(l, r)\uff08r \u5f80\u5de6\u79fb\uff09\u70ba\u975e\u589e\n        // \u521d\u59cb\u5316\u5c07 (l, r = n-1) \u653e\u5165\u6700\u5927\u5806\n        using Node = pair<int, pair<int,int>>; // (value, (l, r))\n        priority_queue<Node> pq;\n        pq = priority_queue<Node>();\n\n        for (int l = 0; l < n; ++l) {\n            int r = n - 1;\n            int v = rmq.value(l, r);\n            pq.push({v, {l, r}});\n        }\n\n        long long ans = 0;\n        while (k-- > 0 && !pq.empty()) {\n            auto [val, lr] = pq.top(); pq.pop();\n            int l = lr.first, r = lr.second;\n            ans += (long long)val;\n\n            // \u5f80\u540c\u4e00 row \u7684\u4e0b\u4e00\u500b\uff08r-1\uff09\u63a8\u9032\n            if (r > l) {\n                int nr = r - 1;\n                int nv = rmq.value(l, nr);\n                pq.push({nv, {l, nr}});\n            }\n        }\n        return ans;\n    }\n};\n","contest":"weekly468","contestType":"weekly","contestNumber":468,"contestUrl":"https://leetcode.com/contest/weekly-contest-468/"},{"key":"contest:contests/weekly469/3697.compute-decimal-representation.cpp","id":3697,"qid":"3697","title":"Compute Decimal Representation","kebab":"compute-decimal-representation","rating":1250.8,"ratingLabel":"1250.8","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/weekly469/3697.compute-decimal-representation.cpp","leetcodeUrl":"https://leetcode.com/problems/compute-decimal-representation/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly469/3697.compute-decimal-representation.cpp","code":"class Solution {\npublic:\n    vector<int> decimalRepresentation(int n) {\n        vector<int> res;\n        long long p = 1;\n        while(n > 0) {\n            int cur = p * (n % 10);\n            if(cur > 0) res.push_back(cur);\n            p *= 10;\n            n /= 10;\n        }\n        reverse(res.begin(), res.end());\n        return res;\n    }\n};\n","contest":"weekly469","contestType":"weekly","contestNumber":469,"contestUrl":"https://leetcode.com/contest/weekly-contest-469/"},{"key":"contest:contests/weekly469/3698.split-array-with-minimum-difference.cpp","id":3698,"qid":"3698","title":"Split Array With Minimum Difference","kebab":"split-array-with-minimum-difference","rating":1648.8,"ratingLabel":"1648.8","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/weekly469/3698.split-array-with-minimum-difference.cpp","leetcodeUrl":"https://leetcode.com/problems/split-array-with-minimum-difference/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly469/3698.split-array-with-minimum-difference.cpp","code":"class Solution {\npublic:\n    long long splitArray(vector<int>& nums) {\n        int n = nums.size();\n\n        vector<long long> pre(n + 1, 0);\n        for (int i = 0; i < n; ++i) pre[i + 1] = pre[i] + nums[i];\n        long long total = pre[n];\n\n        vector<char> inc(n, 0), dec(n, 0);\n        inc[0] = 1;\n        for (int i = 1; i < n; ++i)\n            inc[i] = inc[i - 1] && (nums[i - 1] < nums[i]);\n\n        dec[n - 1] = 1;\n        for (int i = n - 2; i >= 0; --i)\n            dec[i] = dec[i + 1] && (nums[i] > nums[i + 1]);\n\n        long long ans = LLONG_MAX;\n        for (int k = 0; k <= n - 2; ++k) {\n            if (inc[k] && dec[k + 1]) {\n                long long left = pre[k + 1];\n                long long right = total - left;\n                ans = min(ans, llabs(right - left));\n            }\n        }\n        \n        return (ans == LLONG_MAX) ? -1 : ans;\n    }\n};\n","contest":"weekly469","contestType":"weekly","contestNumber":469,"contestUrl":"https://leetcode.com/contest/weekly-contest-469/"},{"key":"contest:contests/weekly469/3699.number-of-zigzag-arrays-i.cpp","id":3699,"qid":"3699","title":"Number Of Zigzag Arrays I","kebab":"number-of-zigzag-arrays-i","rating":2123.1,"ratingLabel":"2123.1","tier":"Master","tierSlug":"2100-2299-master","tierLabel":"2100-2299","path":"contests/weekly469/3699.number-of-zigzag-arrays-i.cpp","leetcodeUrl":"https://leetcode.com/problems/number-of-zigzag-arrays-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly469/3699.number-of-zigzag-arrays-i.cpp","code":"class Solution {\npublic:\n    long long mod = 1e9+7;\n    int zigZagArrays(int n, int l, int r) {\n        long long m = r - l + 1;\n\n        vector<long long> up(m), down(m);\n        for(long long k = 0; k < m; k++) {\n            up[k] = k % mod;\n            down[k] = (m-1-k) % mod;\n        }\n\n        for(long long len = 3; len <= n; len++) {\n            vector<long long> up2(m), down2(m);\n\n            long long pre = 0;\n            for(long long k = 0; k < m; k++) {\n                up2[k] = pre;\n                pre += down[k];\n                if(pre >= mod) pre -= mod;\n            }\n\n            long long suf = 0;\n            for(long long k = m-1; k>=0; k--) {\n                down2[k] = suf;\n                suf += up[k];\n                if(suf >= mod) suf -= mod;\n                if(k == 0) break;\n            }\n\n            up.swap(up2);\n            down.swap(down2);\n        }\n\n        long long res = 0;\n        for(long long k = 0; k < m; k++) {\n            res += up[k];\n            if(res >= mod) res -= mod;\n        }\n        for(long long k = 0; k < m; k++) {\n            res += down[k];\n            if(res >= mod) res -= mod;\n        }\n\n        return res % mod;\n    }\n};\n","contest":"weekly469","contestType":"weekly","contestNumber":469,"contestUrl":"https://leetcode.com/contest/weekly-contest-469/"},{"key":"contest:contests/weekly469/3700.number-of-zigzag-arrays-ii_TLE.cpp","id":3700,"qid":"3700","title":"Number Of Zigzag Arrays II (TLE)","kebab":"number-of-zigzag-arrays-ii","rating":null,"ratingLabel":"-","tier":"Unrated","tierSlug":"unrated","tierLabel":"Unrated","path":"contests/weekly469/3700.number-of-zigzag-arrays-ii_TLE.cpp","leetcodeUrl":"https://leetcode.com/problems/number-of-zigzag-arrays-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly469/3700.number-of-zigzag-arrays-ii_TLE.cpp","code":"class Solution {\npublic:\n    static constexpr long long mod = 1e9 + 7;\n\n    int zigZagArrays(int n, int l, int r) {\n        int m = r - l + 1;\n        if (m <= 0) return 0;\n\n        std::vector<int> up(m), down(m);\n        for (int k = 0; k < m; ++k) {\n            up[k] = k;\n        }\n\n        long long suf = 0;\n        for (int len = 2; len <= n; ++len) {\n            suf = 0;\n            for (int k = m - 1; k >= 0; --k) {\n                down[m - 1 - k] = suf;\n                suf += up[k];\n                if (suf >= mod) suf -= mod;\n            }\n            if (len == n) break;\n            up.swap(down);\n        }\n\n        return int((suf * 2) % mod);\n    }\n};\n","contest":"weekly469","contestType":"weekly","contestNumber":469,"contestUrl":"https://leetcode.com/contest/weekly-contest-469/"},{"key":"contest:contests/weekly470/3701.compute-alternating-sum.cpp","id":3701,"qid":"3701","title":"Compute Alternating Sum","kebab":"compute-alternating-sum","rating":1228.3,"ratingLabel":"1228.3","tier":"Pupil","tierSlug":"1200-1399-pupil","tierLabel":"1200-1399","path":"contests/weekly470/3701.compute-alternating-sum.cpp","leetcodeUrl":"https://leetcode.com/problems/compute-alternating-sum/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly470/3701.compute-alternating-sum.cpp","code":"class Solution {\npublic:\n    int alternatingSum(vector<int>& nums) {\n        int res = 0;\n        for(int i=0; i<nums.size(); i++) {\n            if(i % 2 == 0) res += nums[i];\n            else res -= nums[i];\n        }\n        return res;\n    }\n};\n","contest":"weekly470","contestType":"weekly","contestNumber":470,"contestUrl":"https://leetcode.com/contest/weekly-contest-470/"},{"key":"contest:contests/weekly470/3702.longest-subsequence-with-non-zero-bitwise-xor.cpp","id":3702,"qid":"3702","title":"Longest Subsequence With Non Zero Bitwise Xor","kebab":"longest-subsequence-with-non-zero-bitwise-xor","rating":1489.5,"ratingLabel":"1489.5","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"contests/weekly470/3702.longest-subsequence-with-non-zero-bitwise-xor.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-subsequence-with-non-zero-bitwise-xor/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly470/3702.longest-subsequence-with-non-zero-bitwise-xor.cpp","code":"class Solution {\npublic:\n    int longestSubsequence(vector<int>& nums) {\n        int res = 0, n = nums.size();\n        bool z = true;\n        for(auto & x : nums) {\n            res ^= x;\n            if(x != 0) z = false;\n        }\n        if(z) {\n            return 0;\n        }\n        else if(res != 0) {\n            return n;\n        }\n        else {\n            return n-1;\n        }\n    }\n};\n","contest":"weekly470","contestType":"weekly","contestNumber":470,"contestUrl":"https://leetcode.com/contest/weekly-contest-470/"},{"key":"contest:contests/weekly470/3703.remove-k-balanced-substrings.cpp","id":3703,"qid":"3703","title":"Remove K Balanced Substrings","kebab":"remove-k-balanced-substrings","rating":1802.0,"ratingLabel":"1802.0","tier":"Expert","tierSlug":"1600-1899-expert","tierLabel":"1600-1899","path":"contests/weekly470/3703.remove-k-balanced-substrings.cpp","leetcodeUrl":"https://leetcode.com/problems/remove-k-balanced-substrings/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly470/3703.remove-k-balanced-substrings.cpp","code":"class Solution {\npublic:\n    string removeSubstring(string s, int k) {\n        vector<pair<char, int>> runs;\n\n        auto try_merge_last_two = [&]() {\n            if (runs.size() >= 2 && runs[runs.size()-1].first == runs[runs.size()-2].first) {\n                runs[runs.size()-2].second += runs.back().second;\n                runs.pop_back();\n            }\n        };\n\n        auto try_reduce_tail = [&]() {\n            while (runs.size() >= 2 &&\n                   runs[runs.size()-2].first == '(' &&\n                   runs[runs.size()-1].first == ')' &&\n                   runs[runs.size()-2].second >= k &&\n                   runs[runs.size()-1].second >= k) {\n    \n                runs[runs.size()-2].second -= k;\n                runs[runs.size()-1].second -= k;\n    \n                if (runs.back().second == 0) runs.pop_back();\n                if (!runs.empty() && runs.back().second == 0) runs.pop_back();\n    \n                try_merge_last_two();\n            }\n        };\n\n        for(char & c : s) {\n            if(!runs.empty() && runs.back().first == c) {\n                runs.back().second++;\n            }\n            else {\n                runs.emplace_back(c, 1);\n            }\n            try_reduce_tail();\n        }\n\n        string res;\n        for(auto &p : runs) res.append(p.second, p.first);\n        return res;\n    }\n};\n","contest":"weekly470","contestType":"weekly","contestNumber":470,"contestUrl":"https://leetcode.com/contest/weekly-contest-470/"},{"key":"contest:contests/weekly470/3704.count-no-zero-pairs-that-sum-to-n.cpp","id":3704,"qid":"3704","title":"Count No Zero Pairs That Sum To N","kebab":"count-no-zero-pairs-that-sum-to-n","rating":2419.3,"ratingLabel":"2419.3","tier":"Grandmaster","tierSlug":"2400-2599-grandmaster","tierLabel":"2400-2599","path":"contests/weekly470/3704.count-no-zero-pairs-that-sum-to-n.cpp","leetcodeUrl":"https://leetcode.com/problems/count-no-zero-pairs-that-sum-to-n/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly470/3704.count-no-zero-pairs-that-sum-to-n.cpp","code":"class Solution {\npublic:\n    vector<int> digits;\n    long long dp[20][2][2][2][2][2];\n    bool vis[20][2][2][2][2][2];\n    \n    long long dfs(int pos, int carry, int usedA, int usedB, int endA, int endB) {\n        if (pos == digits.size()) {\n            return (carry == 0 && usedA && usedB) ? 1LL : 0LL;\n        }\n        if (vis[pos][carry][usedA][usedB][endA][endB])\n            return dp[pos][carry][usedA][usedB][endA][endB];\n    \n        long long res = 0;\n        int t = digits[pos];\n    \n        for (int da = 0; da <= 9; ++da) {\n            if (endA && da != 0) continue;\n            int nEndA = endA || (da == 0);\n            for (int db = 0; db <= 9; ++db) {\n                if (endB && db != 0) continue;\n                int nEndB = endB || (db == 0);\n    \n                int s = da + db + carry;\n                if (s % 10 != t) continue;\n    \n                res += dfs(pos + 1, s / 10,\n                           usedA || (da != 0),\n                           usedB || (db != 0),\n                           nEndA, nEndB);\n            }\n        }\n    \n        vis[pos][carry][usedA][usedB][endA][endB] = true;\n        return dp[pos][carry][usedA][usedB][endA][endB] = res;\n    }\n\n    long long countNoZeroPairs(long long n) {\n        digits.clear();\n        \n        while(n > 0) {\n            digits.push_back(n % 10);\n            n /= 10;\n        }\n        \n        memset(vis, 0, sizeof(vis));\n        return dfs(0, 0, 0, 0, 0, 0);\n    }\n};\n","contest":"weekly470","contestType":"weekly","contestNumber":470,"contestUrl":"https://leetcode.com/contest/weekly-contest-470/"},{"key":"contest:contests/weekly471/3712.sum-of-elements-with-frequency-divisible-by-k.cpp","id":3712,"qid":"3712","title":"Sum Of Elements With Frequency Divisible By K","kebab":"sum-of-elements-with-frequency-divisible-by-k","rating":1198.7,"ratingLabel":"1198.7","tier":"Newbie","tierSlug":"0000-1199-newbie","tierLabel":"< 1200","path":"contests/weekly471/3712.sum-of-elements-with-frequency-divisible-by-k.cpp","leetcodeUrl":"https://leetcode.com/problems/sum-of-elements-with-frequency-divisible-by-k/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly471/3712.sum-of-elements-with-frequency-divisible-by-k.cpp","code":"class Solution {\npublic:\n    int sumDivisibleByK(vector<int>& nums, int k) {\n        vector<int> cnt(110, 0);\n        for(auto& i : nums) cnt[i]++;\n\n        int res = 0;\n        for(int i=1; i<=100; i++) {\n            if(cnt[i] % k == 0) {\n                res += i * cnt[i];\n            }\n        }\n        return res;\n    }\n};\n","contest":"weekly471","contestType":"weekly","contestNumber":471,"contestUrl":"https://leetcode.com/contest/weekly-contest-471/"},{"key":"contest:contests/weekly471/3713.longest-balanced-substring-i.cpp","id":3713,"qid":"3713","title":"Longest Balanced Substring I","kebab":"longest-balanced-substring-i","rating":1490.2,"ratingLabel":"1490.2","tier":"Specialist","tierSlug":"1400-1599-specialist","tierLabel":"1400-1599","path":"contests/weekly471/3713.longest-balanced-substring-i.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-balanced-substring-i/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly471/3713.longest-balanced-substring-i.cpp","code":"class Solution {\npublic:\n    int longestBalanced(string s) {\n        int n = s.size();\n        int res = 0;\n\n        for (int i = 0; i < n; i++) {\n            vector<int> cnt(26, 0);\n            int distinct = 0;\n            for (int j = i; j < n; j++) {\n                int idx = s[j] - 'a';\n                if (cnt[idx] == 0) distinct++;\n                cnt[idx]++;\n\n                int mn = INT_MAX, mx = 0;\n                for (int c : cnt) {\n                    if (c > 0) {\n                        mn = min(mn, c);\n                        mx = max(mx, c);\n                    }\n                }\n                if (mn == mx)\n                    res = max(res, j - i + 1);\n            }\n        }\n        return res;\n    }\n};\n","contest":"weekly471","contestType":"weekly","contestNumber":471,"contestUrl":"https://leetcode.com/contest/weekly-contest-471/"},{"key":"contest:contests/weekly471/3714.longest-balanced-substring-ii.cpp","id":3714,"qid":"3714","title":"Longest Balanced Substring II","kebab":"longest-balanced-substring-ii","rating":2201.8,"ratingLabel":"2201.8","tier":"Master","tierSlug":"2100-2299-master","tierLabel":"2100-2299","path":"contests/weekly471/3714.longest-balanced-substring-ii.cpp","leetcodeUrl":"https://leetcode.com/problems/longest-balanced-substring-ii/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly471/3714.longest-balanced-substring-ii.cpp","code":"// UPSOLVING\n\nclass Solution {\npublic:\n    int double_chars(string s, char x, char y) {\n        int n = s.size();\n        int res = 0;\n        unordered_map<int, int> first;\n        int bal = 0;\n\n        first[0] = -1;\n\n        for(int i=0; i<n; i++) {\n            if(s[i] == x) bal++;\n            else if(s[i] == y) bal--;\n            else {\n                bal = 0;\n                first.clear();\n                first[0] = i;\n                continue;\n            }\n            if(first.count(bal)) {\n                res = max(res, i - first[bal]);\n            }\n            else {\n                first[bal] = i;\n            }\n        }\n        return res;\n    }\n    int longestBalanced(string s) {\n        int res = 0;\n        int n = s.size();\n\n        // single char\n        char ch = s[0];\n        for(int i=0, cur=0; i<n; i++) {\n            if(s[i] == ch) {\n                cur++;\n            }\n            else {\n                ch = s[i];\n                cur = 1;\n            }\n            res = max(res, cur);\n        }\n\n        // double chars\n        res = max(res, double_chars(s, 'a', 'b'));\n        res = max(res, double_chars(s, 'b', 'c'));\n        res = max(res, double_chars(s, 'a', 'c'));\n\n        // triple chars\n        int a=0, b=0, c=0;\n        map<pair<int, int>, int> mp;\n        mp[{0,0}] = -1;\n\n        for(int i=0; i<n; i++) {\n            if(s[i] == 'a') a++;\n            else if(s[i] == 'b') b++;\n            else if(s[i] == 'c') c++;\n\n            pair<int, int> k = {a - b, a - c};\n            if(mp.count(k)) res = max(res, i - mp[k]);\n            else mp[k] = i;\n        }\n\n        return res;\n    }\n};\n","contest":"weekly471","contestType":"weekly","contestNumber":471,"contestUrl":"https://leetcode.com/contest/weekly-contest-471/"},{"key":"contest:contests/weekly471/3715.sum-of-perfect-square-ancestors.cpp","id":3715,"qid":"3715","title":"Sum Of Perfect Square Ancestors","kebab":"sum-of-perfect-square-ancestors","rating":2235.4,"ratingLabel":"2235.4","tier":"Master","tierSlug":"2100-2299-master","tierLabel":"2100-2299","path":"contests/weekly471/3715.sum-of-perfect-square-ancestors.cpp","leetcodeUrl":"https://leetcode.com/problems/sum-of-perfect-square-ancestors/","githubUrl":"https://github.com/cyc6221/leetcode/blob/main/contests/weekly471/3715.sum-of-perfect-square-ancestors.cpp","code":"class Solution {\npublic:\n    long long res;\n    int N;\n    unordered_map<int, int> freq;\n\n    int S(int x) {\n        int res = 1;\n        for(int p=2; p * p <= x; p++) {\n            int cnt = 0;\n            while(x % p == 0) {\n                x /= p;\n                cnt ^= 1;\n            }\n            if(cnt) res *= p;\n        }\n        if(x > 1) res *= x;\n        return res;\n    }\n\n    void dfs(unordered_map<int, vector<int>> &adj, vector<int>& nums, vector<int>& vis, int cur) {\n        if(vis[cur]) return;\n        vis[cur] = 1;\n\n        int key = S(nums[cur]);\n        res += freq[key];\n        freq[key]++;\n        \n        for(auto& b : adj[cur]) {\n            if(b != cur) dfs(adj, nums, vis, b);\n        }\n        freq[key]--;\n    }\n    \n    long long sumOfAncestors(int n, vector<vector<int>>& edges, vector<int>& nums) {\n        res = 0;\n        N = n;\n\n        unordered_map<int, vector<int>> adj;\n\n        for(auto& e : edges) {\n            int a = e[0], b = e[1];\n            adj[a].push_back(b);\n            adj[b].push_back(a);\n        }\n\n        vector<int> vis(n, 0);\n        dfs(adj, nums, vis, 0);\n        return res;\n    }\n};\n","contest":"weekly471","contestType":"weekly","contestNumber":471,"contestUrl":"https://leetcode.com/contest/weekly-contest-471/"}]};
